int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        std::sort(a.begin(), a.end());

        long long min_val = a[0];
        long long operations = 0;

        for (int i = 1; i < n; ++i) {
            // For each pile a[i] (where i > 0), we want to add min_val to it
            // as many times as possible without exceeding k.
            // The number of times we can add min_val to a[i] is (k - a[i]) / min_val.
            // This is integer division, which correctly gives the floor.
            operations += (k - a[i]) / min_val;
        }
        std::cout << operations << std::endl;
    }
    return 0;
}

#include <iostream>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        if (a == b) {
            std::cout << 0 << "\n";
            continue;
        }
        long long diff = std::abs(a - b);
        long long count = 0;

        // Greedy approach for denominations 5, 2, 1
        // This works because 1, 2, 5 form a canonical coin system.
        // For any remainder after taking 5s, say `rem`, we need to make `rem` using 2s and 1s.
        // rem can be 0, 1, 2, 3, 4.
        // If rem = 0: 0 presses
        // If rem = 1: 1 press (1)
        // If rem = 2: 1 press (2)
        // If rem = 3: 2 presses (2+1)
        // If rem = 4: 2 presses (2+2)
        // In all these cases, taking as many 2s as possible first, then 1s, is optimal.

        count += diff / 5;
        diff %= 5;

        count += diff / 2;
        diff %= 2;

        count += diff / 1;
        // diff %= 1; // diff will be 0 here

        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    if (n == 2) {
        std::cout << p[1] << " " << p[0] << std::endl;
        return;
    }

    // For n > 2, reversing the permutation always works.
    // Let p = [p_1, p_2, ..., p_n].
    // The sums are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
    // Let p' = [p_n, p_{n-1}, ..., p_1].
    // The sums for p' are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
    // These are exactly the same set of sums, just in reverse order.
    // Since F(p) and F(p') involve sorting these sums, they will be identical.
    // Also, p' is different from p unless p is a palindrome (e.g., [1,2,1] which is not a permutation, or [1,2,3,2,1] not a permutation).
    // A permutation [p_1, ..., p_n] can only be equal to its reverse [p_n, ..., p_1] if p_i = p_{n-i+1} for all i.
    // For example, if n=3, p=[1,2,3], p'=[3,2,1]. Different.
    // If n=4, p=[1,2,3,4], p'=[4,3,2,1]. Different.
    // Since p contains distinct integers from 1 to n, p_1 cannot be equal to p_n unless n=1 (not allowed) or n=2 and p_1=p_2 (not allowed).
    // If p_1 = p_n, then p_1 must be equal to p_n, which is impossible for distinct elements unless n=1.
    // So p_1 != p_n for n >= 2.
    // Thus, p is always different from its reverse p'.

    std::reverse(p.begin(), p.end());
    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

