void solve() {
    std::string s, t;
    std::cin >> s >> t;

    // A character can be propagated across the entire string if it exists.
    // So, if s and t can be made equal, they must be made equal to some
    // common character 'c' that exists in both s and t.
    // If there is at least one common character between s and t,
    // then we can propagate that character throughout s to make s consist
    // only of that character, and similarly for t.
    // For example, if 'a' is in s and 'a' is in t, we can make s="aaa..."
    // and t="aaa...". Thus, s and t become equal.

    // We need to check if there is any character that exists in both strings.
    // A simple way is to use a frequency array or a set for characters in s.

    std::vector<bool> s_chars(26, false);
    for (char c : s) {
        s_chars[c - 'a'] = true;
    }

    bool common_char_found = false;
    for (char c : t) {
        if (s_chars[c - 'a']) {
            common_char_found = true;
            break;
        }
    }

    if (common_char_found) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

