void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << std::endl;
    } else {
        // For n >= 2, we can construct a number.
        // The strategy is to use '2' as the first digit,
        // '3' as the second digit, and '7' for all subsequent digits.
        // This forms a number like 2377...7.
        //
        // Let's check divisibility:
        // 1. Divisibility by 2: The number ends in 7, which is odd. So, not divisible by 2.
        // 2. Divisibility by 3: The sum of digits is 2 + 3 + (n-2)*7.
        //    Sum = 5 + 7n - 14 = 7n - 9.
        //    For n=2, sum = 7*2 - 9 = 14 - 9 = 5. Not divisible by 3.
        //    For n=3, sum = 7*3 - 9 = 21 - 9 = 12. Divisible by 3.
        //    This strategy fails for n=3.
        //
        // Let's try another strategy:
        // For n >= 2, use '2' as the first digit, and '3' for all subsequent digits.
        // This forms a number like 233...3.
        // Digits are 2 and 3.
        // 1. Divisibility by 2: The number ends in 3, which is odd. So, not divisible by 2.
        // 2. Divisibility by 3: The sum of digits is 2 + (n-1)*3.
        //    Sum = 2 + 3n - 3 = 3n - 1.
        //    Since 3n is divisible by 3, 3n-1 is never divisible by 3.
        //    So, the number is never divisible by 3.
        // This strategy works for all n >= 2.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << std::endl;
    }
}

