#include <iostream>
#include <vector>
#include <numeric>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) {
            counts[s_val]++;
        }
    }

    int current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the total value contributed by this power of two
        // to the current_sum, but only up to 2048.
        // For example, if we have three 512s, we can make one 1024 and one 512 remaining.
        // The 1024 can then be combined.
        // Effectively, we are summing up the values.
        // If we have 512, 512, 512, 512, 512 (five 512s), this is 2560.
        // We can make two 1024s and one 512.
        // The two 1024s can make one 2048.
        // So, we just need to sum up all values less than or equal to 2048.
        // If the sum is >= 2048, we can always form 2048.
        // This is because any power of two can be combined with an equal power of two
        // to form the next higher power of two.
        // If we have a total sum S, we can always form a number X such that X <= S
        // and X is a power of two, by repeatedly combining smallest available numbers.
        // For example, if we have {1, 1, 1, 1, 2, 4}, sum is 10.
        // We can make {2, 1, 1, 2, 4} -> {2, 2, 2, 4} -> {4, 2, 4} -> {4, 4, 2} -> {8, 2}.
        // The largest power of two we can form is 8.
        // If the sum of all numbers <= 2048 is >= 2048, then we can always form 2048.
        // This is because we can always combine smaller powers of two to form larger ones
        // until we reach 2048 or exceed it.
        // The only constraint is that we need *two* equal numbers.
        // However, if we have a total sum S, we can always combine numbers to form
        // a number X such that X is the largest power of two less than or equal to S.
        // For example, if S = 2048, we can form 2048.
        // If S = 2047, we can form 1024.
        // If S = 2049, we can form 2048.
        // The greedy strategy of combining the smallest available numbers works.
        // Or, more simply, if we have a total sum of values (up to 2048),
        // we can always achieve 2048 if this sum is 2048 or more.
        // This is because any $2^k$ can be thought of as $2^k$ units of $1$.
        // If we have $X$ units of $1$ in total (where $X$ is the sum of all numbers),
        // we can always combine them to form $2048$ if $X \ge 2048$.
        // The only numbers that matter are those less than or equal to 2048.
        // Numbers greater than 2048 cannot be used to form 2048.

        current_sum += val * count;
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

