void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n); // 0 for white, 1 for black

    bool first_half_color = false; // false for 0, true for 1

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (2 * a[i] < T) {
            p[i] = 0; // Always assign to white (color 0)
        } else if (2 * a[i] > T) {
            p[i] = 1; // Always assign to black (color 1)
        } else { // 2 * a[i] == T
            // Distribute elements equal to T/2
            // Assign to color 0, then 1, then 0, then 1, etc.
            if (first_half_color) {
                p[i] = 1;
            } else {
                p[i] = 0;
            }
            first_half_color = !first_half_color;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

