#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            max_val_in_row = std::max(max_val_in_row, a[i][j]);
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1 and no element is n.
    // If so, it means the actual value n was not present in any min(p_i, p_j)
    // because p_i was always smaller than n.
    // This implies that one of the p_i must be n.
    // The one that should be n would have been assigned n-1 by the max_val_in_row logic.
    // So, if max(p) is n-1, we need to find the first occurrence of n-1 and change it to n.
    // This handles cases like n=2, p={1,2} -> a={0,1;1,0}. max_val_in_row for p_0 is 1, for p_1 is 1.
    // So p becomes {1,1}. We need to change one 1 to 2.

    bool n_found = false;
    for (int val : p) {
        if (val == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // If n is not found in p, it means the true value n was never the minimum
        // in any pair (p_i, p_j) where p_i is the current element.
        // This implies that the element p_k which should be n,
        // had min(p_k, p_j) = p_j for all j != k.
        // So max_{j!=k} (min(p_k, p_j)) = max_{j!=k} (p_j) = n-1.
        // Thus, p_k was assigned n-1.
        // We need to find one such p_k that was assigned n-1 and change it to n.
        // Since all values 1 to n-1 are present in the other elements,
        // there must be at least one element that was assigned n-1.
        // We can just pick the first one.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; 
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    // Initialize min_suffix with the last element, as it's the minimum from index n-1 to n-1.
    // We iterate from n-2 down to 0.
    int min_suffix = a[n - 1]; 

    // Iterate from the second to last element down to the first element
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix, it means a[i] is
            // either equal to or less than min_suffix.
            // In either case, a[i] becomes the new minimum for the suffix
            // starting from index i.
            min_suffix = a[i];
        }
    }
    std::cout << bad_prices_count << "\n";
}

