    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 0;
        long long k = 1; // Represents the number of stairs in the current staircase (1, 3, 7, 15, ...)
        while (true) {
            // Cost of a nice staircase with k stairs is k * (k + 1) / 2
            // For k = 1, cost = 1 * 2 / 2 = 1
            // For k = 3, cost = 3 * 4 / 2 = 6
            // For k = 7, cost = 7 * 8 / 2 = 28
            // For k = 15, cost = 15 * 16 / 2 = 120
            // This is the cost of the staircase itself.
            // The problem statement implies that the nice staircases are those with k = 2^p - 1 stairs.
            // The cost of such a staircase is (2^p - 1) * (2^p) / 2.
            // Let's denote k_p = 2^p - 1.
            // The cost is k_p * (k_p + 1) / 2.
            // The sequence of k values is 1, 3, 7, 15, 31, ...
            // The sequence of costs is 1, 6, 28, 120, 496, ...

            // The cost of the current nice staircase we are considering is k * (k + 1) / 2.
            // We need to calculate the cost for the next staircase in the sequence.
            // The sequence of k values is k_0 = 1, k_1 = 3, k_2 = 7, ...
            // The cost of the p-th nice staircase (with k_p = 2^(p+1)-1 stairs) is (2^(p+1)-1) * (2^(p+1))/2.
            // Let's use `k` to represent the number of stairs in the current nice staircase.
            // The sequence of `k` values is 1, 3, 7, 15, ...
            // The cost of a staircase with `k` stairs is `k * (k + 1) / 2`.

            long long cost_of_current_staircase = k * (k + 1) / 2;

            if (current_cost + cost_of_current_staircase <= x) {
                current_cost += cost_of_current_staircase;
                count++;
                // Calculate the next k in the sequence: k_next = 2 * k + 1
                // This corresponds to 2^(p+1)-1 -> 2^(p+2)-1
                k = 2 * k + 1;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

