#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

bool is_good(const std::vector<int>& b) {
    int m = b.size();
    if (m <= 1) {
        return true;
    }

    // Find the peak index (first element that breaks non-decreasing from left)
    int peak_idx = -1;
    for (int i = 0; i < m - 1; ++i) {
        if (b[i] > b[i+1]) {
            peak_idx = i;
            break;
        }
    }

    // If no peak, array is non-decreasing, so it's good.
    if (peak_idx == -1) {
        return true;
    }

    // Find the valley index (first element that breaks non-increasing from right)
    int valley_idx = -1;
    for (int i = m - 1; i > 0; --i) {
        if (b[i] > b[i-1]) {
            valley_idx = i;
            break;
        }
    }

    // If no valley, array is non-increasing, so it's good.
    if (valley_idx == -1) {
        return true;
    }

    // The "good" array structure requires a non-decreasing prefix followed by a non-increasing suffix.
    // The peak_idx is the last element of the non-decreasing prefix.
    // The valley_idx is the first element of the non-increasing suffix.
    // For the array to be good, all elements between peak_idx and valley_idx (inclusive) must be equal.
    // More precisely, the elements from peak_idx to valley_idx must form a "plateau"
    // where b[peak_idx] >= b[peak_idx+1] >= ... >= b[valley_idx]
    // and b[valley_idx] <= b[valley_idx-1] <= ... <= b[peak_idx]
    // This implies that b[peak_idx] must be the maximum in this segment, and b[valley_idx] must be the minimum.
    // The condition for a good array is that after the initial non-decreasing part,
    // the remaining part must be non-increasing.
    // So, we need to check if b[peak_idx] >= b[peak_idx+1] >= ... >= b[m-1].
    // This means the array must look like: non-decreasing prefix, then non-increasing suffix.
    // The peak_idx is the first place where a[i] > a[i+1].
    // From this point onwards, the array must be non-increasing.
    // So, we check if b[peak_idx+1] >= b[peak_idx+2] >= ... >= b[m-1].

    for (int i = peak_idx + 1; i < m - 1; ++i) {
        if (b[i] < b[i+1]) { // If we find an increasing pair after the initial peak
            return false;
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        if (n <= 1) {
            std::cout << 0 << "\n";
            continue;
        }

        // Find the first index `i` from the right such that a[i] > a[i+1].
        // This marks the end of the non-increasing suffix.
        int suffix_end_idx = n - 1;
        while (suffix_end_idx > 0 && a[suffix_end_idx - 1] >= a[suffix_end_idx]) {
            suffix_end_idx--;
        }
        // Now, a[suffix_end_idx ... n-1] is non-increasing.
        // If suffix_end_idx is 0, the whole array is non-increasing.

        // Find the first index `i` from the right (starting from suffix_end_idx)
        // such that a[i] < a[i+1].
        // This marks the end of the non-decreasing prefix before the non-increasing suffix.
        int prefix_end_idx = suffix_end_idx;
        while (prefix_end_idx > 0 && a[prefix_end_idx - 1] <= a[prefix_end_idx]) {
            prefix_end_idx--;
        }
        // Now, a[prefix_end_idx ... suffix_end_idx-1] is non-decreasing.
        // The elements from a[prefix_end_idx] to a[n-1] form a "good" array structure.
        // The length of the prefix to erase is prefix_end_idx.

        std::cout << prefix_end_idx << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the index of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1], which is at pos[1].
        // min_idx and max_idx are initialized to pos[1].
        // The length is 1, min is 1, max is 1. So m=1 is beautiful.

        // For m > 1, we need to expand the current segment [current_min_idx, current_max_idx]
        // to include the number m.
        // The number m is at pos[m].
        // We need to update current_min_idx and current_max_idx to cover all numbers from 1 to m.
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A segment [l, r] is a permutation of 1..m if:
        // 1. Its length is m (r - l + 1 == m)
        // 2. It contains all numbers from 1 to m.
        //    This is guaranteed if l <= pos[k] <= r for all k from 1 to m.
        //    Our current_min_idx and current_max_idx track the minimum and maximum
        //    indices needed to cover all numbers from 1 to m.
        //    So, the segment [current_min_idx, current_max_idx] contains all numbers 1..m.
        //    The length of this segment is (current_max_idx - current_min_idx + 1).
        //    If this length is exactly m, then it must be a permutation of 1..m
        //    because all numbers in p are distinct and range from 1 to n.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

