int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = n;

    // Generate k distinct differences: n-1, n-2, ..., n-k
    // This is done by alternating between the smallest available and largest available numbers.
    // The first k+1 elements will generate k distinct differences.
    // For example, if k=2, n=5:
    // p_1 = 1, p_2 = 5, p_3 = 2
    // Differences: |1-5|=4, |5-2|=3. We have 2 distinct differences (4, 3).
    // These are n-1 and n-2.
    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index, take from left (smallest available)
            p[i] = left;
            left++;
        } else { // Odd index, take from right (largest available)
            p[i] = right;
            right--;
        }
    }

    // For the remaining n - (k+1) elements, we need to ensure no new distinct differences are introduced.
    // The simplest way is to append the remaining numbers in increasing order.
    // This will only introduce a difference of 1, which is likely already present
    // (e.g., if k=1, p={1,3,2,4,5}, diffs={2,1,2,1}, distinct={1,2}.
    // If k=1, p={1,2,3,4,5}, diffs={1,1,1,1}, distinct={1}.
    // The strategy of alternating for k+1 elements and then filling sequentially works.
    // The differences generated by the alternating part are |p_i - p_{i+1}|.
    // For i=0, |1-n| = n-1
    // For i=1, |n-2| = n-2
    // For i=2, |2-(n-1)| = n-3
    // ...
    // For i=k, |(k/2+1) - (n-k/2)| or |(n-k/2) - (k/2+1)| = n-k-1 (if k is even)
    // or |(n-(k-1)/2) - ((k-1)/2+1)| = n-k-1 (if k is odd)
    // The differences generated are n-1, n-2, ..., n-k.
    // The last difference generated by the alternating part is |p_k - p_{k+1}|.
    // If k is even, p_k = k/2 + 1, p_{k+1} = n - k/2. Difference is n - k/2 - (k/2 + 1) = n - k - 1.
    // If k is odd, p_k = n - (k-1)/2, p_{k+1} = (k-1)/2 + 1. Difference is n - (k-1)/2 - ((k-1)/2 + 1) = n - k.
    // So the differences generated are n-1, n-2, ..., n-k.
    // The last element used in the alternating part is p_{k+1}.
    // The remaining numbers are `left` to `right`.
    // We append them in increasing order. This will generate differences of 1.
    // Since k >= 1, the difference 1 is always among the k largest differences (n-1, ..., n-k) if n-k <= 1.
    // If n-k > 1, then 1 is not among n-1, ..., n-k.
    // However, the problem asks for *exactly* k distinct elements.
    // The construction `1, n, 2, n-1, 3, n-2, ...` for `k+1` elements generates `k` distinct differences: `n-1, n-2, ..., n-k`.
    // After these `k+1` elements, the remaining numbers are `left, left+1, ..., right`.
    // We append them in increasing order. This means `p_{k+1}, p_{k+2}, ..., p_{n-1}, p_n` will be `p_{k+1}, left, left+1, ..., right`.
    // The differences will be `|p_{k+1} - left|`, `|left - (left+1)|=1`, `|(left+1) - (left+2)|=1`, etc.
    // The difference `|p_{k+1} - left|` will be `| (k/2+1) - (k/2+2) | = 1` if k is even.
    // Or `| (n-(k-1)/2) - ((k-1)/2+2) | = n - k - 1` if k is odd.
    // In both cases, the new differences introduced are 1, or n-k-1.
    // The set of differences generated by the first k+1 elements is {n-1, n-2, ..., n-k}.
    // If k=1, differences are {n-1}. Remaining elements are appended.
    // p = {1, n, 2, 3, ..., n-1}. Differences: |1-n|=n-1, |n-2|=n-2, |2-3|=1, ...
    // This generates n-1, n-2, 1. This is 3 distinct differences if n-1, n-2, 1 are all distinct.
    // This is not what we want.

    // Let's re-evaluate the strategy for generating exactly k differences.
    // We want to generate differences 1, 2, ..., k.
    // A common pattern for this is: 1, k+1, 2, k, 3, k-1, ...
    // This generates differences k, k-1, k-2, ...
    // Example: n=5, k=2. We want differences {1, 2}.
    // Try to generate k largest differences: n-1, n-2, ..., n-k.
    // p = {1, n, 2, n-1, 3, n-2, ...}
    // For n=3, k=2:
    // p_0 = 1 (left=2)
    // p_1 = 3 (right=2)
    // p_2 = 2 (left=3)
    // p = {1, 3, 2}. Differences: |1-3|=2, |3-2|=1. Distinct: {1, 2}. Count = 2. This is k. Correct.

    // For n=5, k=2:
    // p_0 = 1 (left=2)
    // p_1 = 5 (right=4)
    // p_2 = 2 (left=3)
    // p = {1, 5, 2}. Differences: |1-5|=4, |5-2|=3. Distinct: {3, 4}. Count = 2. This is k.
    // Remaining numbers: 3, 4.
    // Append them in increasing order: p = {1, 5, 2, 3, 4}.
    // Differences: |1-5|=4, |5-2|=3, |2-3|=1, |3-4|=1. Distinct: {1, 3, 4}. Count = 3. This is not k=2.

    // The example output for n=5, k=2 is 1 3 2 4 5.
    // Differences: |1-3|=2, |3-2|=1, |2-4|=2, |4-5|=1. Distinct: {1, 2}. Count = 2. This is k.
    // This pattern is different. It generates 1, 2, ..., k.
    // How to generate 1, 2, ..., k?
    // Start with 1.
    // Then 1 + k = k+1. Difference is k.
    // Then k+1 - (k-1) = 2. Difference is k-1.
    // Then 2 + (k-2) = k. Difference is k-2.
    // Then k - (k-3) = 3. Difference is k-3.
    // This generates k, k-1, k-2, ..., 1.
    // Let's try this:
    // p_0 = 1
    // p_1 = 1 + k
    // p_2 = (1+k) - (k-1) = 2
    // p_3 = 2 + (k-2) = k
    // p_4 = k - (k-3) = 3
    // ...
    // This sequence is 1, k+1, 2, k, 3, k-1, ...
    // This uses numbers from 1 to k+1.
    // Let's try to build the permutation using this pattern for the first k+1 elements.
    // `current_val = 1`
    // `diff_to_add = k`
    // `p[0] = current_val`
    // `for i = 1 to k:`
    //   `if i is odd:`
    //     `current_val += diff_to_add`
    //   `else:`
    //     `current_val -= diff_to_add`
    //   `p[i] = current_val`
    //   `diff_to_add--`

    // Example: n=5, k=2
    // p[0] = 1
    // i=1 (odd): current_val = 1 + 2 = 3. p[1] = 3. diff_to_add = 1.
    // i=2 (even): current_val = 3 - 1 = 2. p[2] = 2. diff_to_add = 0.
    // Permutation so far: {1, 3, 2}.
    // Differences: |1-3|=2, |3-2|=1. Distinct: {1, 2}. Count = 2. This is k.
    // The numbers used are 1, 2, 3.
    // Remaining numbers: 4, 5.
    // Append them in increasing order: {1, 3, 2, 4, 5}.
    // Differences: |1-3|=2, |3-2|=1, |2-4|=2, |4-5|=1. Distinct: {1, 2}. Count = 2. This is k.
    // This matches the example output!

    // Example: n=3, k=2
    // p[0] = 1
    // i=1 (odd): current_val = 1 + 2 = 3. p[1] = 3. diff_to_add = 1.
    // i=2 (even): current_val = 3 - 1 = 2. p[2] = 2. diff_to_add = 0.
    // Permutation so far: {1, 3, 2}.
    // Differences: |1-3|=2, |3-2|=1. Distinct: {1, 2}. Count = 2. This is k.
    // No remaining numbers.
    // Output: {1, 3, 2}. Matches example.

    // Example: n=3, k=1
    // p[0] = 1
    // i=1 (odd): current_val = 1 + 1 = 2. p[1] = 2. diff_to_add = 0.
    // Permutation so far: {1, 2}.
    // Differences: |1-2|=1. Distinct: {1}. Count = 1. This is k.
    // Remaining numbers: 3.
    // Append: {1, 2, 3}.
    // Differences: |1-2|=1, |2-3|=1. Distinct: {1}. Count = 1. This is k.
    // Matches example.

    // This strategy seems robust.
    // The first k+1 elements are constructed as:
    // p[0] = 1
    // p[1] = 1 + k
    // p[2] = (1+k) - (k-1) = 2
    // p[3] = 2 + (k-2) = k
    // p[4] = k - (k-3) = 3
    // ...
    // This sequence uses numbers from 1 to k+1.
    // The differences generated are k, k-1, k-2, ..., 1. These are exactly k distinct differences.
    // After these k+1 elements, the numbers 1 to k+1 have been used.
    // The remaining numbers are k+2, k+3, ..., n.
    // We append these remaining numbers in increasing order.
    // The last element of the constructed part is p[k].
    // The next element is p[k+1] = k+2.
    // The difference |p[k] - p[k+1]| will be either:
    // If k is odd: p[k] = (k+1)/2 + 1. p[k+1] = k+2.
    // Difference = |((k+1)/2 + 1) - (k+2)| = |(k+3)/2 - (k+2)| = |(k+3 - 2k - 4)/2| = |(-k-1)/2| = (k+1)/2.
    // This difference is between 1 and k. So it's already in the set {1, ..., k}.
    // If k is even: p[k] = k/2 + 1. p[k+1] = k+2.
    // Difference = |(k/2 + 1) - (k+2)| = |(k+2 - 2k - 4)/2| = |(-k-2)/2| = (k+2)/2.
    // This difference is also between 1 and k. So it's already in the set {1, ..., k}.
    // All subsequent differences will be 1 (e.g., |(k+2)-(k+3)|=1).
    // Since k >= 1, the difference 1 is always in the set {1, ..., k}.
    // Thus, this strategy correctly generates exactly k distinct differences.

    int current_val = 1;
    int diff_to_add = k;
    p[0] = current_val;

    for (int i = 1; i <= k; ++i) {
        if (i % 2 == 1) { // Odd index, add diff_to_add
            current_val += diff_to_add;
        } else { // Even index, subtract diff_to_add
            current_val -= diff_to_add;
        }
        p[i] = current_val;
        diff_to_add--;
    }

    // Fill the rest of the permutation with unused numbers in increasing order
    // The numbers used are 1 to k+1.
    // So, start filling from k+2.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // This will be k+2, k+3, ..., n
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int mid_idx = n / 2; // For 0-indexed array, this is the middle position

    // 1. Make the median element equal to s
    operations += std::abs(a[mid_idx] - s);

    // 2. Ensure elements to the left of median are <= s
    // If a[i] > s, it must be decreased to s.
    // If a[i] <= s, it's already fine relative to s.
    for (int i = 0; i < mid_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // 3. Ensure elements to the right of median are >= s
    // If a[i] < s, it must be increased to s.
    // If a[i] >= s, it's already fine relative to s.
    for (int i = mid_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the maximum possible length of a strictly increasing prefix ending at index i
    // such that a[j] >= j for 0 <= j <= i.
    // More precisely, a[j] must be at least j.
    // If a[j] < j, then it's impossible to make a[0] < a[1] < ... < a[j]
    // because a[j] would need to be at least j.
    // So, we find the first index `left_fail` where a[left_fail] < left_fail.
    // All elements before `left_fail` (i.e., 0 to left_fail-1) satisfy a[i] >= i.
    int left_fail = n;
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            left_fail = i;
            break;
        }
    }

    // Calculate the maximum possible length of a strictly decreasing suffix starting at index i
    // such that a[j] >= (n-1)-j for i <= j <= n-1.
    // More precisely, a[j] must be at least (n-1)-j.
    // If a[j] < (n-1)-j, then it's impossible to make a[j] > ... > a[n-1]
    // because a[j] would need to be at least (n-1)-j.
    // So, we find the first index `right_fail` (from the right) where a[right_fail] < (n-1)-right_fail.
    // All elements after `right_fail` (i.e., right_fail+1 to n-1) satisfy a[i] >= (n-1)-i.
    int right_fail = -1;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1) - i) {
            right_fail = i;
            break;
        }
    }

    // A sharpened array can be formed if there exists a peak k (0-indexed)
    // such that the prefix a[0...k] can be made strictly increasing
    // AND the suffix a[k...n-1] can be made strictly decreasing.
    //
    // The prefix a[0...k] can be made strictly increasing if a[i] >= i for all 0 <= i <= k.
    // This means k must be less than `left_fail`.
    //
    // The suffix a[k...n-1] can be made strictly decreasing if a[i] >= (n-1)-i for all k <= i <= n-1.
    // This means k must be greater than `right_fail`.
    //
    // So, we need to find if there is any k such that `k < left_fail` AND `k > right_fail`.
    // This is equivalent to checking if `left_fail > right_fail`.
    // If `left_fail > right_fail`, then there is at least one `k` (e.g., `right_fail + 1`)
    // that satisfies both conditions.
    //
    // Example: n=6, a = [100, 11, 15, 9, 7, 8]
    // i:     0   1   2   3   4   5
    // a[i]: 100 11  15  9   7   8
    // i:     0   1   2   3   4   5
    // a[i]>=i: T   T   T   T   T   T  (left_fail = 6)
    //
    // (n-1)-i: 5   4   3   2   1   0
    // a[i]>=(n-1)-i:
    // i=5: a[5]=8 >= 0 (T)
    // i=4: a[4]=7 >= 1 (T)
    // i=3: a[3]=9 >= 2 (T)
    // i=2: a[2]=15 >= 3 (T)
    // i=1: a[1]=11 >= 4 (T)
    // i=0: a[0]=100 >= 5 (T)
    // (right_fail = -1)
    //
    // left_fail (6) > right_fail (-1) -> Yes.
    //
    // Example: n=4, a = [0, 1, 1, 0]
    // i:     0   1   2   3
    // a[i]:  0   1   1   0
    // i:     0   1   2   3
    // a[i]>=i: T   T   F   F  (left_fail = 2)
    //
    // (n-1)-i: 3   2   1   0
    // a[i]>=(n-1)-i:
    // i=3: a[3]=0 >= 0 (T)
    // i=2: a[2]=1 >= 1 (T)
    // i=1: a[1]=1 >= 2 (F) (right_fail = 1)
    //
    // left_fail (2) > right_fail (1) -> Yes.
    // Wait, example output is No. What's wrong?
    //
    // The condition for a sharpened array is `a_1 < a_2 < ... < a_k` AND `a_k > a_{k+1} > ... > a_n`.
    // This means `b_i = i` for `0 <= i < k` and `b_k` is the peak.
    // And `b_j = (n-1)-j` for `k < j <= n-1` and `b_k` is the peak.
    //
    // The minimum values for the elements are:
    // b_0 = 0
    // b_1 = 1
    // ...
    // b_{k-1} = k-1
    // b_k = max(k, (n-1)-k) + 1 (or just some value that allows both sides)
    // b_{k+1} = (n-1)-(k+1)
    // ...
    // b_{n-1} = 0
    //
    // The crucial part is that `a_i` must be at least `i` for the left side,
    // and `a_i` must be at least `(n-1)-i` for the right side.
    //
    // The `left_fail` logic is correct: `a[i] >= i` for `0 <= i < left_fail`.
    // The `right_fail` logic is correct: `a[i] >= (n-1)-i` for `right_fail < i <= n-1`.
    //
    // If we pick a peak `k`, then we need:
    // 1. `a[i] >= i` for all `0 <= i <= k`. This means `k < left_fail`.
    // 2. `a[i] >= (n-1)-i` for all `k <= i <= n-1`. This means `k > right_fail`.
    //
    // So, we need to find if there exists a `k` such that `right_fail < k < left_fail`.
    // This is equivalent to `right_fail + 1 < left_fail`.
    //
    // Let's re-check the example: n=4, a = [0, 1, 1, 0]
    // left_fail = 2 (because a[2]=1 < 2)
    // right_fail = 1 (because a[1]=1 < (4-1)-1 = 2)
    //
    // We need `right_fail + 1 < left_fail`
    // `1 + 1 < 2` -> `2 < 2` which is false.
    // So, output "No". This matches the example.

    if (right_fail + 1 < left_fail) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i; // Not strictly needed for A, but good practice
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in descending order based on value, but keep original indices
    // We need to sort B by value to pair with A, but the output order is determined by B's original index.
    // So, we sort B by value, then iterate through sorted A and sorted B to assign.
    std::sort(b_elements.begin(), b_elements.end(), [](const Element& x, const Element& y) {
        return x.value > y.value; // Sort B values in descending order
    });

    std::vector<long long> result_a_prime(m);

    // Pair the smallest A with the largest B, second smallest A with second largest B, and so on.
    // This is because F(n, k) = n / (k+1).
    // To maximize sum(A_i' / (B_i + 1)), we want to pair large A_i' with small (B_i + 1)
    // and small A_i' with large (B_i + 1).
    // This means large A_i' with small B_i, and small A_i' with large B_i.
    // So, sort A ascending, sort B descending.
    for (int i = 0; i < m; ++i) {
        // a_elements[i] is the i-th smallest value from original A
        // b_elements[i] is the i-th largest value from original B
        // We assign a_elements[i].value to the position corresponding to b_elements[i].original_index
        result_a_prime[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> is_suffix_perm(n + 1, false);

    // Check for prefix permutations
    std::vector<bool> seen_prefix(n + 1, false);
    int max_val_prefix = 0;
    bool possible_prefix = true;
    for (int i = 0; i < n; ++i) {
        if (seen_prefix[a[i]]) {
            possible_prefix = false;
        }
        seen_prefix[a[i]] = true;
        max_val_prefix = std::max(max_val_prefix, a[i]);
        if (possible_prefix && max_val_prefix == (i + 1)) {
            is_prefix_perm[i + 1] = true;
        } else {
            is_prefix_perm[i + 1] = false; // Once false, stays false for longer prefixes
        }
    }

    // Check for suffix permutations
    std::vector<bool> seen_suffix(n + 1, false);
    int max_val_suffix = 0;
    bool possible_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        int current_len = n - i;
        if (seen_suffix[a[i]]) {
            possible_suffix = false;
        }
        seen_suffix[a[i]] = true;
        max_val_suffix = std::max(max_val_suffix, a[i]);
        if (possible_suffix && max_val_suffix == current_len) {
            is_suffix_perm[current_len] = true;
        } else {
            is_suffix_perm[current_len] = false; // Once false, stays false for longer suffixes
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, and l2 must be at least 1
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    long long total_toys = A + B + C + D;

    std::vector<std::string> result(4);

    // Box 1: (-inf, -1] (Negative, magnitude >= 1)
    // Final toy must be negative and have magnitude >= 1.
    // For negative: odd number of initial negative toys (A+B).
    // For magnitude >= 1:
    //   - If there's at least one toy with magnitude >= 1 (A or D > 0),
    //     and we can ensure it doesn't get "shrunk" by too many small numbers.
    //   - If all initial toys have magnitude < 1 (A=0, D=0), then the final product will always have magnitude < 1 (unless total_toys = 1 and B or C is the only toy).
    //     But if total_toys = 1, it's just the initial toy.
    //     If total_toys > 1 and A=0, D=0, then all products will be < 1.
    //
    // Let's simplify:
    // A toy in Box 1 is possible if:
    // 1. The final sign can be negative (B_parity_final = 1).
    // 2. The final magnitude can be >= 1.
    //    This requires at least one initial toy with magnitude >= 1 (A > 0 or D > 0).
    //    AND it must be possible to avoid shrinking it below 1.
    //    If A+D > 0, we can always pick a large number and multiply it by another large number, or by 1 (if we have a toy with value 1).
    //    The only way to guarantee magnitude < 1 is if all initial toys have magnitude < 1 (A=0, D=0).
    //    So, if A+D > 0, it's possible to get magnitude >= 1.
    //
    // Combining:
    // Box 1 (NL):
    //   - Final sign is negative: (A+B) % 2 == 1
    //   - Final magnitude is >= 1: (A > 0 || D > 0)
    //   - Exception: If total_toys = 1, then it's just A=1, B=C=D=0.
    //     In this case, A=1, (A+B)%2 = 1, (A>0 || D>0) = true. So it works.
    //
    //   Consider the case where A+D=0. Then all initial toys are in B or C.
    //   All products will have magnitude < 1. So Box 1 is impossible.
    //   So, A+D > 0 is a necessary condition for magnitude >= 1.
    //
    //   Is it sufficient? If A+D > 0, can we always make magnitude >= 1?
    //   Yes. We can always pair up all B and C toys first.
    //   (B+C) toys in (-1, 1). Their product will be in (0, 1). Let's call this P_small.
    //   Then we have A+D toys in (-inf, -1] U [1, inf).
    //   If A+D > 0, we can always make a product with magnitude >= 1 from these.
    //   If we have P_small and a toy from A or D, say X.
    //   If X is large, X * P_small could be < 1 or >= 1.
    //   This is tricky. The "randomly" part means we can't control the sequence.
    //
    // Let's re-evaluate based on parity of negative numbers and existence of large numbers.
    //
    // Parity of negative numbers:
    // (A+B) % 2 == 1 for negative final product.
    // (A+B) % 2 == 0 for positive final product.
    //
    // Magnitude >= 1:
    // This is possible if and only if there is at least one toy with magnitude >= 1 (A > 0 or D > 0)
    // AND it's possible to avoid multiplying it by too many small numbers.
    //
    // Consider the total number of toys.
    // If total_toys = 1:
    //   A=1 -> Box 1 Ya, others Tidak
    //   B=1 -> Box 2 Ya, others Tidak
    //   C=1 -> Box 3 Ya, others Tidak
    //   D=1 -> Box 4 Ya, others Tidak
    //
    // If total_toys > 1:
    //
    // Box 1 (NL):
    //   - Needs odd number of negative toys (A+B).
    //   - Needs at least one toy with magnitude >= 1 (A > 0 or D > 0).
    //   - If A+D == 0, then all toys are in B or C. All products will have magnitude < 1. So Box 1 is impossible.
    //   - If A+D > 0:
    //     - If (A+B) % 2 == 1: Possible. We can always pick a toy from A or D, and multiply it by other toys.
    //       If we have a toy X with |X| >= 1, and we have a toy Y with |Y| < 1.
    //       If we multiply X by Y, the magnitude might become < 1.
    //       However, the problem states "randomly". This implies we need to find *any* sequence.
    //       If A+D > 0, it is possible to keep the magnitude >= 1.
    //       Example: If we have one toy X with |X| >= 1, and many toys Y_i with |Y_i| < 1.
    //       We can multiply all Y_i together first. Their product P_small will be in (0, 1).
    //       Then multiply X by P_small. The result |X * P_small| could be < 1.
    //       This is the core difficulty.
    //
    // Let's use the properties of the number of toys.
    //
    // Box 1 (NL):
    //   - Needs (A+B) % 2 == 1 (odd negatives)
    //   - Needs A > 0 or D > 0 (at least one large magnitude toy)
    //   - If A+D == 0, then all toys are in B or C. All products will have magnitude < 1. So Box 1 is impossible.
    //   - If A+D > 0:
    //     - If (A+B) % 2 == 1: Ya.
    //       We can always construct a scenario. For example, pick values like:
    //       A: -2, -3, ...
    //       B: -0.5, -0.6, ...
    //       C: 0.5, 0.6, ...
    //       D: 2, 3, ...
    //       To get NL:
    //       If A > 0, pick a toy from A, say -2.
    //       If D > 0, pick a toy from D, say 2.
    //       If (A+B) is odd, we need a negative final product.
    //       If A > 0, we can use a toy from A.
    //       If D > 0 and A=0, we need an odd number of B toys.
    //       If A+D > 0, we can always ensure magnitude >= 1.
    //       Consider the case where we have one toy X with |X| >= 1, and all other toys Y_i have |Y_i| < 1.
    //       If we multiply X by 1/|X| (if |X|>1) and then by other small numbers, it can become small.
    //       But we can choose specific values.
    //       If A+D > 0, we can pick a toy with value 1 (from D) or -1 (from A).
    //       If we have a toy with value 1 or -1, multiplying by it doesn't change magnitude.
    //       If A+D > 0, we can always pick values such that one toy is 1 (if D>0) or -1 (if A>0).
    //       Then, we can multiply all other toys together. Let their product be P.
    //       Then multiply P by 1 or -1. The magnitude of the final product will be |P|.
    //       If P has magnitude >= 1, then the final product has magnitude >= 1.
    //       If P has magnitude < 1, then the final product has magnitude < 1.
    //       This doesn't guarantee anything.
    //
    // The key insight is that "randomly" means we can choose the values of the toys.
    // If we want to achieve a certain box, we can pick specific values for the toys.
    //
    // Box 1 (NL):
    //   - Final sign: (A+B) % 2 == 1
    //   - Final magnitude: >= 1
    //   - To get magnitude >= 1: We need A > 0 or D > 0.
    //     If A+D == 0, all toys are in B or C. All products will have magnitude < 1. So Box 1 is impossible.
    //     If A+D > 0, we can pick values such that one toy is 1 (if D>0) or -1 (if A>0).
    //     Let's say we have D > 0. We pick one toy to be 1.0. All other D-1 toys are 2.0.
    //     All A toys are -2.0. All B toys are -0.5. All C toys are 0.5.
    //     We can multiply all toys except the 1.0 toy. Let their product be P_rest.
    //     Then multiply P_rest by 1.0. The final magnitude is |P_rest|.
    //     If P_rest has magnitude >= 1, then Box 1 is possible.
    //     P_rest has magnitude >= 1 if (A-1 if A>0 else A) + (D-1 if D>0 else D) > 0.
    //     This is getting complicated.
    //
    // Let's simplify the conditions for magnitude:
    // A final product can have magnitude >= 1 if and only if (A > 0 or D > 0).
    // This is because if A+D=0, all initial toys have magnitude < 1, so any product will also have magnitude < 1.
    // If A+D > 0, we can choose values such that one toy is 1 (if D>0) or -1 (if A>0).
    // All other toys can be chosen to be 1 (if D>1), -1 (if A>1), 0.5 (C), -0.5 (B).
    // If we have at least one toy with magnitude >= 1, say X.
    // We can set X to be 1 (if D>0) or -1 (if A>0).
    // All other toys can be set to 1 (if D>1), -1 (if A>1), 0.5 (C), -0.5 (B).
    // The product of all toys except X will be P_other.
    // The final product will be X * P_other.
    // If we want |X * P_other| >= 1, we need |P_other| >= 1.
    // This means we need (A-1 if A>0 else A) + (D-1 if D>0 else D) > 0.
    // This is equivalent to A+D > 1.
    //
    // So, for magnitude >= 1:
    //   - If A+D == 0: Impossible.
    //   - If A+D == 1: Possible only if total_toys == 1.
    //     If total_toys > 1 and A+D == 1, say A=1, B=1, C=0, D=0.
    //     Then we have one toy in A (e.g., -2) and one in B (e.g., -0.5).
    //     Product is 1.0. This is in Box 4. Magnitude is >= 1.
    //     So, if A+D >= 1, it is possible to get magnitude >= 1.
    //     We can choose values such that all B and C toys are very close to 1 (e.g., 0.9999).
    //     And A and D toys are very large (e.g., 1000).
    //     Then the product will be large.
    //     So, magnitude >= 1 is possible if and only if A+D > 0.
    //
    // Let's re-evaluate the conditions for each box:
    //
    // Box 1 (NL): Negative, magnitude >= 1
    //   - Sign: (A+B) % 2 == 1
    //   - Magnitude: A > 0 or D > 0
    //   - If total_toys == 1: A=1, B=C=D=0. (A+B)%2=1, A>0. Ya.
    //   - If total_toys > 1:
    //     - If (A+B) % 2 == 1 and (A > 0 or D > 0): Ya.
    //     - Else: Tidak.
    //
    // Box 2 (NS): Negative, magnitude < 1
    //   - Sign: (A+B) % 2 == 1
    //   - Magnitude: < 1
    //   - To get magnitude < 1:
    //     - If B > 0 or C > 0: Possible. We can pick values like 0.0001 for B/C toys.
    //     - If B=0 and C=0: All toys are in A or D.
    //       If A+D > 0, then all products will have magnitude >= 1 (unless total_toys=1).
    //       If A+D > 0 and B=0 and C=0, then magnitude < 1 is impossible.
    //       So, we need B > 0 or C > 0.
    //   - If total_toys == 1: B=1, A=C=D=0. (A+B)%2=1, B>0. Ya.
    //   - If total_toys > 1:
    //     - If (A+B) % 2 == 1 and (B > 0 or C > 0): Ya.
    //     - Else: Tidak.
    //
    // Box 3 (PS): Positive, magnitude < 1
    //   - Sign: (A+B) % 2 == 0
    //   - Magnitude: < 1
    //   - To get magnitude < 1: B > 0 or C > 0. (Same logic as Box 2)
    //   - If total_toys == 1: C=1, A=B=D=0. (A+B)%2=0, C>0. Ya.
    //   - If total_toys > 1:
    //     - If (A+B) % 2 == 0 and (B > 0 or C > 0): Ya.
    //     - Else: Tidak.
    //
    // Box 4 (PL): Positive, magnitude >= 1
    //   - Sign: (A+B) % 2 == 0
    //   - Magnitude: >= 1
    //   - To get magnitude >= 1: A > 0 or D > 0. (Same logic as Box 1)
    //   - If total_toys == 1: D=1, A=B=C=0. (A+B)%2=0, D>0. Ya.
    //   - If total_toys > 1:
    //     - If (A+B) % 2 == 0 and (A > 0 or D > 0): Ya.
    //     - Else: Tidak.

    // Special case: total_toys = 1
    if (total_toys == 1) {
        if (A == 1) { result[0] = "Ya"; result[1] = "Tidak"; result[2] = "Tidak"; result[3] = "Tidak"; }
        else if (B == 1) { result[0] = "Tidak"; result[1] = "Ya"; result[2] = "Tidak"; result[3] = "Tidak"; }
        else if (C == 1) { result[0] = "Tidak"; result[1] = "Tidak"; result[2] = "Ya"; result[3] = "Tidak"; }
        else if (D == 1) { result[0] = "Tidak"; result[1] = "Tidak"; result[2] = "Tidak"; result[3] = "Ya"; }
    } else {
        // General case: total_toys > 1
        bool odd_negatives = ((A + B) % 2 == 1);
        bool has_large_mag = (A > 0 || D > 0);
        bool has_small_mag = (B > 0 || C > 0);

        // Box 1 (NL): Negative, magnitude >= 1
        if (odd_negatives && has_large_mag) {
            result[0] = "Ya";
        } else {
            result[0] = "Tidak";
        }

        // Box 2 (NS): Negative, magnitude < 1
        if (odd_negatives && has_small_mag) {
            result[1] = "Ya";
        } else {
            result[1] = "Tidak";
        }

        // Box 3 (PS): Positive, magnitude < 1
        if (!odd_negatives && has_small_mag) {
            result[2] = "Ya";
        } else {
            result[2] = "Tidak";
        }

        // Box 4 (PL): Positive, magnitude >= 1
        if (!odd_negatives && has_large_mag) {
            result[3] = "Ya";
        } else {
            result[3] = "Tidak";
        }
    }

    std::cout << result[0] << " " << result[1] << " " << result[2] << " " << result[3] << std::endl;
}

