#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;
    long long chanek_coins = 0;

    while (n > 0) {
        if (n % 2 != 0) { // N is odd
            chanek_coins += 1;
            n -= 1;
        } else { // N is even
            if (n == 2) { // Special case for N=2
                chanek_coins += 1;
                n -= 1;
            } else {
                // Check if N is a power of 2
                // A number is a power of 2 if (n & (n - 1)) == 0
                // And n is not 0
                if ((n & (n - 1)) == 0) { // N is a power of 2 (and N > 2)
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N is even but not a power of 2
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        }
        // Opponent's turn (if n > 0)
        if (n > 0) {
            if (n % 2 != 0) { // N is odd
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2
                    n -= 1;
                } else {
                    // Check if N is a power of 2
                    if ((n & (n - 1)) == 0) { // N is a power of 2 (and N > 2)
                        n /= 2;
                    } else { // N is even but not a power of 2
                        n /= 2;
                    }
                }
            }
        }
    }
    return chanek_coins;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

