        std::string s;
        std::cin >> s;
        int n = s.length();

        int countR = 0;
        int countS = 0;
        int countP = 0;

        for (char move : s) {
            if (move == 'R') {
                countR++;
            } else if (move == 'S') {
                countS++;
            } else { // move == 'P'
                countP++;
            }
        }

        char most_frequent_bot_move;
        if (countR >= countS && countR >= countP) {
            most_frequent_bot_move = 'R';
        } else if (countS >= countR && countS >= countP) {
            most_frequent_bot_move = 'S';
        } else { // countP is the maximum
            most_frequent_bot_move = 'P';
        }

        char optimal_player_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << optimal_player_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
    } else {
        // We need to append elements.
        // Let S_new = current_sum + b1 + b2 + ...
        // Let X_new = current_xor_sum ^ b1 ^ b2 ^ ...
        // We want S_new = 2 * X_new

        // Strategy: Append two elements.
        // Let the two elements be X_0 and S_0 + X_0.
        // Let X_0 be the current_xor_sum.
        // Let S_0 be the current_sum.
        // Appended elements: b1 = X_0, b2 = S_0 + X_0.
        // New sum: S' = S_0 + X_0 + (S_0 + X_0) = 2*S_0 + 2*X_0
        // New XOR sum: X' = X_0 ^ X_0 ^ (S_0 + X_0) = 0 ^ (S_0 + X_0) = S_0 + X_0
        // Check condition: S' = 2 * X'
        // (2*S_0 + 2*X_0) = 2 * (S_0 + X_0)
        // This identity holds true for any S_0 and X_0.
        // So, appending X_0 and S_0 + X_0 always makes the array good.

        // The problem states that appended elements must be non-negative.
        // X_0 is always non-negative.
        // S_0 is always non-negative (sum of non-negative numbers).
        // So S_0 + X_0 is also non-negative.

        std::cout << 2 << std::endl;
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

