int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means this 'b' will eventually be
            // jumped over by all 'a's to its left.
            // Each 'a' to its left will perform an operation with this 'b'.
            // When an 'a' jumps over this 'b', it becomes 'bba'.
            // The 'a' moves to the right of this 'b'.
            // The 'a' also creates a new 'b' to its left.
            // This new 'b' will then be jumped over by any 'a's further to its left.
            // The number of 'a's currently to the left of this 'b' is `count_a`.
            // Each of these `count_a` 'a's will jump over this 'b'.
            // This adds `count_a` steps.
            // After these `count_a` 'a's jump over this 'b', they will be to its right.
            // Each of these `count_a` 'a's also creates a new 'b' to its left.
            // These `count_a` new 'b's effectively double the number of 'a's that
            // will interact with 'b's further to the left.
            // So, `count_a` effectively doubles for the next 'b' encountered.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' is now to the left
            // of any 'b's we have already processed (to its right).
            // This 'a' will eventually jump over all 'b's to its right.
            // So, we increment the count of 'a's that are waiting to jump.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
