// Function to convert a number to its parity pattern string
// The pattern is always 18 characters long, padded with '0's (even) from the left.
std::string to_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the left to make it 18 characters long
    // The pattern is built from right to left, so we need to reverse it
    // and then pad. Or, more simply, just pad at the end.
    // Example: 241 -> "100". If we want 18 chars, it's "00...00100".
    // The map key should be the canonical 18-digit pattern.
    // The problem states: "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
    // "Similarly, if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This means we should always compare against an 18-digit pattern.
    // So, for 241, its pattern is "00...00100" (15 zeros, then 100).
    // The string `pattern` currently holds "100" (reversed digits).
    // We need to reverse it to get "001", then pad to 18 digits: "000...0001".
    // No, the problem says "i-th from the right digit".
    // So for 241, rightmost is 1 (odd), next is 4 (even), next is 2 (even).
    // Pattern for 241 is "001".
    // If query is "? 1", it means "00...001".
    // If query is "? 010", it means "00...010".
    // So, the canonical form for storage should be the pattern itself, padded to 18 from the left.
    // For 241, it's "001". Padded to 18: "000000000000000001".
    // The `pattern` string is built from right to left, so `pattern` for 241 is "100".
    // We need to reverse it to get "001" and then pad.
    std::reverse(pattern.begin(), pattern.end());
    while (pattern.length() < 18) {
        pattern = '0' + pattern;
    }
    return pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the left to 18 characters
            while (s.length() < 18) {
                s = '0' + s;
            }
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

