int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // prefix_counts[i][0] stores count of 'x' in s[0...i-1]
    // prefix_counts[i][1] stores count of 'y' in s[0...i-1]
    // prefix_counts[i][2] stores count of 'z' in s[0...i-1]
    std::vector<std::vector<int>> prefix_counts(n + 1, std::vector<int>(3, 0));

    for (int i = 0; i < n; ++i) {
        prefix_counts[i + 1][0] = prefix_counts[i][0];
        prefix_counts[i + 1][1] = prefix_counts[i][1];
        prefix_counts[i + 1][2] = prefix_counts[i][2];
        if (s[i] == 'x') {
            prefix_counts[i + 1][0]++;
        } else if (s[i] == 'y') {
            prefix_counts[i + 1][1]++;
        } else { // s[i] == 'z'
            prefix_counts[i + 1][2]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;
        // Adjust to 0-indexed
        --l; 
        --r;

        int len = r - l + 1;

        if (len < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[r + 1][0] - prefix_counts[l][0];
        int count_y = prefix_counts[r + 1][1] - prefix_counts[l][1];
        int count_z = prefix_counts[r + 1][2] - prefix_counts[l][2];

        // The algorithm terminates if and only if the counts of 'x', 'y', 'z'
        // in the substring are "balanced" enough such that any 3-character
        // substring can be rearranged to one of "zyx", "xzy", "yxz".
        // This means the counts must be nearly equal.
        // Specifically, the difference between the maximum and minimum count
        // of any character ('x', 'y', 'z') in the substring must be at most 1.
        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

