// Function to get prime factors of a number
std::map<long long, int> get_prime_factors(long long n) {
    std::map<long long, int> factors;
    for (long long i = 2; i * i <= n; ++i) {
        while (n % i == 0) {
            factors[i]++;
            n /= i;
        }
    }
    if (n > 1) {
        factors[n]++;
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that p % x == 0 and x % q != 0.
        // This means x must not be divisible by q.
        // To make x not divisible by q, we must remove at least one prime factor from p
        // such that the resulting x no longer has all prime factors of q with sufficient powers.

        // Get prime factors of q
        std::map<long long, int> q_factors = get_prime_factors(q);

        long long max_x = 0;

        // Iterate through each distinct prime factor f of q
        for (auto const& [f, q_power] : q_factors) {
            // Calculate the current p_copy, which is p divided by f until it's no longer divisible by q.
            // We want to find the largest x = p / (f^k) such that x % q != 0.
            // To do this, we need to find the smallest k such that p / (f^k) is not divisible by q.
            // Or, more simply, we want to find the largest divisor of p that is not divisible by q.
            // Consider p_prime = p.
            // Divide p_prime by f until p_prime is no longer divisible by q.
            // The resulting p_prime is a candidate for x.

            long long current_p = p;
            while (current_p % q == 0) {
                current_p /= f;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

