    long long min_x = -2000000000LL; // Effectively negative infinity
    long long max_x = 2000000000LL;  // Effectively positive infinity
    long long min_y = -2000000000LL; // Effectively negative infinity
    long long max_y = 2000000000LL;  // Effectively positive infinity

    for (int i = 0; i < n; ++i) {
        long long x, y;
        int f1, f2, f3, f4;
        std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

        // f1 = 0 means cannot move left (x-1). So target X must be >= current x.
        if (f1 == 0) {
            min_x = std::max(min_x, x);
        }
        // f3 = 0 means cannot move right (x+1). So target X must be <= current x.
        if (f3 == 0) {
            max_x = std::min(max_x, x);
        }
        // f4 = 0 means cannot move down (y-1). So target Y must be >= current y.
        if (f4 == 0) {
            min_y = std::max(min_y, y);
        }
        // f2 = 0 means cannot move up (y+1). So target Y must be <= current y.
        if (f2 == 0) {
            max_y = std::min(max_y, y);
        }
    }

    if (min_x <= max_x && min_y <= max_y) {
        std::cout << 1 << " " << min_x << " " << min_y << "\n";
    } else {
