#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_password;

    for (size_t i = 0; i < s.length() - 1; ++i) {
        char c1 = s[i];
        char c2 = s[i+1];
        adj[c1].insert(c2);
        adj[c2].insert(c1);
        used_in_password.insert(c1);
        used_in_password.insert(c2);
    }
    if (s.length() == 1) { // Handle single character password
        used_in_password.insert(s[0]);
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_str = "";
    std::set<char> visited_in_layout;

    for (char c = 'a'; c <= 'z'; ++c) {
        if (used_in_password.count(c) && adj[c].size() <= 1 && !visited_in_layout.count(c)) {
            // Found a starting point for a chain (degree 0 or 1 in the password graph)
            // Build the chain forward
            char current = c;
            while (true) {
                if (visited_in_layout.count(current)) { // Cycle detected within this chain, or already part of another chain
                    // This should not happen if degrees are <= 2 and we start from degree <= 1
                    // unless there's a cycle that's not a simple path, which is caught by degree > 2
                    // or if we try to add a character already in layout_str from a different path.
                    // For simple paths, this means we've completed a segment.
                    break;
                }
                layout_str += current;
                visited_in_layout.insert(current);

                char next_char = '\0';
                for (char neighbor : adj[current]) {
                    if (!visited_in_layout.count(neighbor)) {
                        next_char = neighbor;
                        break;
                    }
                }
                if (next_char == '\0') { // No unvisited neighbors, end of chain
                    break;
                }
                current = next_char;
            }
        }
    }

    // Check if all characters used in password are included in the layout_str
    if (layout_str.length() != used_in_password.size()) {
        std::cout << "NO\n";
        return;
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (!visited_in_layout.count(c)) {
            layout_str += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

