int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_probability = 0.0;

    // Iterate over all possible first characters t[0]
    // For each possible t[0], calculate the best win probability Vasya can achieve.
    // Sum these probabilities, weighted by their frequency.
    for (int char_code = 0; char_code < 26; ++char_code) {
        const std::vector<int>& k_candidates_for_char0 = char_indices[char_code];
        if (k_candidates_for_char0.empty()) {
            continue; // This character does not appear in s, so it cannot be t[0].
        }

        // If there's only one k that results in this t[0], Vasya wins immediately.
        if (k_candidates_for_char0.size() == 1) {
            total_win_probability += 1.0;
            continue;
        }

        // If there are multiple k's, Vasya needs to pick a position p.
        // He wants to maximize the number of k's that become unique after revealing t[p].
        int max_unique_count = 0;

        // Iterate over all possible positions p (1 to L-1)
        for (int p = 1; p < L; ++p) {
            std::map<char, std::vector<int>> k_by_tp_char;
            for (int k_val : k_candidates_for_char0) {
                char tp_char = s[(k_val + p) % L];
                k_by_tp_char[tp_char].push_back(k_val);
            }

            int current_unique_count = 0;
            for (const auto& pair : k_by_tp_char) {
                if (pair.second.size() == 1) {
                    current_unique_count++;
                }
            }
            max_unique_count = std::max(max_unique_count, current_unique_count);
        }
        total_win_probability += static_cast<double>(max_unique_count) / k_candidates_for_char0.size();
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_probability / L << std::endl;

    return 0;
}

