    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial balance (strawberry - blueberry)
    int initial_balance = 0;
    for (int x : a) {
        if (x == 1) {
            initial_balance++;
        } else {
            initial_balance--;
        }
    }

    // If initial balance is 0, no jars need to be emptied.
    if (initial_balance == 0) {
        std::cout << 0 << std::endl;
        return;
    }

    // Store prefix sums for the left part (jars 1 to n)
    // balance_left[i] = (count of 1s - count of 2s) in jars [0, i-1]
    // We are interested in suffix sums from n-1 down to 0.
    // Let's define balance_left_suffix[k] as the balance of jars [n-k, n-1]
    // This is equivalent to balance of jars [0, n-1] minus balance of jars [0, n-k-1]
    // Or, more simply, we can iterate from n-1 down to 0 and calculate balance.
    // We need to find a suffix of the left part (jars from index 0 to n-1)
    // and a prefix of the right part (jars from index n to 2n-1)
    // such that their combined balance equals initial_balance.

    // Map to store the minimum length of a prefix/suffix that results in a certain balance.
    // For the left part (indices 0 to n-1), we consider suffixes ending at n-1.
    // `left_balances[diff]` stores the minimum length `k` such that the suffix `[n-k, n-1]` has a balance `diff`.
    std::map<int, int> left_balances;
    left_balances[0] = 0; // An empty suffix has balance 0 and length 0.

    int current_balance_left = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            current_balance_left++;
        } else {
            current_balance_left--;
        }
        int len = n - i; // Length of suffix [i, n-1]
        if (left_balances.find(current_balance_left) == left_balances.end()) {
            left_balances[current_balance_left] = len;
        }
    }

    // For the right part (indices n to 2n-1), we consider prefixes starting at n.
    // `right_balances[diff]` stores the minimum length `k` such that the prefix `[n, n+k-1]` has a balance `diff`.
    std::map<int, int> right_balances;
    right_balances[0] = 0; // An empty prefix has balance 0 and length 0.

    int current_balance_right = 0;
    for (int i = n; i < 2 * n; ++i) {
        if (a[i] == 1) {
            current_balance_right++;
        } else {
            current_balance_right--;
        }
        int len = i - n + 1; // Length of prefix [n, i]
        if (right_balances.find(current_balance_right) == right_balances.end()) {
            right_balances[current_balance_right] = len;
        }
    }

    int min_jars_to_empty = 2 * n; // Max possible jars to empty

    // Iterate through all possible balances from the left part
    for (auto const& [left_diff, left_len] : left_balances) {
        // We want to find a right_diff such that (initial_balance - left_diff - right_diff) == 0
        // This means right_diff should be initial_balance - left_diff
        int target_right_diff = initial_balance - left_diff;
        if (right_balances.count(target_right_diff)) {
            int right_len = right_balances[target_right_diff];
            // The number of jars kept is left_len + right_len
            // The number of jars emptied is (2*n) - (left_len + right_len)
            min_jars_to_empty = std::min(min_jars_to_empty, (2 * n) - (left_len + right_len));
        }
    }

    std::cout << min_jars_to_empty << std::endl;
}

