    std::sort(a.begin(), a.end());

    int count = 0;
    int j = 0; // Pointer for elements to be placed (the larger ones)
    for (int i = 0; i < n; ++i) { // Pointer for original positions (the smaller ones)
        // We are trying to find an element a[j] such that a[j] > a[i]
        // Since both arrays are sorted, if a[j] > a[i], then any a[k] with k > j will also be >= a[j]
        // We want to use the smallest possible a[j] that is greater than a[i]
        // to save larger elements for later, potentially larger a[i]'s.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // Found an element a[j] > a[i]
            count++;
            j++; // Move to the next element to be placed
        } else {
            // No more elements available that are greater than a[i]
            // Any subsequent a[i'] (i' > i) will be >= a[i], so no elements will be found for them either.
