#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> L(n, 0), R(n, 0);

    // Calculate L[i]: length of consecutive identical values to the left of i (inclusive)
    L[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == a[i - 1]) {
            L[i] = L[i - 1] + 1;
        } else {
            L[i] = 1;
        }
    }

    // Calculate R[i]: length of consecutive identical values to the right of i (inclusive)
    R[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == a[i + 1]) {
            R[i] = R[i + 1] + 1;
        } else {
            R[i] = 1;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) { // Find max_k for 0s
            if (i > 0 && a[i - 1] == 1) { // 10...
                max_k = std::max(max_k, (L[i] + 1) / 2);
            }
            if (i < n - 1 && a[i + 1] == 1) { // ...01
                max_k = std::max(max_k, (R[i] + 1) / 2);
            }
        }
    }

    // Apply smoothing for max_k steps
    std::vector<int> b = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) {
            if (i - max_k >= 0 && a[i - max_k] == 1) { // Check if a 1 is within reach from left
                b[i] = 1;
            }
            if (i + max_k < n && a[i + max_k] == 1) { // Check if a 1 is within reach from right
                b[i] = 1;
            }
        }
    }

    // Check for stability
    bool stable = true;
    for (int i = 1; i < n - 1; ++i) {
        int median_val = (b[i - 1] + b[i] + b[i + 1] >= 2) ? 1 : 0;
        if (b[i] != median_val) {
            stable = false;
            break;
        }
    }

    if (!stable) {
        std::cout << -1 << "\n";
    } else {
        std::cout << max_k << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << b[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Calculate the total delta applied to each element by type 1 operations
    // if we start with an all-zero array.
    std::vector<long long> delta_sum(n, 0);
    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                delta_sum[j] += op.val;
            }
        }
    }

    // Initialize the initial array `a_initial` with a very small value.
    // This is because type 2 operations give upper bounds.
    // We want to find the largest possible initial values that satisfy all constraints.
    // The maximum possible value for m_i is 5*10^7.
    // The maximum possible delta_sum[j] is 5000 * 10^4 = 5*10^7.
    // So a_initial[j] can be around 5*10^7 - 5*10^7 = 0.
    // A safe lower bound for a_initial[j] is -10^9.
    // We initialize with -2*10^9 to ensure it's smaller than any valid value.
    std::vector<long long> a_initial(n, -2000000000LL); // -2 * 10^9

    // Process type 2 operations to find upper bounds for a_initial[j]
    for (const auto& op : ops) {
        if (op.type == 2) {
            long long m_val = op.val;
            for (int j = op.l; j <= op.r; ++j) {
                // For each j in [l, r], a_initial[j] + delta_sum[j] <= m_val
                // So, a_initial[j] <= m_val - delta_sum[j]
                a_initial[j] = std::min(a_initial[j], m_val - delta_sum[j]);
            }
        }
    }

    // Check if the reconstructed a_initial is consistent with all operations
    // We need to simulate the operations with the found a_initial.
    std::vector<long long> current_a = a_initial;
    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_a[j] += op.val;
            }
        } else { // type == 2
            long long max_val_in_range = LLONG_MIN;
            for (int j = op.l; j <= op.r; ++j) {
                max_val_in_range = std::max(max_val_in_range, current_a[j]);
            }
            if (max_val_in_range != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check if all a_initial[j] are within the allowed range [-10^9, 10^9]
    for (int i = 0; i < n; ++i) {
        if (a_initial[i] < -1000000000LL || a_initial[i] > 1000000000LL) {
            std::cout << "NO\n";
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a_initial[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

