#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;
    long long total_d_cry_effect = 0; // Accumulates d_j cries from children who left

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        // Child i goes to the dentist
        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // Mark as treated

        long long current_v_cry_effect = children[i].v;
        long long current_d_cry_sum = 0; // Sum of d_j from children leaving in this step

        // Apply v_i cry effect and check for chain reactions
        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_cry_sum from previous children who left in this step
            // and total_d_cry_effect from previous turns
            children[j].p -= current_d_cry_sum;
            children[j].p -= total_d_cry_effect;

            // Apply v_i cry effect
            if (current_v_cry_effect > 0) {
                children[j].p -= current_v_cry_effect;
                current_v_cry_effect--;
            }

            // Check if child j leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                current_d_cry_sum += children[j].d;
            }
        }

        // After all children in the current iteration have been processed for v_i and d_j effects,
        // update total_d_cry_effect for the next main loop iteration.
        total_d_cry_effect += current_d_cry_sum;
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (or one empty, one full)
    // This means all f(a_i, a_j) = a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    long long goodness1 = (a[n - 2].value + a[n - 1].value) - (a[0].value + a[1].value);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: Partition into two non-empty subsequences.
    // The critical observation is that if h is large, we want to avoid the +h term.
    // If h is small, we might want to mix.
    // The minimum possible f value is a[0].value + a[1].value.
    // The maximum possible f value is a[n-1].value + a[n-2].value + h (if a[n-1] and a[n-2] are separated)
    // OR a[n-1].value + a[n-2].value (if a[n-1] and a[n-2] are together)
    // OR a[n-1].value + a[0].value + h (if a[n-1] and a[0] are separated)

    // Consider the partition where a[0] and a[1] are in one group, and a[2]...a[n-1] are in another.
    // Or more generally, a[0] is in group 1, and a[1]...a[n-1] are in group 2.
    // This is equivalent to saying a[0] is in group 1, and all others are in group 2.
    // This means a[0] is separated from all other elements.
    // The values of f will be:
    // 1. a[i] + a[j] + h for i=0, j>0
    // 2. a[i] + a[j] for i,j > 0
    //
    // min_f:
    //   - If n=2, only a[0]+a[1]+h.
    //   - If n>2, min(a[0]+a[1]+h, a[1]+a[2]).
    // max_f:
    //   - If n=2, only a[0]+a[1]+h.
    //   - If n>2, max(a[0]+a[n-1]+h, a[n-2]+a[n-1]).

    // Let's consider a specific partition: a[0] is in group 1, a[1]...a[n-1] are in group 2.
    // This is a common strategy for minimizing range when h is large.
    // The values of f are:
    // - a[0] + a[j] + h for j = 1, ..., n-1
    // - a[i] + a[j] for i, j = 1, ..., n-1 (i != j)
    //
    // Minimum f value:
    //   min_f = min(a[0].value + a[1].value + h, a[1].value + a[2].value)
    //   (Note: if n=2, a[1]+a[2] is not possible, so it's just a[0]+a[1]+h)
    // Maximum f value:
    //   max_f = max(a[0].value + a[n-1].value + h, a[n-2].value + a[n-1].value)
    //   (Note: if n=2, a[n-2]+a[n-1] is not possible, so it's just a[0]+a[1]+h)

    long long min_f_val_case2;
    long long max_f_val_case2;

    if (n == 2) {
        min_f_val_case2 = a[0].value + a[1].value + h;
        max_f_val_case2 = a[0].value + a[1].value + h;
    } else {
        min_f_val_case2 = std::min(a[0].value + a[1].value + h, a[1].value + a[2].value);
        max_f_val_case2 = std::max(a[0].value + a[n-1].value + h, a[n-2].value + a[n-1].value);
    }

    long long goodness2 = max_f_val_case2 - min_f_val_case2;
    std::vector<int> partition2(n);
    partition2[a[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[a[i].original_index] = 2;
    }

    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

