// Using long long for y to prevent overflow
// Using int for x and array indices as n is up to 2e5

// Structure to store the result of a state (x, parity)
// `val` is the total y accumulated from this state until termination
// `next_x` is the x value when it terminates (or goes out of bounds)
// `next_parity` is the parity of the step (0 for add, 1 for sub) that led to termination
struct Result {
    long long val;
    int next_x; // The x value that caused termination (e.g., 0 or n+1)
    int next_parity; // 0 if terminated after add, 1 if terminated after sub
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1); // a[0] is unused, a[1] will be set by loop
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    // dp[x][parity] stores the Result for starting at index x with the given parity
    // parity 0: next operation is x = x + a[x], y = y + a[x]
    // parity 1: next operation is x = x - a[x], y = y + a[x]
    std::vector<std::vector<Result>> dp(n + 1, std::vector<Result>(2));
    std::vector<std::vector<bool>> visited(n + 1, std::vector<bool>(2, false));
    std::vector<std::vector<bool>> in_stack(n + 1, std::vector<bool>(2, false));

    // Function to compute dp[x][parity] using memoization and cycle detection
    auto solve = [&](auto self, int current_x, int current_parity) -> Result {
        if (current_x <= 0 || current_x > n) {
            return {0, current_x, current_parity}; // Base case: already out of bounds
        }

        if (visited[current_x][current_parity]) {
            if (in_stack[current_x][current_parity]) {
                // Cycle detected
                return {-1, 0, 0}; // Indicate infinite loop
            }
            return dp[current_x][current_parity]; // Already computed
        }

        in_stack[current_x][current_parity] = true;

        long long val_a_x = a[current_x];
        int next_x;
        int next_parity;

        if (current_parity == 0) { // x = x + a[x], y = y + a[x]
            next_x = current_x + val_a_x;
            next_parity = 1; // Next step will be subtraction
        } else { // x = x - a[x], y = y + a[x]
            next_x = current_x - val_a_x;
            next_parity = 0; // Next step will be addition
        }

        Result res = self(self, next_x, next_parity);

        in_stack[current_x][current_parity] = false;
        visited[current_x][current_parity] = true;

        if (res.val == -1) {
            dp[current_x][current_parity] = {-1, 0, 0}; // Propagate infinite loop
        } else {
            dp[current_x][current_parity] = {res.val + val_a_x, res.next_x, res.next_parity};
        }
        return dp[current_x][current_parity];
    };

    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a_1 for the current run

        // Initial state: x=1, y=0. First operation is x = x + a[x], y = y + a[x]
        // So we start with current_x = 1, current_parity = 0
        // The first a[1] is added to y, and x becomes 1 + a[1].
