// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case for k=1
    // Try all possible single cuts
    for (int i = 1; i < n; ++i) {
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string new_s = s2 + s1;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case for k=2
    // If all characters are the same, e.g., "aaaa", "qqqq"
    // It's impossible to form a different palindrome.
    // Any rearrangement of pieces will result in the same string.
    // For example, "a|a|a|a" -> "aaaa"
    // "aa|aa" -> "aaaa"
    // "a|aaa" -> "aaaa"
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }

    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work,
    // then k=2 is always possible.
    // The strategy is to cut the string into s[0...i-1], s[i], s[i+1...N-1]
    // where s[i] is the middle character (or one of the two middle characters)
    // and s[0...i-1] is not all the same character.
    // Since s is a palindrome and not all characters are the same,
    // there must be at least one character different from s[0].
    // Consider the first half of the string s[0...N/2 - 1].
    // If this half is not all the same character, then we can make a cut.
    // Example: "nolon" -> "no|l|on". Rearrange to "on|l|no". This is a palindrome and different.
    // Example: "abacaba" -> "aba|c|aba". Rearrange to "aba|c|aba". This is the same.
    // But we can cut "abacaba" into "ab|a|c|a|ba".
    // The problem states "minimum k".
    // If k=1 didn't work, and not all characters are the same, then k=2 is the answer.
    // Why k=2 is always possible if k=1 fails and not all chars are same:
    // If k=1 fails, it means for any split s = s1 s2, s2s1 is either not a palindrome or s2s1 == s.
    // Since s is a palindrome and not all characters are the same,
    // there must be at least one character s[i] such that s[i] != s[0].
    // Consider the string s' = s[0...N/2 - 1].
    // If s' consists of all identical characters, e.g., "aaaaa", then s must be "aaaaa" (if N is odd) or "aaaaaa" (if N is even).
    // But we already handled the "all_same_char" case.
    // So, s' must contain at least two different characters.
    // For example, "abacaba". s' = "aba".
    // We can always cut s into three pieces:
    // s[0...N/2 - 1], s[N/2], s[N/2 + 1 ... N-1] (if N is odd)
    // s[0...N/2 - 1], s[N/2 ... N-1] (if N is even, this is k=1)
    // The key is that if k=1 fails, it means any cyclic shift of s is either s itself or not a palindrome.
    // If s is a palindrome and not all characters are the same, then s must have at least two distinct characters.
    // For example, "abacaba".
    // s[0...N/2-1] is "aba".
    // s[N/2] is 'c'.
    // s[N/2+1...N-1] is "aba".
    // We can cut "abacaba" into "ab|a|c|a|ba".
    // The pieces are "ab", "a", "c", "a", "ba".
    // This is 4 cuts.
    // The problem states "minimum k".
    // If k=1 fails, and not all characters are the same, then k=2 is the answer.
    // Consider "nolon". k=1 fails. Not all chars are same. Output 2.
    // Consider "otto". k=1 works. Output 1.
    // Consider "kinnikkinnik". k=1 works. Output 1.
    // The logic is that if k=1 doesn't work, it means all cyclic shifts are either not palindromes or equal to s.
    // If s is a palindrome and not all characters are the same, then the first half s[0...N/2-1] must contain at least two distinct characters.
    // If s[0...N/2-1] consists of only one distinct character, say 'a', then s would be 'a...a' (e.g., "aaaaa" or "aaaaaa").
    // But we've already handled the "all_same_char" case.
    // So, s[0...N/2-1] must contain at least two distinct characters.
    // This means we can always find a cut point within s[0...N/2-1] such that the resulting pieces can be rearranged to form a new palindrome.
    // For example, if s = "abacaba", s[0...N/2-1] = "aba".
    // We can cut "abacaba" into "a|bacab|a". Rearrange to "a|bacab|a" (same).
    // We can cut "abacaba" into "ab|acab|a". Rearrange to "a|acab|ab". Not a palindrome.
    // The example "nolon" -> 2.
    // "no|l|on" -> "on|l|no". This is 2 cuts.
    // This implies that if k=1 fails, and the string is not all identical characters, then k=2 is always achievable.
    // The reasoning is that if s is a palindrome and not all characters are the same, then the prefix s[0...N/2-1] must contain at least two distinct characters.
    // Let's take s = "abacaba". N=7. N/2=3. s[0...2] = "aba".
    // If we cut s into s[0...i-1], s[i...j-1], s[j...N-1] (k=2).
    // We need to find a way to rearrange these three pieces to form a new palindrome.
    // The simplest way to guarantee a new palindrome is to take a prefix, a middle part, and a suffix,
