#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    std::vector<long long> head_reach_left(n);
    std::vector<long long> head_reach_right(n);
    for (int i = 0; i < n; ++i) {
        head_reach_left[i] = h[i] - T;
        head_reach_right[i] = h[i] + T;
    }

    int p_idx = 0;
    int h_idx = 0;

    while (p_idx < m) {
        // Find the first head that can reach p[p_idx]
        while (h_idx < n && head_reach_right[h_idx] < p[p_idx]) {
            h_idx++;
        }

        if (h_idx == n) { // No head can reach p[p_idx]
            return false;
        }

        // The current head h_idx can reach p[p_idx].
        // Now, we need to cover as many subsequent p_j tracks as possible with this head.
        // The head h_idx can cover tracks in [head_reach_left[h_idx], head_reach_right[h_idx]].
        // However, we are trying to cover p[p_idx] with head h_idx.
        // The actual range covered by head h_idx, starting from p[p_idx], is
        // [p[p_idx], min(head_reach_right[h_idx], p[p_idx] + (T - abs(p[p_idx] - h[h_idx])))]
        // This is equivalent to saying that if head h_idx covers p[p_idx], it can also cover
        // any track x such that abs(x - h[h_idx]) <= T.
        // So, the effective range for this head is [h[h_idx] - T, h[h_idx] + T].
        // We need to find the maximum p_j that can be covered by this head.

        long long current_head_max_reach = head_reach_right[h_idx];

        // If p[p_idx] is to the left of h[h_idx] - T, then this head cannot cover p[p_idx]
        // This case is handled by the outer while loop (h_idx++).
        // If p[p_idx] is within [h[h_idx] - T, h[h_idx] + T], then it can be covered.
        // We advance p_idx as long as p[p_idx] is within the current head's reach.
        while (p_idx < m && p[p_idx] <= current_head_max_reach) {
            p_idx++;
        }
        h_idx++; // Move to the next head for the remaining tracks
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance: 10^10 (max coord) - 1 (min coord) + 10^10 (max coord) - 1 (min coord)
                                    // A safe upper bound is max(p_i) - min(h_i) or max(h_i) - min(p_i), which is around 10^10.
                                    // Or simply max(p_i) - min(p_i) if one head covers all.
                                    // Max value of h_i or p_i is 10^10. So max diff is 10^10.
                                    // If one head needs to cover a range of 10^10, it takes 10^10 time.
                                    // A tighter upper bound could be max(p_m-1, h_n-1) - min(p_0, h_0)
                                    // The maximum possible time is roughly max(p_i) - min(p_i), which is 10^10.
                                    // 2 * 10^10 is a safe upper bound.

    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

