#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (int p = 0; p <= 9; ++p) { // p is the pivot digit
        int last1 = -1;
        int last2 = -1;
        bool possible = true;
        std::string current_result(n, ' ');

        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit < p) {
                // Must be color 1
                if (digit < last1) {
                    possible = false;
                    break;
                }
                current_result[i] = '1';
                last1 = digit;
            } else if (digit > p) {
                // Must be color 2
                if (digit < last2) {
                    possible = false;
                    break;
                }
                current_result[i] = '2';
                last2 = digit;
            } else { // digit == p
                // Can be color 1 or color 2
                // Prefer color 2 if it maintains sorted order for S2
                // This ensures that all 'p's that are colored 1 come before all 'p's that are colored 2
                if (digit >= last2) { // Can place in S2
                    current_result[i] = '2';
                    last2 = digit;
                } else if (digit >= last1) { // Cannot place in S2, try S1
                    current_result[i] = '1';
                    last1 = digit;
                } else { // Cannot place in either
                    possible = false;
                    break;
                }
            }
        }

        if (possible) {
            result = current_result;
            found_solution = true;
            break;
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

