void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    int min_idx = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < a[min_idx]) {
            min_idx = i;
        }
    }

    long long min_val = a[min_idx];
    long long operations = 0;

    for (int i = 0; i < n; ++i) {
