#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem guarantees that a solution always exists.
    // A simple solution is to reverse the permutation.
    // The sums of adjacent elements for p = [p_1, p_2, ..., p_n] are:
    // [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n]
    //
    // For p_rev = [p_n, p_{n-1}, ..., p_1], the sums are:
    // [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1]
    //
    // This is the same multiset of sums, just in reverse order.
    // Therefore, F(p_rev) = F(p).
    //
    // The only case where p_rev might be equal to p is if p is a palindrome.
    // However, the problem statement guarantees that a *different* permutation
    // with the same fingerprint always exists.
    //
    // For n=2, p=[1,2], p_rev=[2,1]. These are different.
    // F([1,2]) = sort([1+2]) = [3]
    // F([2,1]) = sort([2+1]) = [3]
    //
    // For n=6, p=[2,1,6,5,4,3], p_rev=[3,4,5,6,1,2]. These are different.
    //
    // Since we are guaranteed a solution exists and reversing always works
    // for the fingerprint, and it's different unless p is a palindrome,
    // and even if p is a palindrome, the problem guarantees a solution exists,
    // reversing is a valid strategy for competitive programming because it's
    // simple and likely intended. The problem statement implies that for any
    // given p, p_rev will either be different or there's another simple
    // transformation. However, for permutations, palindromes are rare and
    // reversing is the most straightforward transformation that preserves sums.
    //
    // The problem statement "We can prove that for every permutation satisfying the input constraints, a solution exists."
    // implies that reversing is sufficient, or if not, there's another simple construction.
    // For example, if n=3 and p=[1,2,3], p_rev=[3,2,1]. Both are different.
    // F([1,2,3]) = sort([3,5]) = [3,5]
    // F([3,2,1]) = sort([5,3]) = [3,5]
    //
    // It seems reversing the permutation is always a valid answer.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

