#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    int initial_a0 = a[0];
    int max_a0 = initial_a0;

    // Iterate through piles from 1 to n-1
    for (int i = 1; i < n; ++i) {
        // Cost to move one haybale from pile i to pile 0 is i days.
        int cost_per_haybale = i;

        // If we don't have enough days to move even one haybale from this pile, skip.
        if (d < cost_per_haybale) {
            break; 
        }

        // Number of haybales available in pile i
        int haybales_available = a[i];

        // Maximum haybales we can move from pile i given remaining days
        int haybales_can_move = d / cost_per_haybale;

        // Actual haybales to move is the minimum of available and what we can afford
        int haybales_to_move = std::min(haybales_available, haybales_can_move);

        // Add these haybales to pile 0
        max_a0 += haybales_to_move;

        // Deduct the days spent
        d -= haybales_to_move * cost_per_haybale;
    }

    std::cout << max_a0 << std::endl;
}

