void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << "\n";
    } else {
        // For n >= 2, we can construct a number.
        // A simple construction is to use '2' as the first digit
        // and '3' for all subsequent digits.
        // This number will be 233...3 (n-1 times '3').
        //
        // Let's check the conditions for s = 233...3:
        // 1. s > 0: True.
        // 2. s consists of n digits: True, we construct it this way.
        // 3. No digit in s equals 0: True, all digits are 2 or 3.
        // 4. s is not divisible by any of its digits:
        //    The digits are 2 and 3.
        //    Is s divisible by 2?
        //    s ends in 3, which is an odd digit. So s is odd and not divisible by 2.
        //    Is s divisible by 3?
        //    The sum of digits is 2 + (n-1)*3.
        //    If n=2, s=23. Sum=5. Not div by 3.
        //    If n=3, s=233. Sum=8. Not div by 3.
        //    If n=4, s=2333. Sum=11. Not div by 3.
        //    In general, 2 + (n-1)*3 = 2 + 3n - 3 = 3n - 1.
        //    For 3n-1 to be divisible by 3, 3n-1 must be a multiple of 3.
        //    However, 3n is always a multiple of 3. So 3n-1 is never a multiple of 3.
        //    Thus, the sum of digits is never divisible by 3, which means s is never divisible by 3.
        //
        // This construction satisfies all conditions for n >= 2.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << "\n";
    }
}

