#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No change needed for this element
            // Update has_pos_one/has_neg_one for elements to its left
            if (a[i] == 1) has_pos_one = true;
            if (a[i] == -1) has_neg_one = true;
            continue;
        }

        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) { // Cannot increase if no '1' to the left
                possible = false;
                break;
            }
        } else { // a[i] > b[i], need to decrease a[i]
            if (!has_neg_one) { // Cannot decrease if no '-1' to the left
                possible = false;
                break;
            }
        }

        // Update has_pos_one/has_neg_one for elements to its left
        if (a[i] == 1) has_pos_one = true;
        if (a[i] == -1) has_neg_one = true;
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

