    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by three factors:
        // 1. The number of coders available (each team needs at least one coder).
        // 2. The number of mathematicians available (each team needs at least one mathematician).
        // 3. The total number of students available divided by 3 (each team needs 3 students).
        // So, k <= c, k <= m, k <= (c + m + x) / 3.
        // This means k <= min(c, m, (c + m + x) / 3).
        // Let's call this upper bound 'max_possible_teams'.
        long long max_possible_teams = std::min({c, m, (c + m + x) / 3});

        // The answer is simply this maximum possible value.
        // Why?
        // If we form 'k' teams, we use 'k' coders, 'k' mathematicians, and 'k' other students.
        // The 'k' other students can be taken from the remaining (c-k) coders, (m-k) mathematicians,
        // and 'x' students with no specialization.
        // The total number of "other" students available is (c-k) + (m-k) + x.
        // We need to pick 'k' students for the third slot in each team.
        // So, we need (c-k) + (m-k) + x >= k.
        // This simplifies to c + m + x >= 3k, or k <= (c + m + x) / 3.
        // Since we already established k <= min(c, m, (c + m + x) / 3),
        // the condition c + m + x >= 3k is implicitly satisfied if k is chosen as max_possible_teams.
        //
        // For example, if k = min(c, m), then we have enough coders and mathematicians.
        // We need 3*k total students. We have c+m+x students.
        // If k <= (c+m+x)/3, then we have enough total students.
        // The remaining students (c-k) + (m-k) + x are sufficient to fill the third slots.
        //
        // The logic is that if we can form `k` teams, we need `k` coders, `k` mathematicians,
        // and `k` "third" members. The `k` "third" members can be any of the remaining students.
        // The total number of students is `c + m + x`. If we form `k` teams, we use `3k` students.
        // So, `3k <= c + m + x`.
        // Also, we need at least `k` coders and `k` mathematicians. So `k <= c` and `k <= m`.
        // All these conditions are combined into `k <= min(c, m, (c + m + x) / 3)`.
        // The maximum `k` is simply this minimum.

        std::cout << max_possible_teams << "\n";
    }
    return 0;
}

