#include <vector>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the triangle from the apex to the i-th cut (inclusive of the first i pieces)
        // should be i times the area of a single piece.
        // Total area = h/2. Area of one piece = (h/2)/n.
        // Area up to x_i = i * (h/(2n)) = (i*h)/(2n).
        // Also, Area up to x_i = x_i^2 / (2h).
        // So, x_i^2 / (2h) = (i*h) / (2n).
        // x_i^2 = (i*h^2) / n.
        // x_i = sqrt((i*h^2) / n) = h * sqrt(i/n).
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (c == '(') {
            if (open_count < k / 2) {
                result += '(';
                open_count++;
                balance++;
            }
        } else { // c == ')'
            if (close_count < k / 2 && balance > 0) {
                result += ')';
                close_count++;
                balance--;
            }
        }
        if (open_count == k / 2 && close_count == k / 2) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

