#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string ans(n, '0');

    // For m=1, the subarray is just [1].
    // l = r = pos[1]. min=1, max=1, length=1. Always beautiful.
    ans[0] = '1';

    // Initialize current_min_idx and current_max_idx for the subarray containing 1
    // For m=1, the subarray is just p[pos[1]] = 1.
    // So, the current range of indices is [pos[1], pos[1]].
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    // Iterate for m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // The number 'm' is at pos[m].
        // We need to expand the current range [current_min_idx, current_max_idx]
        // to include 'm'.
        // The new range will be [min(current_min_idx, pos[m]), max(current_max_idx, pos[m])].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current range [current_min_idx, current_max_idx]
        // forms a permutation of 1, ..., m.
        // This requires two conditions:
        // 1. The length of the subarray must be exactly m.
        //    (current_max_idx - current_min_idx + 1 == m)
        // 2. The maximum element in this subarray must be m.
        //    (This is implicitly handled because we are expanding the range
        //     to include numbers 1 to m. If the length is m, and it contains
        //     1 to m, then m must be the max.)
        // The minimum element is 1, which is also implicitly handled as we start
        // with 1 and expand.

        if (current_max_idx - current_min_idx + 1 == m) {
            ans[m - 1] = '1';
        }
    }

    std::cout << ans << "\n";
}

