int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y " << std::fixed << std::setprecision(9) << 0.0 << " " << 0.0 << "\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // d^2 - 4d >= 0 is true for d >= 4
            // a^2 - d*a + d = 0
            // a = (d +/- sqrt(d^2 - 4d)) / 2
            double discriminant = d * d - 4.0 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // We need a, b to be non-negative.
            // Since d >= 4, d is positive.
            // sqrt(d^2 - 4d) is real and non-negative.
            // d + sqrt(d^2 - 4d) is positive. So a1 is positive.
            // For b1, d - sqrt(d^2 - 4d) must be non-negative.
            // This is true if d >= sqrt(d^2 - 4d).
            // Squaring both sides (both are non-negative): d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // d >= 0. This condition is given.
            // So both a1 and b1 are non-negative.

            // The problem asks for a and b such that a+b=d and a*b=d.
            // The quadratic formula gives two solutions for 'a'.
            // Let's pick one for 'a' and the other for 'b'.
            // For example, let a = a1 and b = b1.
            // Then a+b = (d + sqrt_discriminant)/2 + (d - sqrt_discriminant)/2 = 2d/2 = d.
            // And a*b = ((d + sqrt_discriminant)/2) * ((d - sqrt_discriminant)/2)
            //         = (d^2 - (sqrt_discriminant)^2) / 4
            //         = (d^2 - (d^2 - 4d)) / 4
            //         = (d^2 - d^2 + 4d) / 4
            //         = 4d / 4 = d.
            // So these values satisfy the conditions.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the maximum possible length of the strictly increasing prefix
    // starting from 0.
    // For a_i to be part of an increasing sequence 0, 1, 2, ..., i,
    // we need a_i >= i.
    int left_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            left_len++;
        } else {
            break;
        }
    }

    // Calculate the maximum possible length of the strictly decreasing suffix
    // ending at 0.
    // For a_i to be part of a decreasing sequence ..., 2, 1, 0,
    // where a_i is at position (n-1-i) from the end,
    // we need a_i >= (n-1-i).
    int right_len = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            right_len++;
        } else {
            break;
        }
    }

    // If the sum of the lengths of the longest possible increasing prefix
    // and the longest possible decreasing suffix is greater than n,
    // it means there's an overlap, and thus a valid peak k exists.
    // Specifically, if left_len + right_len > n, it means there's at least
    // one index i such that it can be part of both the increasing prefix
    // (a_i >= i) and the decreasing suffix (a_i >= n-1-i).
    // This index i can serve as the peak k.
    if (left_len + right_len > n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

