int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());

    int count = 0;
    int j = 0; // Pointer for the elements we are trying to place (the "larger" elements)
    for (int i = 0; i < n; ++i) { // Pointer for the original positions (the "smaller" elements)
        // We want to find an element a[j] such that a[j] > a[i]
        // Since both arrays are sorted, if a[j] > a[i], then a[j+1], a[j+2], ... will also be > a[i] (or equal)
        // To maximize the count, we should use the smallest possible a[j] that is greater than a[i].
        // This means we should advance j until a[j] > a[i].
        // If we find such an a[j], we use it, increment count, and move to the next a[i] and a[j].
        // If we reach the end of the array with j, we can't find any more matches.

        // The loop for j should continue from its last position.
        // If a[j] is not greater than a[i], we need a larger element, so we increment j.
        // We must ensure j stays within bounds.
        while (j < n && a[j] <= a[i]) {
            j++;
        }

        // If we found an a[j] that is greater than a[i]
        if (j < n) {
            count++;
            j++; // Move to the next element in the 'pool' for the next match
        } else {
            // No more elements in the pool are greater than a[i] (or any subsequent a[k] where k > i)
            // So we can stop.
            break;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

