long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, always take 1
                    chanek_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 != 0) { // N/2 is odd
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N/2 is even
                    // If N/2 is even, taking N/2 leads to an even number for opponent.
                    // Opponent can then take half.
                    // Taking 1 leads to an odd number for opponent.
                    // Opponent must take 1.
                    // Compare taking N/2 vs taking 1.
                    // If Chanek takes N/2: Chanek gets N/2. Remaining N/2.
                    // If Chanek takes 1: Chanek gets 1. Remaining N-1.
                    // Since N/2 is even, N must be a multiple of 4.
                    // If N is a multiple of 4, N/2 is even.
                    // Taking N/2 is always better for Chanek if N > 2.
                    // The only exception is N=2, where N/2=1.
                    // For N=4, Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek: 2+1=3.
                    // For N=4, Chanek takes 1. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek: 1+1=2.
                    // So for N=4, taking N/2 is better.
                    // This logic applies generally. If N/2 is even, taking N/2 is the optimal move.
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, always take 1
                    n -= 1;
                } else if ((n / 2) % 2 != 0) { // N/2 is odd
                    n /= 2;
                } else { // N/2 is even
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

