#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareElementA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareElementB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> A(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> A[i].value;
        A[i].original_index = i;
    }

    std::vector<ElementB> B(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> B[i].value;
        B[i].original_index = i;
    }

    std::sort(A.begin(), A.end(), compareElementA);
    std::sort(B.begin(), B.end(), compareElementB);

    std::vector<long long> result(m);
    std::vector<long long> sorted_A_values(m);
    for (int i = 0; i < m; ++i) {
        sorted_A_values[i] = A[i].value;
    }

    std::vector<long long> sorted_B_values(m);
    for (int i = 0; i < m; ++i) {
        sorted_B_values[i] = B[i].value;
    }

    // Use a multiset to keep track of available A values for the current B_i
    // We need to assign A_j to B_i such that A_j is as small as possible
    // but still satisfies A_j >= B_i.
    // The greedy strategy is to sort B in ascending order.
    // For each B_i, we want to pick the smallest available A_j such that A_j >= B_i.
    // This is because F(n, k) = (n+1)/(k+1).
    // To maximize sum( (A_i+1)/(B_i+1) ), we want to pair large (A_i+1) with small (B_i+1).
    // Or, more precisely, we want to pair A_i with B_i such that A_i is as small as possible
    // for a given B_i, to leave larger A values for larger B values.
    // This is a standard greedy approach for maximizing sum(f(x_i, y_i)) where f is increasing in x and decreasing in y.
    // Here, f(A, B) = (A+1)/(B+1). It's increasing in A and decreasing in B.
    // So we sort A ascending and B ascending.
    // We want to pair A_i with B_j such that A_i is as large as possible for a given B_j.
    // This is because we want to maximize (A_i+1)/(B_j+1).
    // If we sort B in ascending order, we should try to assign the largest possible A to the smallest B.
    // This is the opposite of what I initially thought.
    // Let's re-evaluate the greedy strategy.
    // We want to maximize sum (A_i+1)/(B_i+1).
    // Sort A in ascending order: A_1 <= A_2 <= ... <= A_m
    // Sort B in ascending order: B_1 <= B_2 <= ... <= B_m
    //
    // Consider two pairs (A_i, B_j) and (A_k, B_l).
    // If we swap them to (A_i, B_l) and (A_k, B_j), when is it better?
    // Assume A_i < A_k and B_j < B_l.
    // We want to maximize (A_i+1)/(B_j+1) + (A_k+1)/(B_l+1).
    // If we swap, we get (A_i+1)/(B_l+1) + (A_k+1)/(B_j+1).
    //
    // The condition A_i >= B_j must hold for all i, j.
    // This means we can always assign any A to any B.
    //
    // The problem is a rearrangement problem.
    // We have A_1, ..., A_m and B_1, ..., B_m.
    // We want to find a permutation P of {1, ..., m} such that sum_{i=1}^m F(A_{P[i]}, B_i) is maximized.
    //
    // Let's sort A in ascending order: A_1 <= A_2 <= ... <= A_m.
    // Let's sort B in ascending order: B_1 <= B_2 <= ... <= B_m.
    //
    // Consider the values (A_i+1) and (B_i+1).
    // We want to maximize sum (A_i+1)/(B_i+1).
    // This is a known rearrangement inequality type problem.
    // To maximize sum(x_i * y_i), we sort both x and y in the same order.
    // To maximize sum(x_i / y_i), we sort x in ascending and y in descending, or vice versa.
    // Here, we have (A_i+1) and 1/(B_i+1).
    // So we want to sort (A_i+1) in the same order as 1/(B_i+1).
    // Sorting (A_i+1) in ascending order means A_i in ascending order.
    // Sorting 1/(B_i+1) in ascending order means (B_i+1) in descending order, i.e., B_i in descending order.
    //
    // So, the strategy is:
    // 1. Sort A in ascending order.
    // 2. Sort B in descending order.
    // 3. Pair A_i with B_i (after sorting).
    //
    // Let's try this.
    // Sort A ascending.
    // Sort B descending.
    // Assign A[i] to B[i]'s original position.

    std::sort(A.begin(), A.end(), compareElementA); // A is sorted ascending
    std::sort(B.begin(), B.end(), compareElementB); // B is sorted ascending

    // We need to pair A_i (from sorted A) with B_j (from sorted B)
    // such that A_i is assigned to B_j's original position.
    // The greedy strategy for sum(X_i / Y_i) is to sort X ascending and Y descending.
    // So, we take A values in ascending order and B values in descending order.
    // The B values are associated with their original indices.
    //
    // Let's create a temporary structure for B that stores value and original index.
    // We already have ElementB.
    // Sort B by value in ascending order.
    //
    // Now, we want to assign A_i (from sorted A) to B_j (from sorted B).
    // The final output array `result` will be indexed by the original positions of B.
    //
    // We have A_1 <= A_2 <= ... <= A_m
    // We have B_1 <= B_2 <= ... <= B_m (where B_i now refers to the sorted B values)
    //
    // We want to maximize sum (A'_k + 1) / (B_k + 1) where B_k are the original B values.
    // Let's denote the original B values as B_orig[k].
    // We want to find a permutation P such that sum (A_{P[k]} + 1) / (B_orig[k] + 1) is maximized.
    //
    // This means we should pair the largest A values with the smallest B_orig values.
    // And the smallest A values with the largest B_orig values.
    //
    // So, sort A in ascending order.
    // Sort B (with original indices) in descending order of their values.
    // Then assign A[i] to the original index of B[i].

    // A is already sorted ascending.
    // B needs to be sorted descending by value.
    std::sort(B.begin(), B.end(), [](const ElementB& x, const ElementB& y) {
        return x.value > y.value; // Sort B in descending order
    });

    for (int i = 0; i < m; ++i) {
        // A[i] is the i-th smallest value from original A.
        // B[i] is the i-th largest value from original B (with its original index).
        // We assign A[i] to the original position of B[i].
        result[B[i].original_index] = A[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor ^= a;
    }

    // Condition: current_sum = 2 * current_xor
    // If already good, append 0 elements.
    if (current_sum == 2 * current_xor) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
        return;
    }

    // We need to append at most 3 elements.
    // Let's try to append 2 elements.
    // We want (current_sum + b1 + b2) = 2 * (current_xor ^ b1 ^ b2)
    // A common strategy is to make b1 = current_xor.
    // Then the new XOR sum becomes current_xor ^ current_xor = 0.
    // So we want (current_sum + current_xor + b2) = 2 * (0 ^ b2)
    // (current_sum + current_xor + b2) = 2 * b2
    // current_sum + current_xor = b2
    // So, b2 = current_sum + current_xor.

    // Let's try this:
    // Append b1 = current_xor
    // Append b2 = current_sum + current_xor
    // New sum S' = current_sum + current_xor + (current_sum + current_xor) = 2 * (current_sum + current_xor)
    // New XOR X' = current_xor ^ current_xor ^ (current_sum + current_xor) = 0 ^ (current_sum + current_xor) = current_sum + current_xor
    // Check condition: S' = 2 * X'
    // 2 * (current_sum + current_xor) = 2 * (current_sum + current_xor)
    // This always holds!

    // So we can always append 2 elements: current_xor and (current_sum + current_xor).
    // The problem states that appended elements are non-negative.
    // current_xor is always non-negative.
    // current_sum is always non-negative.
    // So (current_sum + current_xor) is always non-negative.
    // The problem states a_i <= 10^9, n <= 10^5.
    // Max current_sum = 10^5 * 10^9 = 10^14.
    // Max current_xor is roughly 2^30 (since a_i <= 10^9).
    // So current_sum + current_xor can be up to 10^14 + 2^30, which fits in long long.
    // The output elements can be up to 10^18, so this is fine.

    std::cout << 2 << std::endl;
    std::cout << current_xor << " " << (current_sum + current_xor) << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

