#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // Rule: if s[i] is '0', then w[i-x] (if exists) and w[i+x] (if exists) must be '0'.
    // We use this to determine which w[j] must be '0'.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Now, verify if the constructed w can produce s.
    // Rule: s[i] is '1' if w[i-x] (if exists) is '1' OR w[i+x] (if exists) is '1'.
    // If s[i] is '1', we must check if at least one of these conditions holds for our w.
    // If s[i] is '0', we already ensured w[i-x] and w[i+x] are '0' (if they exist),
    // so the generated s_prime[i] will be '0'.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            bool possible_one = false;
            if (i - x >= 0 && w[i - x] == '1') {
                possible_one = true;
            }
            if (i + x < n && w[i + x] == '1') {
                possible_one = true;
            }
            if (!possible_one) {
                std::cout << -1 << std::endl;
                return;
            }
        }
    }

    std::cout << w << std::endl;
}

