    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is sum_r_val
    long long sum_r_val;
    if (b == 1) { // If b=1, then b-1=0, sum is 0.
        sum_r_val = 0;
    } else {
        sum_r_val = (b - 1);
        sum_r_val = (sum_r_val * b) / 2;
        sum_r_val %= MOD;
    }

    // Sum of k from 1 to a: a * (a+1) / 2
    // This is sum_k_val
    long long sum_k_val = a;
    sum_k_val = (sum_k_val * (a + 1)) / 2;
    sum_k_val %= MOD;

    // Term 1: sum_{k=1 to a} sum_{r=1 to b-1} (k * b * r)
    // = (sum_{k=1 to a} k) * b * (sum_{r=1 to b-1} r)
    long long term1 = sum_k_val;
    term1 = (term1 * b) % MOD;
    term1 = (term1 * sum_r_val) % MOD;

    // Term 2: sum_{k=1 to a} sum_{r=1 to b-1} r
    // = (sum_{k=1 to a} 1) * (sum_{r=1 to b-1} r)
    // = a * (sum_{r=1 to b-1} r)
    long long term2 = (a * sum_r_val) % MOD;

    long long total_sum = (term1 + term2) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> pos_char(26);
    for (int i = 0; i < L; ++i) {
        pos_char[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int char_code = 0; char_code < 26; ++char_code) {
        const auto& k_candidates = pos_char[char_code];
        if (k_candidates.empty()) {
            continue;
        }

        // If only one k candidate for this t[0], Vasya wins for sure.
        if (k_candidates.size() == 1) {
            total_win_prob += 1.0 / L;
            continue;
        }

        // If multiple k candidates, Vasya needs to choose p.
        // He wants to maximize the probability of winning for this specific t[0].
        double max_win_prob_for_char = 0.0;

        // Iterate over all possible positions p (from 1 to L-1)
        for (int p = 1; p < L; ++p) {
            // For a fixed p, count how many k_candidates lead to a unique (t[0], t[p]) pair.
            int unique_count = 0;

            // Map to store (t[0], t[p]) -> count of k_candidates that produce it
            // t[0] is fixed as s[k_cand] (which is char_code)
            // t[p] is s[(k_cand + p) % L]
            std::vector<int> char_p_counts(26, 0); // Stores counts for s[(k_cand+p)%L]

            for (int k_cand : k_candidates) {
                char_p_counts[s[(k_cand + p) % L] - 'a']++;
            }

            for (int count : char_p_counts) {
                if (count == 1) {
                    unique_count++;
                }
            }

            // Probability of winning for this p, given t[0] is char_code
            double current_p_win_prob = (double)unique_count / k_candidates.size();
            max_win_prob_for_char = std::max(max_win_prob_for_char, current_p_win_prob);
        }

        // Add the contribution of this t[0] to the total probability
        total_win_prob += max_win_prob_for_char * k_candidates.size() / L;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <algorithm>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26);
    bool possible = true;

    for (size_t i = 0; i < s.length() - 1; ++i) {
        char c1 = s[i];
        char c2 = s[i+1];

        adj[c1 - 'a'].insert(c2);
        adj[c2 - 'a'].insert(c1);

        if (adj[c1 - 'a'].size() > 2 || adj[c2 - 'a'].size() > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string layout = "";
    std::vector<bool> visited(26, false);

    for (int i = 0; i < 26; ++i) {
        if (!visited[i] && adj[i].size() <= 1) { // Start of a path or isolated character
            char current_char = (char)('a' + i);

            // Traverse the path
            while (current_char != 0) { // 0 is a sentinel for end of path
                if (visited[current_char - 'a']) {
                    // This should not happen if logic is correct and graph is paths/isolated nodes
                    // but as a safeguard, break if we somehow hit an already visited node in the same path traversal
                    break; 
                }
                visited[current_char - 'a'] = true;
                layout += current_char;

                char next_char = 0;
                for (char neighbor : adj[current_char - 'a']) {
                    if (!visited[neighbor - 'a']) {
                        next_char = neighbor;
                        break;
                    }
                }
                current_char = next_char;
            }
        }
    }

    // Add any remaining unvisited characters (isolated ones)
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            layout += (char)('a' + i);
        }
    }

    if (layout.length() != 26) {
        // This case should ideally not be reached if the graph construction and traversal are correct
        // and all characters are accounted for. It implies an issue like a cycle or disconnected components
        // that weren't handled, but our graph structure (max degree 2) means only paths and isolated nodes.
        // If a cycle existed, no node would have degree 1, so it wouldn't be picked as a start.
        // If a cycle existed, it would be impossible.
        // The problem statement implies that if it's possible, a full 26-char layout must be provided.
        // If we formed a cycle, it would be impossible.
        // The only way layout.length() != 26 is if there's a cycle or some other graph structure
        // that prevents us from forming a single path.
        // However, the logic for `possible` already checks for degree > 2.
        // If a cycle exists, all nodes in the cycle have degree 2.
        // Our current logic starts traversal from nodes with degree <= 1.
        // If all nodes in a component have degree 2, it's a cycle.
        // A cycle cannot be laid out on a single row.
        // So, if we find any unvisited nodes after processing all degree <= 1 nodes,
        // and those unvisited nodes have degree 2, it means they form a cycle.
        // This makes it impossible.

        // Let's re-check for cycles explicitly.
        // If after the first loop, there are still unvisited nodes, and all of them have degree 2,
        // it means they form one or more cycles.
        // A cycle cannot be represented on a linear keyboard.
        // So, if any character remains unvisited AND has degree 2, it's impossible.
        for (int i = 0; i < 26; ++i) {
            if (!visited[i] && adj[i].size() == 2) {
                possible = false;
                break;
            }
        }
        if (!possible) {
            std::cout << "NO\n";
            return;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

