#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 2) {
            a[i] = -1;
        }
    }

    std::vector<int> prefix_sum_left(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum_left[i + 1] = prefix_sum_left[i] + a[n - 1 - i];
    }

    std::vector<int> prefix_sum_right(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum_right[i + 1] = prefix_sum_right[i] + a[n + i];
    }

    std::map<int, int> left_balance_to_k;
    for (int k_l = 0; k_l <= n; ++k_l) {
        int balance = prefix_sum_left[k_l];
        if (left_balance_to_k.find(balance) == left_balance_to_k.end()) {
            left_balance_to_k[balance] = k_l;
        }
    }

    int min_eaten = 2 * n; // Max possible jars to eat

    for (int k_r = 0; k_r <= n; ++k_r) {
        int current_right_balance = prefix_sum_right[k_r];
        int target_left_balance = -current_right_balance;

        if (left_balance_to_k.count(target_left_balance)) {
            int k_l = left_balance_to_k[target_left_balance];
            min_eaten = std::min(min_eaten, k_l + k_r);
        }
    }

    std::cout << min_eaten << std::endl;
}

