    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize two values: 0 and 1023 (all 10 bits set)
    // We track how these two values transform through the operations.
    // Any input x can be thought of as a combination of bits.
    // If we know how 0 transforms (all bits 0) and how 1023 transforms (all bits 1),
    // we can deduce the transformation for any bit position.
    // For a specific bit 'b' (0 to 9):
    // - The b-th bit of 0 is 0.
    // - The b-th bit of 1023 is 1.
    // Let f(x) be the final function.
    // Let f_b(val) be the b-th bit of f(val).
    // We need to find f_b(0) and f_b(1).
    // If f_b(0) = 0 and f_b(1) = 0, then the b-th bit is always 0.
    // If f_b(0) = 1 and f_b(1) = 1, then the b-th bit is always 1.
    // If f_b(0) = 0 and f_b(1) = 1, then the b-th bit is x_b (original bit).
    // If f_b(0) = 1 and f_b(1) = 0, then the b-th bit is 1 - x_b (original bit flipped).

    int current_val_0 = 0;
    int current_val_1023 = 1023; // 2^10 - 1

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_val_0 &= x;
            current_val_1023 &= x;
        } else if (op_char == '|') {
            current_val_0 |= x;
            current_val_1023 |= x;
        } else if (op_char == '^') {
            current_val_0 ^= x;
            current_val_1023 ^= x;
        }
    }

    // Now, current_val_0 holds f(0) and current_val_1023 holds f(1023).
    // We need to reconstruct the minimal set of operations.
    // We can determine the final state of each bit.
    // Let's find the constants for AND, OR, XOR operations.
    // We need to find A, O, X such that:
    // ((input & A) | O) ^ X = f(input) for all input.
    // This is a standard way to represent any bitwise function.

    int final_and_mask = 1023; // Bits that must remain 1 if they were 1
    int final_or_mask = 0;    // Bits that must become 1
    int final_xor_mask = 0;   // Bits that must be flipped

    for (int b = 0; b < 10; ++b) {
        int bit_0_result = (current_val_0 >> b) & 1;
        int bit_1_result = (current_val_1023 >> b) & 1;

        if (bit_0_result == 0 && bit_1_result == 0) {
            // If input bit is 0, output is 0. If input bit is 1, output is 0.
            // This means the bit is always 0.
            // To achieve this:
            // - AND with 0 at this bit position.
            final_and_mask &= ~(1 << b); // Set b-th bit of AND mask to 0
        } else if (bit_0_result == 1 && bit_1_result == 1) {
            // If input bit is 0, output is 1. If input bit is 1, output is 1.
            // This means the bit is always 1.
            // To achieve this:
            // - OR with 1 at this bit position.
            final_or_mask |= (1 << b); // Set b-th bit of OR mask to 1
        } else if (bit_0_result == 0 && bit_1_result == 1) {
            // If input bit is 0, output is 0. If input bit is 1, output is 1.
            // This means the bit is unchanged (x_b).
            // To achieve this:
            // - AND with 1 (default)
            // - OR with 0 (default)
            // - XOR with 0 (default)
            // No change needed for this bit in final_and_mask, final_or_mask, final_xor_mask.
        } else { // bit_0_result == 1 && bit_1_result == 0
            // If input bit is 0, output is 1. If input bit is 1, output is 0.
            // This means the bit is flipped (1 - x_b).
            // To achieve this:
            // - XOR with 1 at this bit position.
            final_xor_mask |= (1 << b); // Set b-th bit of XOR mask to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;

    // The order of operations matters: AND, then OR, then XOR.
    // This sequence ((x & A) | O) ^ X can represent any bitwise function.

    // If final_and_mask is not all 1s (1023), we need an AND operation.
    // The bits that are 0 in final_and_mask will force the corresponding output bits to 0.
    // The bits that are 1 in final_and_mask will pass through the input bits.
    if (final_and_mask != 1023) {
        result_ops.push_back({'&', final_and_mask});
    }

    // If final_or_mask is not all 0s, we need an OR operation.
    // The bits that are 1 in final_or_mask will force the corresponding output bits to 1.
    // The bits that are 0 in final_or_mask will pass through the current bits.
    if (final_or_mask != 0) {
        result_ops.push_back({'|', final_or_mask});
    }

    // If final_xor_mask is not all 0s, we need an XOR operation.
    // The bits that are 1 in final_xor_mask will flip the corresponding output bits.
    // The bits that are 0 in final_xor_mask will pass through the current bits.
    if (final_xor_mask != 0) {
        result_ops.push_back({'^', final_xor_mask});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> left_zero_block_end; // Stores index i such that a[i]=0 and a[i+1]=1
    std::vector<int> right_one_block_start; // Stores index i such that a[i]=1 and a[i-1]=0

    for (int i = 0; i < n - 1; ++i) {
        if (a[i] == 0 && a[i+1] == 1) {
            left_zero_block_end.push_back(i);
        } else if (a[i] == 1 && a[i+1] == 0) {
            right_one_block_start.push_back(i + 1);
        }
    }

    if (left_zero_block_end.empty() && right_one_block_start.empty()) {
        // Sequence is already stable (all 0s or all 1s, or 0...01...1)
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    int max_dist = 0;
    for (size_t i = 0; i < left_zero_block_end.size(); ++i) {
        int l = left_zero_block_end[i];
        int r = right_one_block_start[i]; // Corresponding right_one_block_start

        int dist = r - l - 1; // Length of the 0101... or 1010... alternating block
        max_dist = std::max(max_dist, dist);
    }

    int k = (max_dist + 1) / 2; // Number of steps to stabilize

    std::vector<int> b = a;
    for (size_t i = 0; i < left_zero_block_end.size(); ++i) {
        int l = left_zero_block_end[i];
        int r = right_one_block_start[i];

        // Fill the left part of the alternating block with 0s
        for (int j = l + 1; j <= l + k && j < r; ++j) {
            b[j] = 0;
        }
        // Fill the right part of the alternating block with 1s
        for (int j = r - 1; j >= r - k && j > l; --j) {
            b[j] = 1;
        }
    }

    std::cout << k << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;
        long long N = std::abs(n);
        long long M = std::abs(m);

        if (N > M) {
            std::swap(N, M);
        }

        // N <= M
        // Minimum moves to reach (N, M) is M.
        // This can be achieved by N diagonal moves and M-N axial moves.
        // If k < M, it's impossible.
        if (k < M) {
            std::cout << -1 << "\n";
            continue;
        }

        // After M moves, we can reach (N, M) with N diagonal and M-N axial moves.
        // We have k - M moves remaining.
        // Each remaining move must be paired with a "return" move to cancel out displacement.
        // E.g., (1,0) then (-1,0) or (1,1) then (-1,-1).
        // Each such pair of moves takes 2 steps and changes parity of coordinates by 0.
        // Or, we can make a move that changes parity, and then another move that changes parity back.
        // For example, if we are at (N, M) and have k-M moves left.
        // We can make a move (1,0) to (N+1, M), then (-1,0) to (N, M). This uses 2 moves.
        // Or (1,1) to (N+1, M+1), then (-1,-1) to (N, M). This uses 2 moves.
        // The parity of (N, M) must match the parity of k.
        // (0,0) -> (x,y) in k moves.
        // Parity of x is parity of k_x (number of x-changing moves).
        // Parity of y is parity of k_y (number of y-changing moves).
        // k_x + k_y = k.
        // x = sum(dx_i), y = sum(dy_i).
        // Each move changes x by dx_i and y by dy_i.
        // dx_i is -1, 0, or 1. dy_i is -1, 0, or 1.
        // x_final = sum(dx_i)
        // y_final = sum(dy_i)
        // Parity of x_final is parity of sum(dx_i).
        // Parity of y_final is parity of sum(dy_i).
        // A move (dx, dy) changes (x,y) to (x+dx, y+dy).
        // Parity of (x+dx, y+dy) is (parity(x)+parity(dx), parity(y)+parity(dy)).
        // Parity of (x,y) after k moves: (k_x_odd % 2, k_y_odd % 2) where k_x_odd is number of moves where dx is odd (i.e. dx != 0).
        // This is equivalent to (N % 2, M % 2).
        // The parity of (N+M) must be equal to the parity of k.
        // Each move changes the sum of coordinates (x+y) by dx+dy.
        // dx+dy can be -2, -1, 0, 1, 2.
        // If dx+dy is odd, (x+y) parity flips. If dx+dy is even, (x+y) parity stays same.
        // dx+dy is odd if one of dx, dy is 0 and the other is +/-1 (axial move).
        // dx+dy is even if both dx, dy are +/-1 (diagonal move) or both are 0 (not a move).
        // So, axial moves flip (x+y) parity. Diagonal moves preserve (x+y) parity.
        // Let `a` be number of axial moves. `d` be number of diagonal moves.
        // `a+d = k`.
        // Parity of (N+M) must be equal to parity of `a`.
        // So, (N+M) % 2 == a % 2.
        // (N+M) % 2 == (k-d) % 2.
        // (N+M) % 2 == (k % 2 - d % 2 + 2) % 2.
        // This is equivalent to (N+M) % 2 == k % 2.
        // If (N+M) % 2 != k % 2, it's impossible.

        if ((N + M) % 2 != k % 2) {
            std::cout << -1 << "\n";
            continue;
        }

        // If we reach here, k >= M and (N+M)%2 == k%2.
