                // The actual minimum r for a given l is the minimum of all x'+2k'+1
                // such that x'+1 <= l and x'+2k'+1 is the end of a triple.
                // This is equivalent to:
                // min_r_for_l[l] = min(min_r_for_l[l], x+2k+1) for l in [1, x+1]

                // However, we can optimize this.
                // If we find a triple ending at x+2k, it means any interval [l, r]
                // where l <= x and r >= x+2k is valid.
                // The smallest r for a given l is x+2k.
                // So, for 0-indexed l, min_r_for_l[l] = min(min_r_for_l[l], x+2k).
                // This applies for all l from 0 to x.

                // The problem statement uses 1-based indexing for l, r, x, k.
                // Let's stick to 0-based for s and convert for min_r_for_l.
                // s_x = s_{x+k} = s_{x+2k}
                // 1-based indices: x_1 = x+1, k_1 = k
                // Triple is at positions x_1, x_1+k_1, x_1+2k_1.
                // The condition is l <= x_1 and x_1+2k_1 <= r.
                // So, for any l from 1 to x_1, the minimum r is x_1+2k_1.
                // min_r_for_l[l] = min(min_r_for_l[l], x_1+2k_1)

                // This means min_r_for_l[l] = min(min_r_for_l[l], x+2k+1) for l from 1 to x+1.
                // We can update min_r_for_l[x+1] = min(min_r_for_l[x+1], x+2k+1).
                // The values for l < x+1 will be handled by a suffix minimum pass.

                min_r_for_l[x + 1] = std::min(min_r_for_l[x + 1], x + 2 * k + 1);
            }
        }
    }

    // Propagate minimum r values:
    // If min_r_for_l[l] is updated, then min_r_for_l[l-1] can potentially be smaller.
    // Specifically, min_r_for_l[l-1] = min(min_r_for_l[l-1], min_r_for_l[l]).
    // This ensures that if an interval [l, r] is valid, then [l-1, r] is also valid
    // (if l-1 is within bounds).
    for (int l = n - 1; l >= 1; --l) {
        min_r_for_l[l] = std::min(min_r_for_l[l], min_r_for_l[l + 1]);
    }

    long long count = 0;
    for (int l = 1; l <= n; ++l) {
        if (min_r_for_l[l] <= n) { // If there is at least one valid r for this l
            // All r from min_r_for_l[l] to n are valid for this l.
            // Number of such r's is n - min_r_for_l[l] + 1.
            count += (n - min_r_for_l[l] + 1);
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <vector>

// Function to calculate parity of a string
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    int len_a = a.length();
    int len_b = b.length();

    // Calculate initial parity of a
    int current_parity_a = calculate_parity(a);

    // If |a| < |b|, we must extend 'a' using parity operations
    // until its length is at least |b|.
    // We also need to ensure that the parity of 'a' (after extension)
    // matches the parity of 'b' if 'b' were to be a suffix.
    // The number of '1's in 'a' can be at most len_a.
    // The number of '1's in 'b' can be at most len_b.

    // The maximum number of '1's we can have in 'a' after extensions
    // is its current count + (number of extensions if they all add '1').
    // This is not directly useful.

    // Let's consider the total number of '1's in 'a' after extensions.
    // Each time we append a parity bit, the number of '1's changes.
    // If parity is 0, count of '1's remains same.
    // If parity is 1, count of '1's increases by 1.

    // We need to find if 'b' can be a suffix of 'a' after some operations.
    // This means 'b' must be a suffix of a string 'a_prime'
    // where 'a_prime' is formed by 'a' followed by some parity bits.
    // And 'a_prime' must have length at least |b|.

    // Let's calculate the number of '1's in 'a' and 'b'.
    int ones_in_a = 0;
    for (char c : a) {
        if (c == '1') {
            ones_in_a++;
        }
    }

    int ones_in_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_in_b++;
        }
    }

    // Case 1: |a| == |b|
    // If lengths are equal, we can only remove characters from 'a'
    // to match 'b' if 'b' is a suffix of 'a'.
    // But the problem states we can remove the first character.
    // This implies we can only remove characters from the front.
    // If |a| == |b|, we can't apply operation 1 (append parity)
    // because that would make |a| > |b|.
    // We can't apply operation 2 (remove first char)
    // because that would make |a| < |b|.
    // So if |a| == |b|, 'a' must be exactly 'b'.
    // However, the example 01011 -> 0110 shows that we can remove from front
    // and then append.
    // The operations are:
    // 01011 -> 1011 (remove '0')
    // 1011 -> 011 (remove '1')
    // 011 -> 0110 (append parity(011) = 0)
    // This means we can remove characters first, then append.

    // The core idea is that 'b' must be a suffix of some string `a_prime`
    // where `a_prime` is `a` followed by some parity bits.
    // Let `a_prime = a + p_1 + p_2 + ... + p_k`.
    // The length of `a_prime` must be at least `len_b`.
    // The number of '1's in `a_prime` must have the same parity as `ones_in_b`
    // if `len_a_prime` and `len_b` have the same parity.
    // More precisely, `ones_in_a_prime % 2 == ones_in_b % 2` is not enough.
    // We need `ones_in_a_prime >= ones_in_b` and `(ones_in_a_prime - ones_in_b)` must be even.
    // This is because if `b` is a suffix of `a_prime`, then `a_prime = prefix + b`.
    // `ones_in_a_prime = ones_in_prefix + ones_in_b`.
    // So `ones_in_a_prime - ones_in_b = ones_in_prefix`.
    // The length of `prefix` is `len_a_prime - len_b`.
    // The number of '1's in `prefix` can be any value from 0 to `len_a_prime - len_b`.
    // So we need `ones_in_a_prime >= ones_in_b` and `ones_in_a_prime - ones_in_b <= len_a_prime - len_b`.
    // The second condition is always true if `ones_in_a_prime` is the actual count.

    // Let's simplify.
    // We can always extend 'a' by appending parity bits.
    // The maximum number of '1's we can have in 'a' after extensions is `ones_in_a + (len_b - len_a)` if all appended bits are '1'.
    // The minimum number of '1's we can have in 'a' after extensions is `ones_in_a` if all appended bits are '0'.
    // This is not quite right. The parity bit depends on the current string.

    // Let `current_ones = ones_in_a`.
    // Let `current_len = len_a`.
    // We need to reach a state where `current_len >= len_b` and
    // `current_ones >= ones_in_b` and `(current_ones - ones_in_b)` is even.
    // This is because if `b` is a suffix of `a_prime`, then `a_prime = prefix + b`.
    // `ones_in_a_prime = ones_in_prefix + ones_in_b`.
    // `len_a_prime = len_prefix + len_b`.
    // So `ones_in_prefix = ones_in_a_prime - ones_in_b`.
    // And `len_prefix = len_a_prime - len_b`.
    // The number of ones in `prefix` must be `ones_in_a_prime - ones_in_b`.
    // The length of `prefix` is `len_a_prime - len_b`.
    // The number of ones in `prefix` must be less than or equal to its length.
    // So `ones_in_a_prime - ones_in_b <= len_a_prime - len_b`.
    // Also, `ones_in_a_prime - ones_in_b >= 0`.

    // Let's calculate the maximum possible number of ones in 'a' if we extend it to length `L`.
    // If we extend `a` to length `L`, we add `L - len_a` bits.
    // The maximum number of ones we can have is `ones_in_a + (L - len_a)`.
    // This happens if every appended parity bit is '1'.
    // The minimum number of ones we can have is `ones_in_a`.
    // This happens if every appended parity bit is '0'.
    // Any number of ones between `ones_in_a` and `ones_in_a + (L - len_a)`
    // with the same parity as `ones_in_a` (if `L - len_a` is even)
    // or opposite parity (if `L - len_a` is odd) can be achieved.
    // This is because appending a '0' keeps the parity of ones the same.
    // Appending a '1' flips the parity of ones.
    // We can choose to append '0' or '1' by manipulating the string before appending.
    // But we can only append `parity(current_string)`.

    // The crucial insight:
    // We can always extend `a` to any length `L >= len_a`.
    // When we append `parity(s)`, the number of ones in `s` either stays the same (if parity is 0)
    // or increases by 1 (if parity is 1).
    // So, `ones_count` can only increase or stay the same.
    // `ones_count_new = ones_count_old + parity(s)`.
    // `parity(s)` is `ones_count_old % 2`.
    // So `ones_count_new = ones_count_old + (ones_count_old % 2)`.
    // If `ones_count_old` is even, `ones_count_new = ones_count_old`.
    // If `ones_count_old` is odd, `ones_count_new = ones_count_old + 1`.
    // In both cases, `ones_count_new` is even.
    // This means after the first parity append operation, the number of ones will be even.
    // And all subsequent parity append operations will append '0' (since count of ones is even).
    // So, `a` -> `a + parity(a)` -> `a + parity(a) + 0` -> `a + parity(a) + 0 + 0` ...
    // The number of ones in `a` will become `ones_in_a + (ones_in_a % 2)` and then stay constant.
    // The length will increase by 1 each time.

    // Let `final_ones_in_a_extended = ones_in_a + (ones_in_a % 2)`.
    // This is the number of ones in `a` after at least one parity append operation.
    // The length of `a` will be `len_a + k` after `k` parity append operations.

    // We need to check if `b` can be a suffix of `a_extended`.
    // `a_extended` will have `final_ones_in_a_extended` ones.
    // Its length can be `len_a + k` for any `k >= 0`.
    // If `k=0`, `a_extended = a`.
    // If `k=1`, `a_extended = a + parity(a)`. `ones = ones_in_a + (ones_in_a % 2)`.
    // If `k=2`, `a_extended = a + parity(a) + 0`. `ones = ones_in_a + (ones_in_a % 2)`.
    // And so on.

    // So, we can effectively get a string `a_prime` of any length `L >= len_a`
    // such that:
    // If `L == len_a`, `a_prime = a`, `ones_in_a_prime = ones_in_a`.
    // If `L > len_a`, `a_prime` is `a` followed by `parity(a)` and then `L - len_a - 1` zeros.
    // In this case, `ones_in_a_prime = ones_in_a + (ones_in_a % 2)`.

    // Condition for `b` to be a suffix of `a_prime`:
    // 1. `len_a_prime >= len_b`.
    // 2. `ones_in_a_prime - ones_in_b >= 0`.
    // 3. `ones_in_a_prime - ones_in_b <= len_a_prime - len_b`.

    // Let's check two scenarios for `a_prime`:
    // Scenario 1: No parity operations are performed, or only removal operations.
    // This means `a_prime` is just `a`.
    // In this case, we need `len_a >= len_b`.
    // And `ones_in_a - ones_in_b >= 0`.
    // And `ones_in_a - ones_in_b <= len_a - len_b`.
    // If these conditions hold, then `b` can be a suffix of `a` if `a` is truncated from the front.
    // This is equivalent to `b` being a suffix of `a`.
    // Example: a = "01011", b = "011"
    // len_a = 5, len_b = 3
    // ones_in_a = 4, ones_in_b = 2
    // 4 - 2 = 2. 5 - 3 = 2.
    // 2 <= 2. This is possible.
    // The string "01011" has suffix "011". Yes.

    // Scenario 2: At least one parity operation is performed.
    // After the first parity operation, the number of ones becomes `ones_in_a + (ones_in_a % 2)`.
    // Let `effective_ones_in_a = ones_in_a + (ones_in_a % 2)`.
    // The length of `a` can be extended to any `L >= len_a + 1`.
    // For any such `L`, the number of ones in `a_prime` will be `effective_ones_in_a`.
    // We need to find if there exists an `L >= len_a + 1` such that:
    // 1. `L >= len_b`.
    // 2. `effective_ones_in_a - ones_in_b >= 0`.
    // 3. `effective_ones_in_a - ones_in_b <= L - len_b`.

    // The minimum `L` we need to consider is `max(len_b, len_a + 1)`.
    // Let `min_L = max(len_b, len_a + 1)`.
    // If `effective_ones_in_a - ones_in_b >= 0` AND
    // `effective_ones_in_a - ones_in_b <= min_L - len_b`, then it's possible.
    // The condition `effective_ones_in_a - ones_in_b <= L - len_b` is easier to satisfy with larger `L`.
    // So if it holds for `min_L`, it holds for all `L > min_L`.

    // Combining both scenarios:
    // We need to check if `b` can be a suffix of `a` (after removing prefix)
    // OR if `b` can be a suffix of `a_extended` (after removing prefix),
    // where `a_extended` is `a` followed by `parity(a)` and then some zeros.

    // Let `max_ones_in_a_prefix = ones_in_a + (ones_in_a % 2)`.
    // This is the maximum number of ones we can have in the "prefix part" of `a`
    // that we can use to form `b`.
    // If `ones_in_a` is odd, we can add one '1' to it.
    // If `ones_in_a` is even, we add one '0' to it, so `ones_in_a` remains the same.
    // So, `max_ones_in_a_prefix` is the number of ones in `a` if we append at least one parity bit.
    // If we don't append any parity bit, the number of ones is `ones_in_a`.

    // We need to check if `b` can be formed.
    // The number of ones in `b` is `ones_in_b`.
    // The length of `b` is `len_b`.

    // Consider the total number of '1's we can have in `a` after any number of operations.
    // Let `current_ones = ones_in_a`.
    // If `current_ones % 2 == 1`, we can append '1', making `current_ones + 1` ones.
    // If `current_ones % 2 == 0`, we can append '0', making `current_ones` ones.
    // So, the number of ones in `a` can be `ones_in_a` (if no parity op or only '0's appended)
    // or `ones_in_a + 1` (if `ones_in_a` was odd and we appended '1').
    // After the first append operation, the number of ones becomes even.
    // `ones_in_a_after_first_append = ones_in_a + (ones_in_a % 2)`.
    // All subsequent appends will be '0's, so the number of ones will remain `ones_in_a_after_first_append`.

    // So, the total number of '1's in the "source string" (before removing prefix to get `b`)
    // can be either `ones_in_a` (if no parity operations are used to extend `a` beyond `len_a`)
    // or `ones_in_a + (ones_in_a % 2)` (if at least one parity operation is used).

    // Let `possible_ones_counts` be a set of possible total '1's counts.
    // `possible_ones_counts = {ones_in_a}`.
    // If `len_a < len_b` or `ones_in_a + (ones_in_a % 2)` is different from `ones_in_a`,
    // we can also achieve `ones_in_a + (ones_in_a % 2)` ones.
    // This is the count of ones if we extend `a` by at least one parity bit.
    // Let `max_ones_available = ones_in_a + (ones_in_a % 2)`.

    // We need to check if `b` can be a suffix of `a_prime`.
    // `a_prime` has length `L` and `N` ones.
    // We need `N >= ones_in_b` and `N - ones_in_b <= L - len_b`.

    // Case 1: `a` itself (without any parity appends) can be truncated to `b`.
    // This means `len_a >= len_b`.
    // And `ones_in_a >= ones_in_b`.
    // And `(ones_in_a - ones_in_b)` must be less than or equal to `(len_a - len_b)`.
    // If these conditions are met, then `b` can be formed.
    if (len_a >= len_b) {
        if (ones_in_a >= ones_in_b && (ones_in_a - ones_in_b) <= (len_a - len_b)) {
            std::cout << "YES\n";
            return 0;
        }
    }

    // Case 2: `a` needs to be extended by at least one parity bit.
    // After the first parity bit is appended, the number of ones becomes `ones_in_a + (ones_in_a % 2)`.
    // Let this be `extended_ones_in_a`.
    int extended_ones_in_a = ones_in_a + (ones_in_a % 2);

    // The length of `a` after at least one append operation will be at least `len_a + 1`.
    // We need to find if there's a length `L` such that `L >= len_a + 1` and `L >= len_b`.
    // The minimum such `L` is `std::max(len_a + 1, len_b)`.
    int min_required_len_after_extend = std::max(len_a + 1, len_b);

    // Now check the conditions for this `a_prime` (with `extended_ones_in_a` ones and length `min_required_len_after_extend`):
    // 1. `extended_ones_in_a >= ones_in_b`.
    // 2. `(extended_ones_in_a - ones_in_b)` must be less than or equal to `(min_required_len_after_extend - len_b)`.
    if (extended_ones_in_a >= ones_in_b &&
        (extended_ones_in_a - ones_in_b) <= (min_required_len_after_extend - len_b)) {
        std::cout << "YES\n";
        return 0;
    }

    std::cout << "NO\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

long long solve() {
    int n, m;
    std::cin >> n >> m;
    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }
    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    std::vector<long long> required_p;
    std::set<long long> h_set(h.begin(), h.end());
    for (long long val : p) {
        if (h_set.find(val) == h_set.end()) {
            required_p.push_back(val);
        }
    }

    if (required_p.empty()) {
        return 0;
    }

    // Remove heads that are outside the range of required_p
    // Or rather, heads that are too far left/right to be useful for the current required_p range
    // This optimization is tricky because a head far away might be useful for a large T.
    // Let's keep all heads for now.

    long long low = 0;
    long long high = 2e10 + 7; // Max possible distance for a single head (10^10 - 1 + 10^10 - 1)

    long long ans = high;

    while (low <= high) {
        long long T = low + (high - low) / 2;

        // dp[i] = minimum index of head required to cover required_p[0...i]
        // dp[i] = -1 if not possible
        std::vector<int> dp(required_p.size(), -1);

        // Base case: required_p[0]
        // Find the first head that can cover required_p[0]
        auto it_h = std::upper_bound(h.begin(), h.end(), required_p[0] + T);
        if (it_h != h.begin()) {
            --it_h;
            if (*it_h >= required_p[0] - T) {
                dp[0] = std::distance(h.begin(), it_h);
            }
        }

        for (int i = 1; i < required_p.size(); ++i) {
            // Option 1: Use a new head for required_p[i]
            // Find the first head that can cover required_p[i]
            auto it_h_new = std::upper_bound(h.begin(), h.end(), required_p[i] + T);
            if (it_h_new != h.begin()) {
                --it_h_new;
                if (*it_h_new >= required_p[i] - T) {
                    int head_idx = std::distance(h.begin(), it_h_new);
                    if (dp[i] == -1 || head_idx < dp[i]) {
                        dp[i] = head_idx;
                    }
                }
            }

            // Option 2: Extend coverage from previous required_p[j] using the same head
            // This means required_p[i] must be covered by the head that covered required_p[j]
            // and all tracks required_p[j+1...i-1] must also be covered by that same head.
            // The head used for required_p[j] is h[dp[j]].
            // It must cover the range [required_p[j], required_p[i]].
            // This means h[dp[j]] must be in [required_p[i] - T, required_p[j] + T].
            // And also h[dp[j]] must be >= required_p[j] - T.
            // Combining these, h[dp[j]] must be in [max(required_p[j]-T, required_p[i]-T), required_p[j]+T].
            // This is equivalent to saying that the interval [required_p[j], required_p[i]] must be covered by h[dp[j]] within time T.
            // This means max(required_p[i] - h[dp[j]], h[dp[j]] - required_p[j]) <= T.
            // Or, h[dp[j]] must be in [required_p[i] - T, required_p[j] + T].
            // And also, the head h[dp[j]] must be able to reach required_p[j] (which is already true by definition of dp[j]).
            // So, we need to check if h[dp[j]] can reach required_p[i].
            // And also, the head h[dp[j]] must be able to reach required_p[j] (which is already true by definition of dp[j]).
            // The crucial part is that the head h[dp[j]] must cover the entire segment [required_p[j], required_p[i]].
            // This means h[dp[j]] must be within [required_p[i] - T, required_p[j] + T].
            // And also, h[dp[j]] must be able to cover required_p[j] (which is true by dp[j] definition).
            // So, we need to find the smallest head index `k` such that `h[k]` can cover `required_p[i]`.
            // If `dp[i-1]` is valid, then `h[dp[i-1]]` is the head that covered `required_p[i-1]`.
            // We check if `h[dp[i-1]]` can also cover `required_p[i]`.
            // This means `h[dp[i-1]]` must be in `[required_p[i] - T, required_p[i-1] + T]`.
            // If this condition holds, then `dp[i]` can be `dp[i-1]`.
            if (dp[i-1] != -1) {
                long long current_h_pos = h[dp[i-1]];
                if (current_h_pos >= required_p[i] - T && current_h_pos <= required_p[i-1] + T) {
                    if (dp[i] == -1 || dp[i-1] < dp[i]) {
                        dp[i] = dp[i-1];
                    }
                }
            }
        }

        if (dp.back() != -1) {
            ans = T;
            high = T - 1;
        } else {
            low = T + 1;
        }
    }

    return ans;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::cout << solve() << std::endl;
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
