// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case 1: k = 1 cut
    // Try all possible single cuts
    for (int i = 1; i < n; ++i) {
        std::string s_prime = s.substr(i) + s.substr(0, i);
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case 2: k = 2 cuts
    // If k=1 is not possible, check if k=2 is possible.
    // A common strategy for k=2 is to cut s into A|B|C and rearrange to C|B|A.
    // This requires A to be a palindrome and C to be a palindrome, and B to be a palindrome.
    // Or, more generally, we can cut s into s_prefix | s_middle | s_suffix.
    // If we can find a prefix s[0...i-1] such that s[0...i-1] is a palindrome,
    // and s[i...n-1-i] is a palindrome, and s[n-i...n-1] is a palindrome,
    // and s[0...i-1] == s[n-i...n-1], then we can swap prefix and suffix.
    // This is equivalent to checking if s is of the form P M P where P is a palindrome.
    // If s = P M P, then P M P is a palindrome.
    // If we cut P|M|P, we can rearrange to P|M|P (original) or P|P|M (not necessarily palindrome) or M|P|P etc.
    // The problem states "cut the paper minimum number of times k, so they got k+1 pieces of paper with substrings of the initial string, and then unite those pieces together to get a new string."
    // For k=2, we have 3 pieces: s[0...i-1], s[i...j-1], s[j...n-1].
    // Let's consider the specific strategy of cutting s into s_prefix | s_middle | s_suffix,
    // where s_prefix = s[0...i-1] and s_suffix = s[n-i...n-1].
    // If s_prefix == s_suffix (which is true for any palindrome s),
    // and s_middle = s[i...n-1-i] is also a palindrome,
    // then we can swap s_prefix and s_suffix.
    // The new string would be s_suffix + s_middle + s_prefix.
    // Since s is a palindrome, s_prefix is the reverse of s_suffix.
    // If s_prefix == s_suffix, then s_prefix must be a palindrome.
    // Example: nolon. n=5.
    // i=1: prefix="n", middle="olo", suffix="n".
    // s_prime = "n" + "olo" + "n" = "nolon" (original).
    // But we can swap prefix and suffix if they are distinct.
    // The example "nolon" -> "onlno" uses 2 cuts.
    // This means "no" | "l" | "on" -> "on" | "l" | "no".
    // Here, s_prefix = "no", s_middle = "l", s_suffix = "on".
    // s_prefix is not a palindrome. s_suffix is not a palindrome.
    // But s_prefix is reverse of s_suffix.
    // The new string "onlno" is a palindrome.
    // This is a specific case of k=2: cut s into A|B|C, then form C|B|A.
    // For C|B|A to be a palindrome, it must be that C is reverse of A, and B is a palindrome.
    // Since s is a palindrome, s = A B C.
    // A B C is a palindrome means A is reverse of C, and B is a palindrome.
    // So if we cut s into A|B|C such that A is reverse of C and B is a palindrome,
    // then C B A will be a palindrome.
    // We need C B A != A B C. This means A != C.
    // If A != C, then A cannot be a palindrome.
    // If A is not a palindrome, then A != reverse(A).
    // Since s is a palindrome, A = reverse(C).
    // So we need to find a cut point `i` such that `s.substr(0, i)` is not a palindrome.
    // And `s.substr(i, n - 2*i)` is a palindrome.
    // And `s.substr(0, i)` != `s.substr(n-i, i)`. This is always true if `s.substr(0, i)` is not a palindrome.
    // The condition `s.substr(0, i)` != `s.substr(n-i, i)` is actually `A != C`.
    // Since s is a palindrome, `A = reverse(C)`. So `A != C` implies `A != reverse(A)`, i.e., `A` is not a palindrome.
    // So we are looking for an `i` such that `s.substr(0, i)` is not a palindrome,
    // and `s.substr(i, n - 2*i)` is a palindrome.
    // The length of the middle part `n - 2*i` must be non-negative. So `i <= n/2`.
    // We iterate `i` from `1` to `n/2`.
    // `A = s.substr(0, i)`
    // `B = s.substr(i, n - 2*i)`
    // `C = s.substr(n - i, i)`
    // We know `A = reverse(C)` because `s` is a palindrome.
    // We need `A != C` (i.e., `A` is not a palindrome) and `B` is a palindrome.
    // If these conditions hold, then `CBA` is a palindrome and `CBA != ABC`.
    // This requires 2 cuts.

    // Check for k=2
    // Iterate `i` from 1 up to `n/2`.
    // `i` is the length of the prefix `A`.
    // `A = s.substr(0, i)`
    // `B = s.substr(i, n - 2*i)`
    // `C = s.substr(n - i, i)`
    // We need `A != C` (which means `A` is not a palindrome) AND `B` is a palindrome.
    // If `A` is not a palindrome, then `A != reverse(A)`.
    // Since `s` is a palindrome, `A = reverse(C)`.
    // So `A != C` is equivalent to `A != reverse(A)`, i.e., `A` is not a palindrome.
    // So we need to find `i` such that `s.substr(0, i)` is NOT a palindrome AND `s.substr(i, n - 2*i)` IS a palindrome.
    // The length of `B` is `n - 2*i`. This must be >= 0.
    // If `n - 2*i == 0`, `B` is empty, which is a palindrome.
    // If `n - 2*i == 1`, `B` is a single character, which is a palindrome.
    for (int i = 1; i <= n / 2; ++i) {
        std::string prefix = s.substr(0, i);
        std::string middle = s.substr(i, n - 2 * i);

        if (!is_palindrome(prefix) && is_palindrome(middle)) {
            std::cout << 2 << std::endl;
            return 0;
        }
    }

    // If neither k=1 nor k=2 works, it's impossible.
    // This happens if all prefixes s[0...i-1] are palindromes for i <= n/2,
    // AND for all such i, s[i...n-1-i] is not a palindrome.
    // The condition "all prefixes s[0...i-1] are palindromes for i <= n/2"
    // implies that s must be composed of repeating characters, e.g., "aaaaa", "abaaba".
    // If s consists of all same characters (e.g., "qqqq"), then any prefix is a palindrome.
    // In this case, `s.substr(i, n - 2*i)` will also be all same characters, hence a palindrome.
    // So for "qqqq", `i=1`: prefix="q" (pal), middle="qq" (pal). This would output 2.
    // But "qqqq" is Impossible.
    // The issue is that for "qqqq", `s_prime = C B A` would be "qqqq" itself.
    // We need `s_prime != s`.
    // If `s` consists of all same characters, e.g., "aaaaa", then `A="a"`, `B="aaa"`, `C="a"`.
    // `CBA = "a" + "aaa" + "a" = "aaaaa"`, which is `s`.
    // So the condition `s_prime != s` is crucial.
    // For `CBA != ABC`, we need `A != C`.
    // But `s` is a palindrome, so `A = reverse(C)`.
    // Thus `A != C` is equivalent to `A != reverse(A)`, i.e., `A` is not a palindrome.
    // If `s` consists of all same characters, then any `A` (prefix) is a palindrome.
    // So `A == reverse(A)`, which means `A == C`.
    // In this case, `CBA` will always be equal to `ABC`.
    // So if `s` consists of all same characters, `k=2` (using this strategy) will not work.

    // Let's re-evaluate the "Impossible" case.
    // If all characters in `s` are the same, e.g., "aaaaa".
    // Any substring `s.substr(i, len)` is also "aaaa..." and is a palindrome.
    // For `k=1`, `s' = B+A`. If `s` is "aaaaa", `A="a"`, `B="aaaa"`. `s'="aaaaa"`. Always `s' == s`.
    // For `k=2`, `s' = C+B+A`. If `s` is "aaaaa", `A="a"`, `B="aaa"`, `C="a"`. `s'="aaaaa"`. Always `s' == s`.
    // So if all characters are the same, it's impossible.
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }

    if (all_same) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work, then k=2 must work.
    // Why? Consider the string `s`. Since it's a palindrome and not all characters are the same,
    // there must be at least two distinct characters.
    // Let `s = c_0 c_1 ... c_{n-1}`.
    // Since `s` is a palindrome, `c_i = c_{n-1-i}`.
    // Since not all characters are the same, there exists some `j` such that `c_j != c_0`.
    // Let `j_min` be the smallest index such that `c_{j_min} != c_0`.
    // Then `s[0...j_min-1]` consists only of `c_0`. This prefix is a palindrome.
    // `s[j_min]` is `c_{j_min}`.
    // Consider `i = 1`. `A = s[0]`, `B = s[1...n-2]`, `C = s[n-1]`.
    // `A` is a palindrome. `C` is a palindrome. `A=C`.
    // If `B` is not a palindrome, then `k=2` is possible by cutting `s` into `s[0] | s[1...n-2] | s[n-1]`
    // and rearranging to `s[n-1] | s[1...n-2] | s[0]`.
    // This new string is `s` itself. This is not what we want.
    // The k=2 strategy that works is:
    // Cut `s` into `s[0...i-1] | s[i...n-1-i] | s[n-i...n-1]`.
    // Let `A = s[0...i-1]`, `B = s[i...n-1-i]`, `C = s[n-i...n-1]`.
    // Since `s` is a palindrome, `A = reverse(C)`.
    // We want to form `C B A`. This will be a palindrome.
    // We need `C B A != A B C`. This means `A != C`.
    // `A != C` implies `A != reverse(A)`, i.e., `A` is not a palindrome.
    // So we need to find an `i` such that `s.substr(0, i)` is NOT a palindrome.
    // If such an `i` exists, then we can use `k=2`.
    // The middle part `B = s.substr(i, n - 2*i)` must be a palindrome.
    // If `n - 2*i < 0`, this `i` is invalid. So `i <= n/2`.
    // If `n - 2*i == 0` or `1`, `B` is a palindrome.
    // If `n - 2*i > 1`, `B` must be a palindrome.

    // The problem statement implies that if k=1 doesn't work, and it's not "Impossible", then k=2 must be the answer.
    // The only case where it's "Impossible" is when all characters are the same.
    // If not all characters are the same, then there must be some `i` such that `s[i] != s[0]`.
    // Consider `s = "nolon"`. `n=5`.
    // `k=1` check:
    // `i=1`: `A="n"`, `B="olon"`. `s'="olonn"`. Not pal.
    // `i=2`: `A="no"`, `B="lon"`. `s'="lonno"`. Not pal.
    // `i=3`: `A="nol"`, `B="on"`. `s'="onnol"`. Not pal.
    // `i=4`: `A="nolo"`, `B="n"`. `s'="nnolo"`. Not pal.
    // So `k=1` fails for "nolon".
    // `k=2` check:
    // `i=1`: `prefix="n"`. Is pal. Skip.
    // `i=2`: `prefix="no"`. Not pal. `middle="l"`. Is pal.
    // Conditions met: `prefix` not pal, `middle` is pal. Output 2.
    // This matches the example.

    // The logic seems to be:
    // 1. Check for k=1. If found, print 1 and exit.
    // 2. Check if all characters in `s` are the same. If so, print "Impossible" and exit.
    // 3. Otherwise (k=1 failed, and not all chars same), print 2.
    // This covers all cases. The k=2 check in the code is actually implicitly covered by the fact that if not all chars are same,
    // there must exist some `i` such that `s.substr(0, i)` is not a palindrome.
    // For example, if `s = "abacaba"`. `n=7`.
    // `k=1` check:
    // `i=1`: `A="a"`, `B="bacaba"`. `s'="bacabaa"`. Not pal.
    // `i=2`: `A="ab"`, `B="acaba"`. `s'="acabaab"`. Not pal.
    // ...
    // `k=1` will fail for "abacaba".
    // All chars are not same. So output 2.
    // Let's verify for "abacaba" that k=2 works.
    // `i=1`: `prefix="a"` (pal). Skip.
    // `i=2`: `prefix="ab"` (not pal). `middle="aca"` (pal). Conditions met. Output 2.
    // This seems correct.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    for (int i = 0; i < n; ++i) {
        // Case 1: Substring starts with '1'
        if (s[i] == '1') {
            long long current_val = 0;
            for (int j = i; j < n; ++j) {
                current_val = (current_val << 1) | (s[j] - '0');
                int len = j - i + 1;

                // Optimization: If current_val exceeds a reasonable bound,
                // further extensions will only make it larger, while len increases linearly.
                // Max possible len is n. If current_val > n, it's unlikely to be equal to len.
                // More precisely, if current_val > n + (max_leading_zeros_to_consider),
                // we can break.
                // For s[i] = '1', current_val is at least 2^(len-1).
                // If 2^(len-1) > n, then current_val > n, so current_val > len.
                // log2(2e5) approx 17.6. So if len-1 > 17, i.e., len > 18, then 2^(len-1) > 2e5.
                // So we only need to check up to len approx 18-20.
                if (len > 20 && current_val > len) { // 20 is a safe upper bound for log2(2e5) + small margin
                    break;
                }

                if (current_val == len) {
                    good_substrings_count++;
                }
            }
        }
    }

    // Case 2: Substrings starting with '0'
    // These are handled by iterating through '1's and looking left.
    // For each '1' at index `i`, we consider substrings `s[k...i]` where `s[k]` is '0'.
    // The value `f(s[k...i])` is the same as `f(s[first_one...i])` where `first_one` is the index of the first '1' in `s[k...i]`.
    // Let `first_one_idx` be the index of the first '1' in `s[k...i]`.
    // The length is `i - k + 1`.
    // We need `i - k + 1 = f(s[first_one_idx...i])`.
    // Let `val_from_first_one = f(s[first_one_idx...i])`.
    // We need `i - k + 1 = val_from_first_one`.
    // This means `k = i + 1 - val_from_first_one`.
    // We need to count how many `k` satisfy this, such that `k <= first_one_idx` and `s[k...first_one_idx-1]` are all '0's.
    // This is equivalent to `k` being in the range `[max(0, i + 1 - val_from_first_one), first_one_idx]`.
    // The number of such `k` is `first_one_idx - max(0, i + 1 - val_from_first_one) + 1`.

    // Precompute positions of '1's
    std::vector<int> one_indices;
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            one_indices.push_back(i);
        }
    }

    // Iterate through each '1' as the rightmost '1' in a potential substring
    for (int i = 0; i < one_indices.size(); ++i) {
        int current_one_idx = one_indices[i];
        long long current_val = 0;

        // Iterate left from current_one_idx to find previous '1's
        // or the beginning of the string.
        // This loop calculates f(s[prev_one_idx...current_one_idx])
        // and considers leading zeros.
        for (int j = i; j >= 0; --j) {
            int prev_one_idx = one_indices[j];

            // Calculate value of s[prev_one_idx ... current_one_idx]
            // This part is tricky. We need to calculate the value of the binary string
            // starting from prev_one_idx up to current_one_idx.
            // The maximum length of such a substring is current_one_idx - prev_one_idx + 1.
            // If this length is too large, the value will be too large.
            // Max length is N. Max value is 2^N.
            // We are interested in values up to N.
            // So, if current_one_idx - prev_one_idx + 1 > 60 (approx log2(10^18)),
            // the value will be too large to be equal to N.
            // For N=2e5, log2(2e5) is about 17.6. So we only need to consider
            // substrings of length up to ~20.
            if (current_one_idx - prev_one_idx + 1 > 20) { // Max length to consider for value calculation
                break; // Further left '1's will result in even longer substrings, thus larger values
            }

            current_val = 0; // Recalculate value for s[prev_one_idx ... current_one_idx]
            for (int k = prev_one_idx; k <= current_one_idx; ++k) {
                current_val = (current_val << 1) | (s[k] - '0');
            }

            // Now we have `val_from_first_one = current_val`.
            // We need to find `k_start` such that `s[k_start...current_one_idx]` is good.
            // `len = current_one_idx - k_start + 1`.
            // We need `len = current_val`.
            // So, `current_one_idx - k_start + 1 = current_val`.
            // `k_start = current_one_idx + 1 - current_val`.

            if (current_val <= 0) continue; // Should not happen if prev_one_idx is a '1'

            int k_start_required = current_one_idx + 1 - static_cast<int>(current_val);

            // Check if k_start_required is valid:
            // 1. k_start_required must be <= prev_one_idx (it can have leading zeros)
            // 2. k_start_required must be >= 0 (within string bounds)
            // 3. All characters s[k_start_required ... prev_one_idx-1] must be '0's.
            //    This is implicitly handled by checking k_start_required against the previous '1' index.
            //    The number of leading zeros allowed is `prev_one_idx - k_start_required`.

            if (k_start_required >= 0 && k_start_required <= prev_one_idx) {
                // The number of valid starting positions `k` for this `current_val`
                // is `prev_one_idx - k_start_required + 1`.
                // However, we must ensure that `k` does not go past the previous '1' in `s`.
                // The actual number of leading zeros allowed is `prev_one_idx - k_start_required`.
                // The starting position `k` must be in the range `[max(0, k_start_required), prev_one_idx]`.
                // The number of such `k` is `prev_one_idx - max(0, k_start_required) + 1`.
                // But we also need to consider the '0's before `prev_one_idx`.
                // Let `last_zero_block_start` be the index of the first '0' in the block of '0's
                // immediately preceding `prev_one_idx`. If `prev_one_idx` is 0 or `s[prev_one_idx-1]` is '1',
                // then `last_zero_block_start` is `prev_one_idx`.
                // The actual number of leading zeros we can add is `prev_one_idx - (index of previous '1' + 1)`.
                // Or, if no previous '1', `prev_one_idx - 0`.

                int prev_one_or_start_idx = (j == 0) ? -1 : one_indices[j-1];
                int max_k_start_for_zeros = prev_one_idx; // The leftmost '0' we can include is prev_one_idx itself if it's a '0'
                                                           // No, this is wrong. The substring must start with '0's and end at current_one_idx.
                                                           // The first '1' in the substring is at prev_one_idx.
                                                           // So the starting index `k` must be `k <= prev_one_idx`.
                                                           // And `s[k...prev_one_idx-1]` must all be '0's.
                                                           // This means `k` must be greater than the index of the '1' before `prev_one_idx`.
                                                           // Let `limit_k_left` be `prev_one_or_start_idx + 1`.
                                                           // So `k` must be in `[limit_k_left, prev_one_idx]`.
                                                           // We need `k = k_start_required`.
                                                           // If `k_start_required` is in `[limit_k_left, prev_one_idx]`, then it's a good substring.
                                                           // The number of such `k` is `prev_one_idx - max(limit_k_left, k_start_required) + 1`.
                                                           // This is the number of valid starting positions for a fixed `current_val` and `current_one_idx`.
                                                           // The number of leading zeros is `prev_one_idx - k_start_required`.
                                                           // The maximum number of leading zeros we can have is `prev_one_idx - (prev_one_or_start_idx + 1)`.
                                                           // So, `prev_one_idx - k_start_required` must be `<= prev_one_idx - (prev_one_or_start_idx + 1)`.
                                                           // This simplifies to `k_start_required >= prev_one_or_start_idx + 1`.
                                                           // And `k_start_required >= 0`.
                                                           // So, `k_start_required >= std::max(0, prev_one_or_start_idx + 1)`.

                int min_valid_k_start = (j == 0) ? 0 : one_indices[j-1] + 1;

                if (k_start_required >= min_valid_k_start) {
                    good_substrings_count++;
                }
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long s1 = elements[0].value;
    long long s2 = elements[1].value;
    long long sn_1 = elements[n - 2].value;
    long long sn = elements[n - 1].value;

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // min_f = s1 + s2
    // max_f = sn_1 + sn
    // goodness = (sn_1 + sn) - (s1 + s2)
    long long goodness1 = (sn_1 + sn) - (s1 + s2);
    std::vector<int> partition1(n, 1);

    // Case 2: Partition such that s1 is in one subsequence, and s2, ..., sn are in another.
    // Or s1, ..., sn-1 in one, sn in another.
    // This is equivalent to having one element in one group and n-1 in another.
    // The minimum f value will be s1 + s2 + h (s1 and s2 are separated).
    // The maximum f value will be sn_1 + sn (sn_1 and sn are together).
    // goodness = (sn_1 + sn) - (s1 + s2 + h)
    // This is only valid if s1 and s2 are separated.
    // If s1 is in group 1, and s2...sn are in group 2:
    // min_f = s1 + s2 + h (s1 and s2 are separated)
    // max_f = sn_1 + sn (sn_1 and sn are together)
    // goodness = (sn_1 + sn) - (s1 + s2 + h)
    // This is the same as goodness1 - h.
    // This partition is: elements[0] gets 1, elements[1...n-1] get 2.
    // Or elements[0...n-2] get 1, elements[n-1] gets 2.
    // The minimum f value will be s1 + s2 + h (s1 and s2 are separated).
    // The maximum f value will be max(s1 + sn + h, sn_1 + sn).
    // If s1 is in group 1, and s2...sn are in group 2:
    // min_f = s1 + s2 + h
    // max_f = max(s1 + sn + h, sn_1 + sn)
    // goodness = max(s1 + sn + h, sn_1 + sn) - (s1 + s2 + h)
    // This simplifies to max(sn - s2, sn_1 + sn - s1 - s2 - h).
    // This is the "optimal" partition for large h.
    // The partition is: elements[0] gets 1, elements[1...n-1] get 2.
    // Or elements[0...n-2] get 1, elements[n-1] gets 2.
    // Let's consider the partition where elements[0] is in group 1, and all others are in group 2.
    // min_f = s1 + s2 + h
    // max_f = std::max(s1 + sn + h, sn_1 + sn)
    // goodness = max_f - min_f
    // This is the "one element separated" strategy.
    // The minimum possible value of f is s1 + s2 + h (s1 and s2 are separated).
    // The maximum possible value of f is max(s1 + sn + h, sn_1 + sn).
    // The goodness is max(s1 + sn + h, sn_1 + sn) - (s1 + s2 + h).
    // This is the goodness for the partition where elements[0] is in group 1, and all others are in group 2.
    // Let's call this goodness2.
    long long goodness2 = std::max(s1 + sn + h, sn_1 + sn) - (s1 + s2 + h);
    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[elements[i].original_index] = 2;
    }

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

