    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        std::sort(a.begin(), a.end());

        long long min_val = a[0];
        long long operations = 0;

        for (int i = 1; i < n; ++i) {
            // For each pile a[i] (where i > 0), we can add min_val to it
            // as many times as possible without exceeding k.
            // The number of times is (k - a[i]) / min_val.
            // Note: k - a[i] must be non-negative. Since a[i] <= k initially,
            // and we only add if a[i] + min_val <= k, this is fine.
            // If a[i] is already k, then k - a[i] = 0, so 0 operations.
            // If a[i] + min_val > k, then (k - a[i]) / min_val will be 0.
            operations += (k - a[i]) / min_val;
        }
        std::cout << operations << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    if (n == 2) {
        std::cout << p[1] << " " << p[0] << std::endl;
        return;
    }

    // For n > 2, reversing the permutation always works.
    // The sums of adjacent elements are p_i + p_{i+1}.
    // For the reversed permutation p', p'_i = p_{n-i-1}.
    // The sums are p'_i + p'_{i+1} = p_{n-i-1} + p_{n-(i+1)-1} = p_{n-i-1} + p_{n-i-2}.
    // This is the same set of sums, just in reverse order.
    // For example, if p = [p_1, p_2, p_3, p_4], sums are [p_1+p_2, p_2+p_3, p_3+p_4].
    // Reversed p' = [p_4, p_3, p_2, p_1], sums are [p_4+p_3, p_3+p_2, p_2+p_1].
    // The set of sums is {p_1+p_2, p_2+p_3, p_3+p_4} for both.
    // Since n > 2, a permutation cannot be equal to its reverse unless it's a palindrome.
    // If p is a palindrome, p_i = p_{n-i-1} for all i.
    // For example, [1, 2, 1] is not a permutation.
    // A permutation of distinct integers from 1 to n can only be a palindrome if n=1 (trivial)
    // or if n is odd and the middle element is unique, and pairs are symmetric.
    // E.g., [1, 2, 3, 2, 1] is not a permutation of 1..5.
    // A permutation of distinct integers from 1 to n cannot be a palindrome for n > 1.
    // If p is a palindrome, p_1 = p_n, p_2 = p_{n-1}, etc.
    // But all elements must be distinct. This is only possible if n=1.
    // For n > 1, p_1 and p_n must be distinct. So p cannot be a palindrome.
    // Thus, p is always different from its reverse.

    std::reverse(p.begin(), p.end());
    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

