#include <algorithm>

void solve() {
    int n;
    long long d;
    std::cin >> n >> d;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0];

    for (int i = 1; i < n; ++i) {
        long long pile_idx = i; // 0-indexed pile_idx, corresponds to (i+1)-th pile
        long long haybales_in_pile = a[i];
        long long days_per_haybale = pile_idx; // days to move from pile_idx to pile 0

        if (days_per_haybale == 0) { // Should not happen for i > 0
            continue;
        }

        // Calculate how many haybales can be moved from this pile
        // based on available days.
        // Each haybale costs days_per_haybale days.
        // We have d days remaining.
        long long max_haybales_from_this_pile = d / days_per_haybale;

        // The actual number of haybales we can move is limited by
        // either the haybales available in the pile or the days we have.
        long long haybales_to_move = std::min(haybales_in_pile, max_haybales_from_this_pile);

        current_a1 += haybales_to_move;
        d -= haybales_to_move * days_per_haybale;

        if (d <= 0) {
            break; // No more days left
        }
    }

    std::cout << current_a1 << std::endl;
}

