#include <vector>
#include <numeric>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) {
            counts[s_val]++;
        }
    }

    int current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the total value contributed by this power of two
        // to the current_sum, but only up to 2048.
        // For example, if we have three 512s, we can form one 1024 and one 512 remains.
        // The 1024 contributes to the sum.
        // If we have four 512s, we can form two 1024s, which combine to one 2048.
        // The 2048 contributes to the sum.
        // This is equivalent to just adding the value of each number.
        // The "combining" process is implicitly handled by the sum.
        // If we have 512, 512, 1024, the sum is 2048.
        // We can combine 512, 512 to get 1024. Then we have 1024, 1024.
        // Combine them to get 2048.
        // The total sum of numbers less than or equal to 2048 is what matters.
        // If this sum is >= 2048, we can always form 2048.
        // This is because any power of two can be combined with an equal power of two
        // to form the next higher power of two.
        // If we have a total sum of X, and X >= 2048, we can always combine
        // numbers to reach 2048. For example, if we have 1024, 512, 256, 256.
        // Sum is 2048. Combine 256, 256 to get 512. Now we have 1024, 512, 512.
        // Combine 512, 512 to get 1024. Now we have 1024, 1024.
        // Combine 1024, 1024 to get 2048.
        // The key insight is that the operation preserves the sum of the numbers.
        // If we have two 'x's and replace them with '2x', the sum remains 'x + x = 2x'.
        // So, if the initial sum of all numbers <= 2048 is at least 2048, we can always form 2048.
        // Numbers > 2048 are useless.
        current_sum += val * count;
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

