        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i], Need to decrease a[i]
            if (!has_minus_one) {
                possible = false;
                break;
            }
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
