    std::cin >> l >> r;

    if (r < 4) { // If r is 2 or 3, the only possible divisor (excluding 1) is 2 or 3.
                 // If l=2, r=2, only 2.
                 // If l=2, r=3, 2 appears once (for 2), 3 appears once (for 3). Any is fine.
                 // If l=3, r=3, only 3.
        std::cout << l << std::endl;
    } else {
        // For any range [l, r] where r >= 4, 2 will always be a divisor of at least one number
        // (if l is even) or two numbers (if l is odd and l+1 is even).
        // Specifically, if r >= 4, there are at least two even numbers in [l, r]
        // unless the range is very small, e.g., [4,4] (one even), [4,5] (one even), [5,5] (zero even), [5,6] (one even).
        //
        // Let's count occurrences for 2 and 3.
        // Count for 2: floor(r/2) - floor((l-1)/2)
        // Count for 3: floor(r/3) - floor((l-1)/3)
        //
        // The number 2 is the most frequent divisor for any sufficiently large range.
        // The count of multiples of d in [l, r] is floor(r/d) - floor((l-1)/d).
        // This count is maximized when d is minimized.
        // The smallest possible divisor (excluding 1) is 2.
        //
        // Consider the counts:
        // For d=2, count is approx (r-l+1)/2.
        // For d=3, count is approx (r-l+1)/3.
        // For d=4, count is approx (r-l+1)/4.
        // ...
        //
        // The count for 2 will always be greater than or equal to the count for any other d > 2,
        // unless the range [l, r] is extremely small and specifically excludes many multiples of 2
        // while including many multiples of some other d.
        //
        // Example: [3, 6]
        // Multiples of 2: {4, 6} -> count = 2
        // Multiples of 3: {3, 6} -> count = 2
        // Here, 2 and 3 have the same count. The problem allows printing any.
        //
        // Example: [19, 29]
        // Multiples of 2: {20, 22, 24, 26, 28} -> count = 5
        // Multiples of 3: {21, 24, 27} -> count = 3
        // Multiples of 4: {20, 24, 28} -> count = 3
        // Multiples of 5: {20, 25} -> count = 2
        // ...
        // In this case, 2 is clearly the winner.
        //
        // The only edge cases where 2 might not be the unique maximum are when the range is very small.
        // If r - l + 1 < 2, i.e., r = l.
        // If l = r = 2, answer is 2.
        // If l = r = 3, answer is 3.
        // If l = r = 4, answer is 2. (Divisors of 4 are 2, 4. Count for 2 is 1, count for 4 is 1. Any is fine.)
        //
        // If r - l + 1 = 2, i.e., r = l + 1.
        // If l=2, r=3: 2 appears for 2, 3 appears for 3. Both 2 and 3 have count 1. Any is fine.
        // If l=3, r=4: 2 appears for 4, 3 appears for 3. Both 2 and 3 have count 1. Any is fine.
        // If l=4, r=5: 2 appears for 4. 3 appears for none. 2 is winner.
        //
        // The problem statement guarantees l >= 2.
        //
        // The only scenario where 3 could have a count equal to or greater than 2 is if the range is very small
        // and happens to contain more multiples of 3 than 2, or an equal number.
        //
        // Consider the case where r - l + 1 is small.
        // If r - l + 1 <= 2:
        //   If l = r:
        //     If l is prime (e.g., 2, 3, 5, 7), the answer is l.
        //     If l is composite (e.g., 4, 6), the smallest prime factor is the answer. For 4, it's 2. For 6, it's 2.
        //   If l = r-1:
        //     e.g., [2,3]. 2 appears for 2, 3 appears for 3. Both 1. Output 2 or 3.
        //     e.g., [3,4]. 3 appears for 3, 2 appears for 4. Both 1. Output 2 or 3.
        //     e.g., [4,5]. 2 appears for 4. 3 appears for none. Output 2.
        //
        // The problem asks for *any* integer if there are multiple answers.
        // The integer 2 is the smallest possible divisor (excluding 1).
        // Its frequency is `r/2 - (l-1)/2`.
        // The frequency of any other divisor `d` is `r/d - (l-1)/d`.
        // Since `d >= 2`, `r/d <= r/2` and `(l-1)/d >= (l-1)/2` (for d=2, it's equal).
        // So `r/d - (l-1)/d <= r/2 - (l-1)/2`.
        // This means the count for 2 is always greater than or equal to the count for any other divisor `d`.
        // Therefore, 2 is always a valid answer.
        // The only exception is if 2 is not a divisor of any number in the range, which is impossible since r >= 2.
        //
        // The only case where 2 might not be the answer is if the range is so small that 2 is not present,
        // but the problem states l >= 2, so 2 is always a candidate.
        //
        // The only case where 2 is not the *only* answer is when its count is equal to some other number's count.
        // For example, [3,6]. Count for 2 is 2 (4,6). Count for 3 is 2 (3,6). Both are valid.
        // Outputting 2 is always safe.

        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_R_pos = -1; // Represents the position of the last 'R' or the starting cell 0.
                             // If last_R_pos = -1, it means the frog is at cell 0.
                             // If last_R_pos = k, it means the frog is at cell k (which must have been reached from an 'R' jump or cell 0).

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // If we encounter an 'R' at index i (which corresponds to cell i+1),
                // it means the frog can jump from its current position (last_R_pos)
                // to cell i+1. The distance required for this jump is (i+1) - last_R_pos.
                // We need to find the maximum such distance.
                max_gap = std::max(max_gap, (i + 1) - last_R_pos);
                last_R_pos = i + 1; // Update the last 'R' position to the current cell.
            }
        }

        // After iterating through the string, the frog needs to make one final jump
        // from the last 'R' position (or cell 0 if no 'R's) to cell n+1.
        // The distance for this jump is (n + 1) - last_R_pos.
        max_gap = std::max(max_gap, (n + 1) - last_R_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        if (n == 0) { // Edge case, though constraints say n >= 1
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        int min_suffix_price = a[n - 1]; // Initialize with the last price

        // Iterate from right to left, starting from the second to last element
        // The last element (a[n-1]) can never be a bad price by definition
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_suffix_price) {
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_suffix_price,
                // it means a[i] is a new minimum or equal to the current minimum.
                // Update min_suffix_price to reflect the minimum from this point onwards.
                min_suffix_price = a[i];
            }
        }
        std::cout << bad_prices_count << "\n";
    }
    return 0;
}

#include <iostream>
