#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);

    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) {
                max_val_in_row = std::max(max_val_in_row, a[i][j]);
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any p[i] is 0. If so, it means all a[i][j] for j!=i were 0.
    // This implies p[i] must be 1 (the smallest possible value in a permutation).
    // This case happens if n=2 and p={1,2} or p={2,1}.
    // If p[i] is 0, it means max_val_in_row was 0.
    // This can only happen if all a[i][j] for j!=i are 0.
    // In a permutation of 1 to n, the smallest value is 1.
    // So if max_val_in_row is 0, p[i] must be 1.
    // This logic is only needed if n=2 and the permutation is {1,2} or {2,1}.
    // For example, if p={1,2}, a[0][1]=min(p[0],p[1])=min(1,2)=1.
    // max_val_in_row for i=0 would be 1. So p[0]=1.
    // max_val_in_row for i=1 would be 1. So p[1]=1.
    // This would give p={1,1}, which is not a permutation.
    // The problem states "permutation of integers from 1 to n".
    // The values a_i,j are min(p_i, p_j).
    // If p_i is the maximum value (n), then for all j!=i, a_i,j = min(n, p_j) = p_j.
    // So max_{j!=i} a_i,j = max_{j!=i} p_j = n-1.
    // If p_i is the minimum value (1), then for all j!=i, a_i,j = min(1, p_j) = 1.
    // So max_{j!=i} a_i,j = 1.
    // This means if p_i = 1, then max_val_in_row for i is 1.
    // So the logic `p[i] = max_val_in_row` correctly assigns 1 to p[i] if p[i] is 1.
    // The only case where max_val_in_row could be 0 is if all p_j for j!=i are 0, which is impossible.
    // So max_val_in_row will always be at least 1.
    // The only special case is when n=2 and p={1,2}.
    // a = [[0,1],[1,0]].
    // For i=0, max_val_in_row = a[0][1] = 1. So p[0]=1.
    // For i=1, max_val_in_row = a[1][0] = 1. So p[1]=1.
    // This results in {1,1}, which is not a permutation.
    // The problem states "permutation of integers from 1 to n".
    // The values in p must be distinct and from 1 to n.
    // If all p[i] calculated this way are distinct and cover 1 to n, then it's a solution.
    // If there's a duplicate, it means one of the values must be n.
    // The value n is unique. It will appear in a_i,j only if p_i=n and p_j=n, which is impossible.
    // Or if p_i=n and p_j < n, then a_i,j = p_j.
    // Or if p_i < n and p_j=n, then a_i,j = p_i.
    // The maximum value in the entire matrix `a` (excluding diagonals) is `n-1`.
    // This is because `min(p_i, p_j)` can be at most `n-1` (if one is `n` and the other is `n-1`).
    // The value `n` itself never appears in `a_i,j` unless `n=1` (not allowed).
    // So, if `n` is not present in `p` after the initial calculation, it must be that one of the `p[i]` values should be `n`.
    // Which one? The one that was `n-1` and is now duplicated.
    // Example: n=2, p={1,2}.
    // a = [[0,1],[1,0]].
    // p[0] = max(a[0][1]) = 1.
    // p[1] = max(a[1][0]) = 1.
    // Result: {1,1}. This is not a permutation.
    // The missing value is 2. One of the 1s must be 2.
    // The logic is: if all `p[i]` are `max_val_in_row`, then the set of `p[i]` will contain `n-1` as its maximum.
    // The value `n` is missing.
    // One of the `p[i]` values must be `n`.
    // Which one? The one that corresponds to the `p_k` such that `p_k = n`.
    // For this `p_k`, `max_{j!=k} a_k,j = max_{j!=k} min(n, p_j) = max_{j!=k} p_j = n-1`.
    // So, the `p[k]` that should be `n` will be calculated as `n-1` by the `max_val_in_row` logic.
    // This means there will be exactly one `n-1` that should be `n`.
    // All other `p[i]` values will be correctly calculated.
    // So, we find the maximum value in the calculated `p`. If it's `n-1`, then one of the `n-1`s should be `n`.
    // We can just change one of the `n-1`s to `n`.
    // Since the problem guarantees a solution, there will be exactly one `n-1` that needs to be `n`.
    // Or, more simply, if `n` is not present in the calculated `p`, then one of the `p[i]` must be `n`.
    // The `p[i]` that should be `n` would have `max_{j!=i} a[i][j] = n-1`.
    // So, we find the maximum value in the `p` array. If it's `n-1`, then we increment one of the `n-1`s to `n`.
    // This is because the true `n` in the permutation `P` would have `max_{j!=k} min(P_k, P_j) = max_{j!=k} P_j = n-1`.
    // So, the `P_k` that is `n` would be calculated as `n-1` by our current logic.
    // All other `P_i` (where `P_i < n`) would be correctly calculated as `P_i`.
    // Thus, the calculated `p` array will contain all values from `1` to `n-1`, with `n-1` appearing twice, and `n` missing.
    // We need to change one of the `n-1`s to `n`.

    bool n_found = false;
    for (int val : p) {
        if (val == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // If n is not found, it means the element that should be n was calculated as n-1.
        // We need to find one such element and change it to n.
        // Since the problem guarantees a solution, there will be exactly one such element.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

