    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;
        while (low <= high) {
            long long mid = low + (high - low) / 2;
            // To form 'mid' teams, we need 'mid' coders and 'mid' mathematicians as minimum.
            // The remaining students are:
            // c_rem = c - mid
            // m_rem = m - mid
            // x_rem = x
            // Total remaining students: c_rem + m_rem + x_rem
            // These remaining students must fill the 'mid' third slots in the teams.
            // So, c_rem + m_rem + x_rem >= mid
            if (c - mid >= 0 && m - mid >= 0 && (c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

