int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long k = n / m; // Number of multiples of m up to n

        if (k == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // The last digits of m*1, m*2, ..., m*10 form a cycle.
        // Calculate the sum of these 10 last digits.
        long long cycle_sum = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_sum += (m * i) % 10;
        }

        // Number of full cycles
        long long num_full_cycles = k / 10;

        // Sum from full cycles
        long long total_sum = num_full_cycles * cycle_sum;

        // Remaining multiples (k % 10)
        long long remaining_multiples = k % 10;
        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (m * i) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // Update the range [current_min_idx, current_max_idx] to include pos[m]
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current range [current_min_idx, current_max_idx]
        // forms a permutation of 1, ..., m.
        // This requires two conditions:
        // 1. The length of the range must be exactly m.
        // 2. The minimum element in p[current_min_idx ... current_max_idx] must be 1.
        // 3. The maximum element in p[current_min_idx ... current_max_idx] must be m.
        //
        // Condition 2 and 3 are implicitly handled by how current_min_idx and current_max_idx
        // are updated. We always expand the range to include the current 'm'.
        // Since we are processing m from 1 to n, the minimum element in the range
        // [current_min_idx, current_max_idx] will always be 1 (because pos[1] is included)
        // and the maximum element will always be m (because pos[m] is included and
        // all numbers from 1 to m are considered).
        //
        // So, we only need to check if the length of the segment is m.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

