int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0) {
            std::cout << "Y " << std::fixed << std::setprecision(9) << 0.0 << " " << 0.0 << "\n";
        } else if (d < 4) {
            std::cout << "N\n";
        } else {
            // d^2 - 4d >= 0 is true for d >= 4
            // a^2 - d*a + d = 0
            // a = (d +/- sqrt(d^2 - 4d)) / 2
            double discriminant = d * d - 4 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // Ensure a and b are non-negative.
            // Since d >= 4, d is positive.
            // sqrt(d^2 - 4d) is real and non-negative.
            // d + sqrt(d^2 - 4d) is clearly positive.
            // d - sqrt(d^2 - 4d):
            // We need d >= sqrt(d^2 - 4d) for b1 to be non-negative.
            // Squaring both sides (both are non-negative):
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // This is true since d >= 4.
            // So both a1 and b1 are non-negative.

            // The problem asks for a and b such that a+b=d and a*b=d.
            // The order doesn't matter, so we can print them in any order.
            // It's common to print the larger one first, or just a and then b.
            // Let's print a1 and b1.
            std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the maximum possible length of the strictly increasing prefix
    // ending at index i, if we were to make a[0] = 0, a[1] = 1, ...
    // This means a[i] must be at least i.
    // We can achieve a[i] = i if original a[i] >= i.
    // The actual value of a[i] can be decreased.
    // So, we need to find the largest 'i' such that a[j] >= j for all j from 0 to i.
    int left_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            left_len = i + 1;
        } else {
            break;
        }
    }

    // Calculate the maximum possible length of the strictly decreasing suffix
    // starting at index i, if we were to make a[n-1] = 0, a[n-2] = 1, ...
    // This means a[i] must be at least (n-1-i).
    // We can achieve a[i] = (n-1-i) if original a[i] >= (n-1-i).
    // So, we need to find the smallest 'i' such that a[j] >= (n-1-j) for all j from i to n-1.
    int right_len = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            right_len = n - i;
        } else {
            break;
        }
    }

    // If there is any overlap between the potential increasing prefix and decreasing suffix,
    // it means there's at least one 'k' (peak) that can satisfy both conditions.
    // The peak 'k' (0-indexed) must be such that:
    // 1. It's part of the increasing prefix: k < left_len
    // 2. It's part of the decreasing suffix: k >= n - right_len
    // So, we need left_len > (n - 1 - right_len)
    // Or, more simply, if left_len + right_len > n, there is an overlap.
    // Example: n=5. left_len=3 means a[0],a[1],a[2] can be part of prefix.
    // right_len=3 means a[2],a[3],a[4] can be part of suffix.
    // left_len=3 means indices 0, 1, 2 are covered.
    // right_len=3 means indices 2, 3, 4 are covered.
    // Overlap at index 2.
    // The condition for overlap is left_len + right_len > n.
    if (left_len + right_len > n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

