    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int mid_idx = n / 2;

    // First, make the median element equal to s
    operations += std::abs(a[mid_idx] - s);
    a[mid_idx] = s; // Conceptually change it for subsequent checks

    // Elements to the left of median must be <= s
    for (int i = 0; i < mid_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
            // a[i] = s; // No need to actually change, just calculate cost
        }
    }

    // Elements to the right of median must be >= s
    for (int i = mid_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
            // a[i] = s; // No need to actually change, just calculate cost
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

