    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int b_ptr = 0; // Pointer for the elements we are trying to place (the 'b' array elements)
    for (int i = 0; i < n; ++i) { // Pointer for the original 'a' array elements
        // We are trying to find an element a[b_ptr] such that a[b_ptr] > a[i]
        // To maximize matches, we should use the smallest possible a[b_ptr] that satisfies the condition.
        // Since both arrays are sorted, we can use two pointers.
        // If a[b_ptr] is not greater than a[i], we need a larger element for a[b_ptr], so increment b_ptr.
        // If a[b_ptr] is greater than a[i], we found a match. Increment count, and move both pointers.
        // We move b_ptr because a[b_ptr] has been "used".
        // We move i because a[i] has been "matched" (or we couldn't find a match for it and moved on).
        while (b_ptr < n && a[b_ptr] <= a[i]) {
            b_ptr++;
        }
        if (b_ptr < n) { // If we found an element a[b_ptr] > a[i]
            count++;
            b_ptr++; // This element a[b_ptr] is now "used"
        }
    }
    std::cout << count << std::endl;
    return 0;
}

