// Function to determine if a box can be the special box
// Parameters:
//   a, b, c, d: initial counts of toys in boxes 1, 2, 3, 4
//   target_box: the box we are checking if it can be the special box (1, 2, 3, or 4)
//   initial_sign: the desired sign of the final toy (1 for positive, -1 for negative)
//   initial_mag_gt1: the desired magnitude property of the final toy (true for |x| > 1, false for |x| < 1)
//   initial_mag_eq1: the desired magnitude property of the final toy (true for |x| = 1)
bool check(long long a, long long b, long long c, long long d, int target_box, int initial_sign, bool initial_mag_gt1, bool initial_mag_eq1) {
    long long total_toys = a + b + c + d;
    if (total_toys == 0) return false; // Should not happen based on constraints A+B+C+D > 0

    // If only one toy initially, it is the super toy.
    // Check if its properties match the target box.
    if (total_toys == 1) {
        if (a == 1) return target_box == 1;
        if (b == 1) return target_box == 2;
        if (c == 1) return target_box == 3;
        if (d == 1) return target_box == 4;
    }

    // The final toy's sign is determined by the parity of negative numbers multiplied.
    // The number of negative toys is A + B.
    // If A+B is even, final sign is positive.
    // If A+B is odd, final sign is negative.
    int final_sign_parity = (a + b) % 2; // 0 for positive, 1 for negative

    // We need to achieve initial_sign.
    // If initial_sign is 1 (positive), we need final_sign_parity == 0.
    // If initial_sign is -1 (negative), we need final_sign_parity == 1.
    if ((initial_sign == 1 && final_sign_parity == 1) || (initial_sign == -1 && final_sign_parity == 0)) {
        // The desired sign cannot be achieved with the current number of negative toys.
        // However, we can change the sign by introducing a toy with value 0.
        // If there is a toy with value 0, the final product is 0.
        // A toy with value 0 is not in any of the boxes.
        // The problem states "fun values in range of $(-\infty,-1]$", etc.
        // This implies no toy has value 0.
        // So, the sign is fixed by the parity of negative toys.
        return false;
    }

    // Now consider magnitude.
    // We need to determine if it's possible to achieve the desired magnitude property.
    // The key insight is that we can always manipulate the magnitude relative to 1
    // if we have enough toys that can push the magnitude in either direction.

    // Toys in Box 1 and Box 4 have magnitude >= 1.
    // Toys in Box 2 and Box 3 have magnitude < 1.

    // Let's count toys with magnitude >= 1 (strong toys) and magnitude < 1 (weak toys).
    long long strong_toys = a + d;
    long long weak_toys = b + c;

    // Case 1: We want the final toy to have magnitude > 1 (initial_mag_gt1 = true)
    if (initial_mag_gt1) {
        // To get |x| > 1, we need at least one strong toy that is not "cancelled out" by weak toys.
        // If we have at least one strong toy (A+D > 0), we can always achieve |x| > 1.
        // Example: Pick a strong toy $S_1$ and a weak toy $W_1$.
        // If $|S_1 \cdot W_1| > 1$, we are good.
        // If $|S_1 \cdot W_1| < 1$, we can pick another strong toy $S_2$ and multiply it with $S_1 \cdot W_1$.
        // We can always pick a strong toy with a very large magnitude (e.g., 1000) and a weak toy with a very small magnitude (e.g., 0.001).
        // If we have at least one strong toy, we can always make the final product have magnitude > 1.
        // The only exception is if all strong toys are multiplied by weak toys such that the final product is < 1.
        // But we can control the order. We can multiply all weak toys together first.
        // The product of all weak toys will be < 1.
        // Then multiply all strong toys together. The product of all strong toys will be >= 1.
        // If there's at least one strong toy, this product will be >= 1.
        // If there are multiple strong toys, it can be > 1.
        // If there's only one strong toy, its product with other strong toys is itself.
        // If we have strong_toys > 0, we can always make the final product > 1.
        // We can pick a very large number for one of the strong toys, and very small numbers for weak toys.
        // For example, if we have $S_1, S_2, W_1, W_2$. We want $|X| > 1$.
        // We can set $S_1 = 1000, S_2 = 2, W_1 = 0.0001, W_2 = 0.0001$.
        // $(S_1 \cdot S_2) \cdot (W_1 \cdot W_2) = (2000) \cdot (0.00000001) = 0.00002 < 1$. This is not what we want.
        // The key is that we can choose the *values* of the toys.
        // If we want |X| > 1, we can pick one toy from Box 1 or Box 4 to be very large (e.g., 10^9).
        // All other toys can be chosen to have magnitude close to 1 (e.g., 0.99 or 1.01).
        // The product of (total_toys - 1) toys, each with magnitude close to 1, will still be close to 1.
        // Then multiply by the very large toy. The result will be very large.
        // So, if strong_toys > 0, we can always achieve |X| > 1.
        return strong_toys > 0;
    }
    // Case 2: We want the final toy to have magnitude < 1 (initial_mag_gt1 = false, initial_mag_eq1 = false)
    else if (!initial_mag_eq1) {
        // To get |x| < 1, we need at least one weak toy that is not "cancelled out" by strong toys.
        // If we have at least one weak toy (B+C > 0), we can always achieve |x| < 1.
        // Similar logic: pick one toy from Box 2 or Box 3 to be very small (e.g., 10^-9).
        // All other toys can be chosen to have magnitude close to 1.
        // The product will be very small.
        // So, if weak_toys > 0, we can always achieve |X| < 1.
        return weak_toys > 0;
    }
    // Case 3: We want the final toy to have magnitude = 1 (initial_mag_eq1 = true)
    else { // initial_mag_eq1 == true
        // To get |x| = 1, we need to be able to choose values such that the product is exactly 1.
        // This is possible if and only if we have at least one strong toy AND at least one weak toy.
        // If strong_toys == 0, all toys have magnitude < 1, so product < 1.
        // If weak_toys == 0, all toys have magnitude >= 1, so product >= 1.
        // If strong_toys > 0 and weak_toys > 0:
        // We can pick one strong toy $S_1$ and one weak toy $W_1$.
        // We can choose their values such that $|S_1 \cdot W_1| = 1$.
        // For example, $S_1 = 2$, $W_1 = 0.5$.
        // All other toys can be chosen to have magnitude 1 (e.g., 1 or -1).
        // Toys with value 1 or -1 are in Box 1 or Box 4.
        // If we have $A+D > 0$ and $B+C > 0$, we can achieve magnitude 1.
        // Example: $A=1, B=1$. Choose $x_A = -2, x_B = -0.5$. Product is 1.
        // Example: $A=1, C=1$. Choose $x_A = -2, x_C = 0.5$. Product is -1.
        // Example: $D=1, B=1$. Choose $x_D = 2, x_B = -0.5$. Product is -1.
        // Example: $D=1, C=1$. Choose $x_D = 2, x_C = 0.5$. Product is 1.
        // So, if strong_toys > 0 and weak_toys > 0, we can achieve |X| = 1.
        return strong_toys > 0 && weak_toys > 0;
    }
}

void solve() {
    long long a, b, c, d;
    std::cin >> a >> b >> c >> d;

    std::string ans[4];

    // Box 1: (-inf, -1] -> sign = -1, mag > 1 or mag = 1
    ans[0] = (check(a, b, c, d, 1, -1, true, false) || check(a, b, c, d, 1, -1, false, true)) ? "Ya" : "Tidak";

    // Box 2: (-1, 0) -> sign = -1, mag < 1
    ans[1] = check(a, b, c, d, 2, -1, false, false) ? "Ya" : "Tidak";

    // Box 3: (0, 1) -> sign = 1, mag < 1
    ans[2] = check(a, b, c, d, 3, 1, false, false) ? "Ya" : "Tidak";

    // Box 4: [1, inf) -> sign = 1, mag > 1 or mag = 1
    ans[3] = (check(a, b, c, d, 4, 1, true, false) || check(a, b, c, d, 4, 1, false, true)) ? "Ya" : "Tidak";

    std::cout << ans[0] << " " << ans[1] << " " << ans[2] << " " << ans[3] << std::endl;
}

