#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i - 1], a[i]);
    }

    std::vector<int> suffix_max(n);
    suffix_max[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i + 1], a[i]);
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int distinct_count_prefix = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] > i + 1 || seen_prefix[a[i]]) {
            break;
        }
        if (!seen_prefix[a[i]]) {
            seen_prefix[a[i]] = true;
            distinct_count_prefix++;
        }
        if (distinct_count_prefix == i + 1 && prefix_max[i] == i + 1) {
            is_prefix_perm[i + 1] = true;
        }
    }

    std::vector<bool> is_suffix_perm(n + 1, false);
    std::vector<bool> seen_suffix(n + 1, false);
    int distinct_count_suffix = 0;
    for (int i = n - 1; i >= 0; --i) {
        int current_len = n - i;
        if (a[i] > current_len || seen_suffix[a[i]]) {
            break;
        }
        if (!seen_suffix[a[i]]) {
            seen_suffix[a[i]] = true;
            distinct_count_suffix++;
        }
        if (distinct_count_suffix == current_len && suffix_max[i] == current_len) {
            is_suffix_perm[current_len] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n == 1) {
                chanek_coins += 1;
                n = 0;
            } else if (n % 2 == 1) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                // Option 1: Take 1 coin
                // Remaining N-1 (odd). Opponent takes 1. N-2 (even).
                // Chanek takes N/2.
                // This path is generally worse if N/2 is a good move.

                // Option 2: Take N/2 coins
                // Remaining N/2.
                // If N/2 is odd, opponent takes 1. N/2-1 (even).
                // If N/2 is even, opponent takes N/4. N/4 (even).

                // Strategy: If N is even, and N is not a power of 2,
                // Chanek should take N/2. This leaves N/2 for opponent.
                // If N is a power of 2 (e.g., 2, 4, 8, 16, ...),
                // taking N/2 leaves N/2, which is also a power of 2.
                // This means the opponent can also take N/4, and so on.
                // This leads to a 50/50 split if only N/2 moves are made.
                // In this case, taking 1 coin might be better.

                // Let's check if N is a power of 2.
                // A number is a power of 2 if (n > 0) and (n & (n - 1)) == 0.
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    // If Chanek takes N/2, opponent takes N/4, etc.
                    // Chanek gets N/2 + N/8 + N/32 + ...
                    // Opponent gets N/4 + N/16 + N/64 + ...
                    // Total Chanek: N/2 * (1 + 1/4 + 1/16 + ...) = N/2 * (1 / (1 - 1/4)) = N/2 * (4/3) = 2N/3 (approx)
                    // Total Opponent: N/4 * (1 + 1/4 + 1/16 + ...) = N/4 * (4/3) = N/3 (approx)
                    // This is not quite right because the game ends.
                    // If N is a power of 2, say 2^k.
                    // Chanek takes 2^(k-1). N becomes 2^(k-1).
                    // Opponent takes 2^(k-2). N becomes 2^(k-2).
                    // ...
                    // Chanek takes 2^1. N becomes 2^1.
                    // Opponent takes 2^0. N becomes 2^0.
                    // Chanek takes 1. N becomes 0.
                    // Chanek gets 2^(k-1) + 2^(k-3) + ... + 2^1.
                    // Opponent gets 2^(k-2) + 2^(k-4) + ... + 2^0.
                    // This is a geometric series.
                    // If Chanek takes 1: N becomes N-1 (odd).
                    // Opponent takes 1. N becomes N-2 (even).
                    // Chanek takes (N-2)/2.
                    // This is the optimal strategy for powers of 2.
                    // Chanek takes 1. N becomes N-1.
                    chanek_coins += 1;
                    n -= 1;
                } else { // N is even but not a power of 2
                    // Take N/2. This is generally the greedy move.
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            if (n == 1) {
                n = 0; // Opponent takes 1
            } else if (n % 2 == 1) { // N is odd
                n -= 1; // Opponent takes 1
            } else { // N is even
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    n -= 1; // Opponent takes 1
                } else { // N is even but not a power of 2
                    n /= 2; // Opponent takes N/2
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

#include <iostream>
