#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need S' = 2 * X'
    // Let S_0 be current_sum and X_0 be current_xor_sum.
    // We want to find b1, b2, b3 such that (S_0 + b1 + b2 + b3) = 2 * (X_0 ^ b1 ^ b2 ^ b3)

    // Strategy: Append at most 3 elements.
    // The problem guarantees a solution with at most 3 elements.
    // A common strategy for these problems is to try to make the XOR sum equal to some value,
    // and then adjust the sum.

    // Let's try to append two elements: X_0 and S_0 + X_0.
    // Let b1 = X_0.
    // New XOR sum: X_0' = X_0 ^ b1 = X_0 ^ X_0 = 0.
    // New sum: S_0' = S_0 + b1 = S_0 + X_0.
    // Now we need to append one more element, say b2, such that:
    // (S_0' + b2) = 2 * (X_0' ^ b2)
    // (S_0 + X_0 + b2) = 2 * (0 ^ b2)
    // (S_0 + X_0 + b2) = 2 * b2
    // S_0 + X_0 = b2

    // So, if we append b1 = X_0 and b2 = S_0 + X_0, the condition should hold.
    // Let's verify:
    // New total sum S_final = S_0 + X_0 + (S_0 + X_0) = 2 * (S_0 + X_0)
    // New total XOR sum X_final = X_0 ^ X_0 ^ (S_0 + X_0) = 0 ^ (S_0 + X_0) = S_0 + X_0
    // Is S_final = 2 * X_final?
    // 2 * (S_0 + X_0) = 2 * (S_0 + X_0). Yes, it holds.

    // This strategy always works and uses 2 elements.
    // The problem allows up to 3 elements, and doesn't require minimization.
    // The values can be large, up to 10^18, which S_0 + X_0 can reach.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

