int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long b_count = 0;
    long long mod = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            b_count = (b_count + 1) % mod;
        } else { // s[i] == 'a'
            // This 'a' will jump over all 'b_count' 'b's to its right.
            // Each jump operation 'ab' -> 'bba' adds 1 to total_steps.
            // After jumping over one 'b', the 'a' is still an 'a',
            // but it has effectively created a new 'b' to its left.
            // So, the number of 'b's to its right effectively doubles for the next 'a' to its left.
            total_steps = (total_steps + b_count) % mod;
            b_count = (b_count * 2) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

