    // Step 2: Verify if the constructed w can produce s
    std::string s_reconstructed(n, '0');
    for (int i = 0; i < n; ++i) {
        bool is_one = false;
        if (i - x >= 0 && w[i - x] == '1') {
            is_one = true;
        }
        if (i + x < n && w[i + x] == '1') {
            is_one = true;
        }
        if (is_one) {
            s_reconstructed[i] = '1';
        } else {
            s_reconstructed[i] = '0';
        }
    }

    if (s_reconstructed == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

