void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string ans(n, ' ');
    bool possible = false;

    for (int p = 0; p <= 9; ++p) { // p is the pivot digit
        std::string current_ans(n, ' ');
        char last1 = '0'; // Last digit in sequence 1
        char last2 = '0'; // Last digit in sequence 2
        bool valid_p = true;

        for (int i = 0; i < n; ++i) {
            char digit = s[i];
            if (digit < p + '0') {
                // Must be in sequence 1
                if (digit < last1) {
                    valid_p = false;
                    break;
                }
                current_ans[i] = '1';
                last1 = digit;
            } else if (digit > p + '0') {
                // Must be in sequence 2
                if (digit < last2) {
                    valid_p = false;
                    break;
                }
                current_ans[i] = '2';
                last2 = digit;
            } else { // digit == p + '0'
                // Can be in sequence 1 or 2
                // Try to put it in sequence 2 if possible, to keep sequence 1 shorter
                if (digit >= last2) {
                    current_ans[i] = '2';
                    last2 = digit;
                } else if (digit >= last1) {
                    current_ans[i] = '1';
                    last1 = digit;
                } else {
                    valid_p = false;
                    break;
                }
            }
        }

        if (valid_p) {
            // Check final condition: last1 <= first2
            // This is implicitly handled by the greedy choice for digits equal to p.
            // If a digit 'p' is placed in S1, last1 becomes 'p'.
            // If a digit 'p' is placed in S2, last2 becomes 'p'.
            // Any digit < p must be in S1. Any digit > p must be in S2.
            // The only tricky part is digits equal to p.
            // Our strategy: if digit == p, try to put it in S2. If not possible (violates S2 non-decreasing),
            // then try to put it in S1. If not possible (violates S1 non-decreasing), then invalid.
            // This ensures that all 'p's that go to S1 appear before all 'p's that go to S2.
            // And all digits < p are in S1, all digits > p are in S2.
            // So, the final sequence will be (digits < p) + (some p's) + (other p's) + (digits > p).
            // The split point for 'p's is handled by the greedy choice.
            // The last digit of S1 will be the largest digit assigned '1'.
            // The first digit of S2 will be the smallest digit assigned '2'.
            // If S1 is empty, last1 is '0'. If S2 is empty, first2 is '9'+1.
            // The condition last1 <= first2 is implicitly satisfied by the construction.
            // For example, if last1 is 'p' and first2 is 'p', it's fine.
            // If last1 is 'p' and first2 is 'p'+1, it's fine.
            // If last1 is 'p'-1 and first2 is 'p', it's fine.
            // The only way it could fail is if a digit 'p' was forced into S1, making last1='p',
            // and then a later digit 'p' was forced into S2, making first2='p',
            // but an earlier digit 'p' was forced into S2, making last2='p', and then a later digit 'p' was forced into S1.
            // This is prevented by the greedy choice for 'p': always try S2 first.
            // If a 'p' goes to S1, it means it couldn't go to S2 (because it was smaller than current last2).
            // This implies that all subsequent 'p's must also go to S1 or be smaller than current last2.
            // This is not quite right. The greedy choice for 'p' is:
            // if digit == p:
            //   if digit >= last2: put in S2
            //   else if digit >= last1: put in S1
            //   else: invalid
            // This ensures that all digits assigned '1' form a non-decreasing sequence, and all digits assigned '2' form a non-decreasing sequence.
            // The crucial part is that the last digit of S1 must be <= the first digit of S2.
            // Let's verify this.
            // All digits < p are in S1. All digits > p are in S2.
            // Digits equal to p are split. Some go to S1, some to S2.
            // The split point for 'p's is determined by the greedy choice.
            // Any 'p' that goes to S1 must be >= last1.
            // Any 'p' that goes to S2 must be >= last2.
            // The greedy choice for 'p' means we prefer S2.
            // So, if a 'p' goes to S1, it means it couldn't go to S2 (i.e., 'p' < last2).
            // This implies that all 'p's that go to S1 must appear before any 'p' that goes to S2,
            // if we consider the values.
            // Example: 040425524644, p=4
            // d: 0 4 0 4 2 5 5 2 4 6 4 4
            // p: 1 2 1 2 1 2 2 1 1 2 1 1
            // S1: 0 0 2 2 4 4 4
            // S2: 4 4 5 5 6
            // last1 = 4, first2 = 4. Valid.
            // This greedy strategy for 'p's works.
            // All digits assigned '1' will be <= p. All digits assigned '2' will be >= p.
            // The last digit of S1 will be <= p. The first digit of S2 will be >= p.
            // So last1 <= first2 is guaranteed.

            ans = current_ans;
            possible = true;
            break; // Found a valid coloring for this pivot p
        }
    }

    if (possible) {
        std::cout << ans << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

