#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;
        long long abs_n = std::abs(n);
        long long abs_m = std::abs(m);

        long long min_coord = std::min(abs_n, abs_m);
        long long max_coord = std::max(abs_n, abs_m);

        if (k < max_coord) {
            std::cout << -1 << "\n";
            continue;
        }

        long long remaining_moves = k - max_coord;
        long long diagonal_moves = min_coord;
        long long axial_moves_to_max = max_coord - min_coord;

        // Case 1: Target (n,m) and k have same parity
        // (abs_n + abs_m) % 2 == k % 2
        // This is equivalent to (max_coord + min_coord) % 2 == k % 2
        // Or (max_coord % 2) == (k % 2) if min_coord is even
        // Or (max_coord % 2) != (k % 2) if min_coord is odd
        // A simpler way: (max_coord - min_coord) % 2 == (k - min_coord) % 2
        // (axial_moves_to_max) % 2 == (remaining_moves) % 2
        if ((axial_moves_to_max % 2) == (remaining_moves % 2)) {
            std::cout << k << "\n";
        } else {
            // Case 2: Target (n,m) and k have different parity
            // (abs_n + abs_m) % 2 != k % 2
            // This means we need to adjust the parity of k.
            // We can do this by sacrificing one diagonal move for two axial moves,
            // or by sacrificing one axial move for two axial moves (if possible).
            // The minimum number of moves to change parity is 1.
            // If k is odd and (abs_n+abs_m) is even, or vice versa.
            // We need to reduce k by 1 or 2 to match parity.
            // Since k >= max_coord, and we know k and max_coord have different parity,
            // k - max_coord must be odd.
            // So remaining_moves is odd.
            // We need to make remaining_moves even.
            // We can do this by using one move to go back and forth, e.g., (x,y) -> (x+1,y) -> (x,y).
            // This uses 2 moves and changes parity of (x,y) by 0.
            // Or (x,y) -> (x+1,y+1) -> (x,y+1). This uses 2 moves, changes parity of (x,y) by 1.
            // The most efficient way to change parity of k is to use one move to go to (x+1,y) and then (x,y+1)
            // or (x+1,y+1) and then (x+1,y).
            // If we have at least one move to spare (remaining_moves >= 1), we can use it.
            // If remaining_moves is odd, we need to use one move to flip parity.
            // This means we use k-1 moves to reach the target, and the last move to flip parity.
            // The maximum number of diagonal moves would be k-2.
            // Example: (0,0) -> (1,1) in 3 moves. Target (1,1). k=3.
            // abs_n=1, abs_m=1. min_coord=1, max_coord=1.
            // k=3, max_coord=1. k >= max_coord.
            // remaining_moves = 3-1 = 2.
            // axial_moves_to_max = 1-1 = 0.
            // (0 % 2) == (2 % 2) -> 0 == 0. Parity matches. Output k=3.
            // Example: (0,0) -> (2,2) in 3 moves. Target (2,2). k=3.
            // abs_n=2, abs_m=2. min_coord=2, max_coord=2.
            // k=3, max_coord=2. k >= max_coord.
            // remaining_moves = 3-2 = 1.
            // axial_moves_to_max = 2-2 = 0.
            // (0 % 2) == (1 % 2) -> 0 != 1. Parity mismatch.
            // We need to reduce k by 1 or 2.
            // If k is odd and (abs_n+abs_m) is even, or vice versa.
            // This means k and max_coord have different parities.
            // So k - max_coord is odd.
            // We need to use one move to change parity.
            // This means we effectively have k-1 moves to reach a point with the same parity as max_coord.
            // And then one move to flip parity.
            // The maximum number of diagonal moves would be k-1-1 = k-2.
            // This is because we use one move to go to (x+1,y) and then (x,y+1) or similar.
            // This uses 2 moves, and changes the parity of the final coordinate by 0.
            // So if k and max_coord have different parities, we must use at least one "wasted" move.
            // This "wasted" move effectively reduces the number of moves that can contribute to diagonal moves by 2.
            // For example, if we need to reach (2,2) in 3 moves.
            // (0,0) -> (1,1) -> (2,1) -> (2,2). This is 2 diagonal, 1 axial. Total 3 moves.
            // (0,0) -> (1,1) -> (2,2) -> (1,2). This is 2 diagonal, 1 axial. Total 3 moves.
            // The maximum number of diagonal moves is k-2.
            std::cout << k - 2 << "\n";
        }
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 0;
        long long k = 1; // Represents the number of stairs in the current nice staircase (1, 3, 7, 15, ...)
        while (true) {
            // Cost of a nice staircase with k stairs: k * (k + 1) / 2
            // k is of the form 2^p - 1.
            // So, cost is (2^p - 1) * (2^p) / 2
            // Let m = 2^p. Then cost is (m - 1) * m / 2.
            // For k=1 (p=1, m=2), cost = (2-1)*2/2 = 1.
            // For k=3 (p=2, m=4), cost = (4-1)*4/2 = 6.
            // For k=7 (p=3, m=8), cost = (8-1)*8/2 = 28.
            // For k=15 (p=4, m=16), cost = (16-1)*16/2 = 120.

            long long cost_of_k_staircase = k * (k + 1) / 2;

            if (current_cost + cost_of_k_staircase <= x) {
                current_cost += cost_of_k_staircase;
                count++;
                // Next k will be 2*k + 1
                // Check for overflow before multiplying
                if (k > (2000000000000000000LL - 1) / 2) { // k_max approx 10^18, so 2*k+1 can exceed 2*10^18
                    break; // k is too large, next k would overflow or exceed practical limits
                }
                k = 2 * k + 1;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

