    }

    std::string result_layout = "";
    std::vector<bool> visited(26, false);

    for (int i = 0; i < 26; ++i) {
        if (present_in_s[i] && !visited[i]) {
            if (adj[i].size() <= 1) { // Start of a path or isolated node
                int current_char_idx = i;
                while (current_char_idx != -1) {
                    if (visited[current_char_idx]) {
                        // This should not happen if graph is valid (max degree 2)
                        // and we start from degree 0 or 1 nodes.
                        // It implies a cycle or an issue with path traversal.
                        // For this problem, it means we found a cycle that was not fully processed.
                        // Or a path that was already part of another path.
                        // Given the problem constraints (max degree 2), this means we've hit a cycle.
                        // If it's a cycle of characters from 's', it's fine as long as it's a simple cycle.
                        // But we are building a linear layout.
                        // If we start from a degree 1 node, we should always extend it.
                        // If we start from a degree 0 node, it's just itself.
                        // If we hit a visited node, it means we are trying to extend a path into an already processed path/cycle.
                        // This can happen if there are multiple connected components that are paths/cycles.
                        // For example, if 'ab' and 'cd' are in s, and we process 'ab', then 'cd'.
                        // If 'a' is degree 1, we process 'a' then 'b'.
                        // If 'c' is degree 1, we process 'c' then 'd'.
                        // This loop condition is more for detecting issues in graph traversal logic.
                        break;
                    }
                    visited[current_char_idx] = true;
                    result_layout += (char)('a' + current_char_idx);

                    int next_char_idx = -1;
                    for (int neighbor : adj[current_char_idx]) {
                        if (!visited[neighbor]) {
                            next_char_idx = neighbor;
                            break;
                        }
                    }
                    current_char_idx = next_char_idx;
                }
            }
        }
    }

    // Check if all characters from 's' are included in the layout
    // This implicitly checks for cycles among characters in 's' that are not paths.
    // If there's a cycle, no node will have degree 0 or 1, so we won't start a path from it.
    // If all nodes in 's' have degree 2, it means they form one or more cycles.
    // A single cycle can be linearized, but multiple cycles or a cycle plus a path cannot.
    // The current logic only starts from degree 0 or 1 nodes.
    // If all present_in_s nodes have degree 2, they form cycles.
    // If there's only one cycle, we can pick any node, traverse it, and it will be a valid layout.
    // But our current logic won't pick any node if all have degree 2.
    // Let's refine: if all present_in_s nodes are visited, it's good.
    // If not, it means there are unvisited nodes from 's'.
    // These unvisited nodes must all have degree 2 (otherwise they would have been picked).
    // If they all have degree 2, they form one or more cycles.
    // If there's exactly one cycle, we can pick any node from it and traverse.
    // If there are multiple cycles, it's impossible.

    // Let's count unvisited nodes that are present in 's'
    int unvisited_present_count = 0;
    int first_unvisited_present = -1;
    for (int i = 0; i < 26; ++i) {
        if (present_in_s[i] && !visited[i]) {
            unvisited_present_count++;
            if (first_unvisited_present == -1) {
                first_unvisited_present = i;
            }
        }
    }

    if (unvisited_present_count > 0) {
        // If there are unvisited nodes from 's', they must all have degree 2.
        // This means they form one or more cycles.
        // We need to check if they form exactly one cycle.
        // We can do a DFS/BFS from first_unvisited_present to count nodes in its component.
        std::vector<bool> cycle_visited(26, false);
        std::vector<int> q;
        q.push_back(first_unvisited_present);
        cycle_visited[first_unvisited_present] = true;
        int current_component_count = 0;
        int head = 0;
        while(head < q.size()){
            int u = q[head++];
            current_component_count++;
            for(int v : adj[u]){
                if(!cycle_visited[v]){
                    cycle_visited[v] = true;
                    q.push_back(v);
                }
            }
        }

        if (current_component_count != unvisited_present_count) {
            // Multiple cycles or a cycle and other paths not handled.
            // This means there are multiple connected components of degree-2 nodes.
            std::cout << "NO\n";
            return;
        } else {
            // Exactly one cycle. We can linearize it.
            // Pick first_unvisited_present, traverse it, add to layout.
            int current_char_idx = first_unvisited_present;
            int prev_char_idx = -1; // To handle cycle traversal

            // Add the cycle to the layout
            while (true) {
                visited[current_char_idx] = true;
                result_layout += (char)('a' + current_char_idx);

                int next_char_idx = -1;
                for (int neighbor : adj[current_char_idx]) {
                    if (neighbor != prev_char_idx) { // Don't go back immediately
                        next_char_idx = neighbor;
                        break;
                    }
                }

                if (next_char_idx == -1 || next_char_idx == first_unvisited_present) {
                    // Reached the end of the path or back to the start of the cycle
                    // If next_char_idx == first_unvisited_present, it means we completed the cycle.
                    // If next_char_idx == -1, it means current_char_idx has only one neighbor (prev_char_idx),
                    // which implies it's an end of a path, but we are in a cycle context.
                    // This should only happen if the cycle has only 2 nodes, and we've visited both.
                    break;
                }
                prev_char_idx = current_char_idx;
                current_char_idx = next_char_idx;
            }
        }
    }

    // Add remaining characters not in 's'
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            result_layout += (char)('a' + i);
        }
    }

    std::cout << "YES\n";
    std::cout << result_layout << "\n";
}

