#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char first_char_t = s[k_actual]; // t[0]

        // Find all possible k' values that would result in the same t[0]
        const std::vector<int>& possible_k_indices = char_indices[first_char_t - 'a'];

        if (possible_k_indices.size() == 1) {
            // If only one k' results in this t[0], Vasya wins immediately.
            total_win_prob += 1.0;
            continue;
        }

        // Vasya needs to choose an optimal position p to reveal t[p].
        // p can be from 1 to L-1.
        double max_win_prob_for_k_actual = 0.0;

        for (int p = 1; p < L; ++p) {
            int current_p_wins = 0;

            // For each possible k' that yields the same t[0] as k_actual:
            // Check if revealing t[p] helps distinguish k_actual from other k's.
            // Vasya wins if k_actual is the *only* k' that matches both t[0] and t[p].

            // We need to count how many k' values (from possible_k_indices)
            // would result in the same (t[0], t[p]) pair as (s[k_actual], s[(k_actual + p) % L]).
            // If this count is 1, then Vasya wins for this specific k_actual and chosen p.

            // The character at t[p] for the actual k is s[(k_actual + p) % L].
            char second_char_t = s[(k_actual + p) % L];

            int count_matches = 0;
            for (int k_prime : possible_k_indices) {
                if (s[(k_prime + p) % L] == second_char_t) {
                    count_matches++;
                }
            }

            if (count_matches == 1) {
                // If only one k' (which must be k_actual) matches both t[0] and t[p], Vasya wins.
                current_p_wins = 1;
            }

            max_win_prob_for_k_actual = std::max(max_win_prob_for_k_actual, (double)current_p_wins);
        }
        total_win_prob += max_win_prob_for_k_actual;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    // We need to handle division by 2 with modulo.
    // (b-1) * b can be large, so take modulo at each step.
    long long sum_r_term1 = (b - 1 + MOD) % MOD; // Ensure positive for (b-1) if b=1
    long long sum_r_term2 = b % MOD;

    long long sum_r_numerator = (sum_r_term1 * sum_r_term2) % MOD;

    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 8) / 2 = 500000004
    long long inv2 = 500000004; 
    long long sum_r = (sum_r_numerator * inv2) % MOD;

    // Calculate sum_k_b_plus_1 = sum_{k=1 to a} (k * b + 1)
    // sum_k_b_plus_1 = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // sum_{k=1 to a} k = a * (a + 1) / 2
    // sum_{k=1 to a} 1 = a

    long long sum_k_numerator = (a % MOD * ((a + 1) % MOD)) % MOD;
    long long sum_k = (sum_k_numerator * inv2) % MOD;

    long long sum_k_b_plus_1 = ( (b % MOD * sum_k) % MOD + (a % MOD) ) % MOD;

    // Total sum = (sum_r * sum_k_b_plus_1) % MOD
    long long total_sum = (sum_r * sum_k_b_plus_1) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we'll use for the alternating part to generate k distinct differences

    // Generate k distinct differences: 1, 2, ..., k
    // We can achieve this by alternating between the smallest available and largest available numbers.
    // For example, if k=3, we want differences 1, 2, 3.
    // We can use numbers 1, 2, 3, 4.
    // Sequence: 1, 4, 2, 3
    // Differences: |1-4|=3, |4-2|=2, |2-3|=1. Distinct: {1,2,3}.
    // This pattern uses k+1 numbers.

    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index, print from left (smallest available)
            std::cout << left++;
        } else { // Odd index, print from right (largest available)
            std::cout << right--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // After generating k distinct differences using k+1 numbers,
    // we have used numbers from 1 up to (k+1).
    // The remaining numbers are (k+2), (k+3), ..., n.
    // To avoid introducing new distinct differences, we can just print them in increasing order.
    // This will only introduce a difference of 1 (e.g., |(k+1) - (k+2)| = 1),
    // which is already among the k distinct differences (since k >= 1).

    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // We need to track the transformation for two specific inputs: 0 and 1023.
    // Let's call them `val0` and `val1023`.
    // `val0` will store the result of applying all operations to 0.
    // `val1023` will store the result of applying all operations to 1023.
    // The maximum value for constants is 1023, which is 0b1111111111 (10 bits).
    // So we only care about bits 0-9.
    int val0 = 0;
    int val1023 = 1023; // All bits set

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            val0 &= x;
            val1023 &= x;
        } else if (op_char == '|') {
            val0 |= x;
            val1023 |= x;
        } else if (op_char == '^') {
            val0 ^= x;
            val1023 ^= x;
        }
    }

    // Now we have the final state for input 0 and input 1023.
    // Let's determine the equivalent operations.
    // We need to find A, B, C such that:
    // (x & A | B) ^ C = final_result(x) for all x in [0, 1023]
    // Or, more generally, a sequence of at most 5 operations.

    // Let's analyze bit by bit. For each bit `j` (0 to 9):
    // Let `x_j` be the j-th bit of input `x`.
    // Let `f_j(x_j)` be the j-th bit of the final result.
    // We know `f_j(0)` (j-th bit of `val0`) and `f_j(1)` (j-th bit of `val1023` if `x_j` was 1).
    // The j-th bit of `val0` is `(val0 >> j) & 1`.
    // The j-th bit of `val1023` is `(val1023 >> j) & 1`.

    // Case 1: `f_j(0) = 0`, `f_j(1) = 0` => `x_j` always becomes 0. This is `x_j & 0`.
    // Case 2: `f_j(0) = 0`, `f_j(1) = 1` => `x_j` becomes `x_j`. This is `x_j & 1` or `x_j | 0` or `x_j ^ 0`.
    // Case 3: `f_j(0) = 1`, `f_j(1) = 0` => `x_j` becomes `!x_j`. This is `x_j ^ 1`.
    // Case 4: `f_j(0) = 1`, `f_j(1) = 1` => `x_j` always becomes 1. This is `x_j | 1`.

    // We can combine these into three operations:
    // 1. An AND operation to set certain bits to 0.
    // 2. An OR operation to set certain bits to 1.
    // 3. An XOR operation to flip certain bits.

    // Let's find the constants for these three operations.
    // `and_const`: bits that must be 0 (Case 1) or can be `x_j` (Case 2) or `!x_j` (Case 3).
    //              If `f_j(0)=0` and `f_j(1)=0`, then `and_const_j` must be 0.
    //              Otherwise, `and_const_j` can be 1.
    // `or_const`: bits that must be 1 (Case 4) or can be `x_j` (Case 2) or `!x_j` (Case 3).
    //             If `f_j(0)=1` and `f_j(1)=1`, then `or_const_j` must be 1.
    //             Otherwise, `or_const_j` can be 0.
    // `xor_const`: bits that must be flipped (Case 3) or can be `x_j` (Case 2) or `!x_j` (Case 3).
    //              If `f_j(0)=1` and `f_j(1)=0`, then `xor_const_j` must be 1.
    //              Otherwise, `xor_const_j` can be 0.

    // Let's define the constants for the three operations:
    // `final_and_val`: bits that are forced to 0. If `f_j(0)=0` and `f_j(1)=0`, then `final_and_val_j` is 0. Otherwise 1.
    // `final_or_val`: bits that are forced to 1. If `f_j(0)=1` and `f_j(1)=1`, then `final_or_val_j` is 1. Otherwise 0.
    // `final_xor_val`: bits that are flipped. If `f_j(0)=1` and `f_j(1)=0`, then `final_xor_val_j` is 1. Otherwise 0.

    int final_and_val = 0b1111111111; // Initialize to all 1s
    int final_or_val = 0;             // Initialize to all 0s
    int final_xor_val = 0;            // Initialize to all 0s

    for (int j = 0; j < 10; ++j) {
        int bit0 = (val0 >> j) & 1;
        int bit1 = (val1023 >> j) & 1;

        if (bit0 == 0 && bit1 == 0) { // Case 1: x_j -> 0
            final_and_val &= ~(1 << j); // Force this bit to 0
        } else if (bit0 == 0 && bit1 == 1) { // Case 2: x_j -> x_j
            // No change to final_and_val, final_or_val, final_xor_val for this bit
        } else if (bit0 == 1 && bit1 == 0) { // Case 3: x_j -> !x_j
            final_xor_val |= (1 << j); // Flip this bit
        } else if (bit0 == 1 && bit1 == 1) { // Case 4: x_j -> 1
            final_or_val |= (1 << j); // Force this bit to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;

    // The order of operations matters. A common canonical form is:
    // (x & A | B) ^ C
    // Let's verify this.
    // For a bit j:
    // If x_j -> 0 (Case 1): A_j=0, B_j=0, C_j=0. (x_j & 0 | 0) ^ 0 = 0. Correct.
    // If x_j -> x_j (Case 2): A_j=1, B_j=0, C_j=0. (x_j & 1 | 0) ^ 0 = x_j. Correct.
    // If x_j -> !x_j (Case 3): A_j=1, B_j=0, C_j=1. (x_j & 1 | 0) ^ 1 = !x_j. Correct.
    // If x_j -> 1 (Case 4): A_j=1, B_j=1, C_j=0. (x_j & 1 | 1) ^ 0 = 1. Correct.

    // So, the constants are:
    // A = final_and_val
    // B = final_or_val
    // C = final_xor_val

    // Add operations if their constants are not identity.
    // & 1023 is identity for AND.
    // | 0 is identity for OR.
    // ^ 0 is identity for XOR.

    if (final_and_val != 1023) {
        result_ops.push_back({'&', final_and_val});
    }
    if (final_or_val != 0) {
        result_ops.push_back({'|', final_or_val});
    }
    if (final_xor_val != 0) {
        result_ops.push_back({'^', final_xor_val});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << 1 << std::endl;
        return 0;
    }

    int k = static_cast<int>(std::sqrt(n));
    while (k * k < n) {
        k++;
    }
    // k is now ceil(sqrt(n))

    // The strategy is to divide the numbers 1 to n into blocks of size k.
    // Each block will be printed in decreasing order.
    // The blocks themselves will be arranged such that the numbers in later blocks
    // are generally larger than numbers in earlier blocks.
    // Specifically, we print numbers from (i*k + 1) to min((i+1)*k, n) in decreasing order.
    // This means the first block is k, k-1, ..., 1 (or up to n if n < k)
    // The second block is 2k, 2k-1, ..., k+1 (or up to n if n < 2k)
    // And so on.

    for (int i = 0; i < n; ++i) {
        int block_start_val = (i / k) * k; // This is the base value for the current block
        int current_val_in_block = block_start_val + (k - (i % k));

        // Adjust for the last block if n is not a multiple of k
        // The numbers are 1-indexed, so block_start_val + 1 is the smallest in the block
        // and block_start_val + k is the largest.
        // We want to print from block_start_val + k down to block_start_val + 1.
        // The current element is at index i.
        // Its position within its block is i % k.
        // So, for i % k = 0, we want to print the largest element in the block.
        // For i % k = k-1, we want to print the smallest element in the block.
        // The value to print is (block_start_val + k) - (i % k).

        int val_to_print = (block_start_val + k) - (i % k);

        // Ensure we don't print values greater than n
        if (val_to_print > n) {
            // This happens if the last block is not full.
            // For example, n=4, k=2.
            // i=0: block_start_val=0, i%k=0. val_to_print = (0+2)-0 = 2. Output 2.
            // i=1: block_start_val=0, i%k=1. val_to_print = (0+2)-1 = 1. Output 1.
            // i=2: block_start_val=2, i%k=0. val_to_print = (2+2)-0 = 4. Output 4.
            // i=3: block_start_val=2, i%k=1. val_to_print = (2+2)-1 = 3. Output 3.
            // Result: 2 1 4 3.
            // This is not the example output (3 4 1 2).
            // The example output for n=4, k=2 is 3 4 1 2.
            // LIS: [3,4] or [1,2] (len 2)
            // LDS: [3,1], [3,2], [4,1], [4,2] (len 2)
            // Sum = 4.
            // My current construction for n=4, k=2: 2 1 4 3.
            // LIS: [2,4], [2,3], [1,4], [1,3] (len 2)
            // LDS: [2,1], [4,3] (len 2)
            // Sum = 4. Both are valid.

            // Let's re-evaluate the block construction.
            // The goal is to have LIS and LDS both be around k.
            // A common construction is to print blocks of size k in decreasing order,
            // and then arrange these blocks such that the numbers in later blocks are larger.
            // Example: n=4, k=2.
            // Block 1: 2 1
            // Block 2: 4 3
            // Permutation: 2 1 4 3.
            // LIS: [2,4], [2,3], [1,4], [1,3] -> length 2.
            // LDS: [2,1], [4,3] -> length 2.
            // Sum = 4.

            // Example: n=9, k=3.
            // Block 1: 3 2 1
            // Block 2: 6 5 4
            // Block 3: 9 8 7
            // Permutation: 3 2 1 6 5 4 9 8 7
            // LIS: [1,4,7], [2,5,8], [3,6,9] -> length 3.
            // LDS: [3,2,1], [6,5,4], [9,8,7] -> length 3.
            // Sum = 6.

            // The current logic `val_to_print = (block_start_val + k) - (i % k);`
            // correctly generates this pattern.
            // The only issue is if `val_to_print` exceeds `n`.
            // This happens for the last block if `n` is not a multiple of `k`.
            // For example, n=5, k=3.
            // i=0: block_start_val=0, i%k=0. val_to_print = (0+3)-0 = 3. Output 3.
            // i=1: block_start_val=0, i%k=1. val_to_print = (0+3)-1 = 2. Output 2.
            // i=2: block_start_val=0, i%k=2. val_to_print = (0+3)-2 = 1. Output 1.
            // i=3: block_start_val=3, i%k=0. val_to_print = (3+3)-0 = 6. This is > n=5.
            // i=4: block_start_val=3, i%k=1. val_to_print = (3+3)-1 = 5. Output 5.
            // The problem is that the last block should only contain numbers up to n.
            // The numbers in the last block are `n`, `n-1`, ..., `(num_blocks-1)*k + 1`.
            // The `block_start_val` for the last block is `(num_blocks-1)*k`.
            // The numbers to print are `n`, `n-1`, ..., `(num_blocks-1)*k + 1`.
            // The number of elements in the last block is `n - (num_blocks-1)*k`.
            // Let `num_blocks = (n + k - 1) / k`.
            // The last block starts at index `(num_blocks - 1) * k`.
            // For `i` in the last block: `i >= (num_blocks - 1) * k`.
            // The values should be `n - (i - (num_blocks - 1) * k)`.

            int num_blocks = (n + k - 1) / k;
            int current_block_idx = i / k;

            if (current_block_idx == num_blocks - 1) { // This is the last block
                int start_of_last_block_idx = (num_blocks - 1) * k;
                val_to_print = n - (i - start_of_last_block_idx);
            } else {
                val_to_print = (current_block_idx * k + k) - (i % k);
            }
        }

        std::cout << val_to_print << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // diff_L[k] = (count of 1s in a[0...k-1]) - (count of 2s in a[0...k-1])
    // diff_L[0] = 0
    std::vector<int> diff_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_L[i + 1] = diff_L[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate prefix sums for the right side (jars n+1 to 2n)
    // diff_R[k] = (count of 1s in a[2n-1...2n-k]) - (count of 2s in a[2n-1...2n-k])
    // diff_R[0] = 0
    std::vector<int> diff_R(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_R[i + 1] = diff_R[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Store the minimum number of jars removed from the left to achieve a certain diff_L value
    // map_L[diff_val] = k (meaning diff_L[k] = diff_val)
    std::map<int, int> map_L;
    for (int k = 0; k <= n; ++k) {
        if (map_L.find(diff_L[k]) == map_L.end()) {
            map_L[diff_L[k]] = k;
        }
    }

    int min_removed = 2 * n; // Initialize with max possible removed jars

    // Iterate through all possible numbers of jars removed from the right (k_R)
    // For each k_R, we have diff_R[k_R].
    // We need to find k_L such that diff_L[k_L] + diff_R[k_R] = 0.
    // This means diff_L[k_L] = -diff_R[k_R].
    for (int k_R = 0; k_R <= n; ++k_R) {
        int target_diff_L = -diff_R[k_R];
        if (map_L.count(target_diff_L)) {
            int k_L = map_L[target_diff_L];
            min_removed = std::min(min_removed, k_L + k_R);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Edge case, though problem states n >= 3
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> left_zero_run(n);
    std::vector<int> right_zero_run(n);
    std::vector<int> left_one_run(n);
    std::vector<int> right_one_run(n);

    // Calculate left_zero_run and left_one_run
    left_zero_run[0] = (a[0] == 0);
    left_one_run[0] = (a[0] == 1);
    for (int i = 1; i < n; ++i) {
        left_zero_run[i] = (a[i] == 0) ? (left_zero_run[i - 1] + 1) : 0;
        left_one_run[i] = (a[i] == 1) ? (left_one_run[i - 1] + 1) : 0;
    }

    // Calculate right_zero_run and right_one_run
    right_zero_run[n - 1] = (a[n - 1] == 0);
    right_one_run[n - 1] = (a[n - 1] == 1);
    for (int i = n - 2; i >= 0; --i) {
        right_zero_run[i] = (a[i] == 0) ? (right_zero_run[i + 1] + 1) : 0;
        right_one_run[i] = (a[i] == 1) ? (right_one_run[i + 1] + 1) : 0;
    }

    int max_k = 0;
    std::vector<int> final_b = a;

    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) { // Current element is 0
            // Find the length of the 0-run it belongs to
            int current_zero_run_len = left_zero_run[i] + right_zero_run[i] - 1;
            if (current_zero_run_len % 2 == 1) { // Odd length 0-run
                // This 0 will never change to 1.
                // It will become 0 in the final sequence.
                // The number of steps for it to stabilize is 0.
            } else { // Even length 0-run
                // This 0 will eventually become 1.
                // It will change to 1 after (current_zero_run_len / 2) steps.
                // The final value will be 1.
                // The number of steps for it to stabilize is (current_zero_run_len / 2).
                int k_val = current_zero_run_len / 2;
                max_k = std::max(max_k, k_val);
                final_b[i] = 1;
            }
        } else { // Current element is 1
            // Find the length of the 1-run it belongs to
            int current_one_run_len = left_one_run[i] + right_one_run[i] - 1;
            if (current_one_run_len % 2 == 1) { // Odd length 1-run
                // This 1 will never change to 0.
                // It will become 1 in the final sequence.
                // The number of steps for it to stabilize is 0.
            } else { // Even length 1-run
                // This 1 will eventually become 0.
                // It will change to 0 after (current_one_run_len / 2) steps.
                // The final value will be 0.
                // The number of steps for it to stabilize is (current_one_run_len / 2).
                int k_val = current_one_run_len / 2;
                max_k = std::max(max_k, k_val);
                final_b[i] = 0;
            }
        }
    }

    std::cout << max_k << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << final_b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <map>
