char get_winning_move(char bot_move) {
    if (bot_move == 'R') return 'P';
    if (bot_move == 'S') return 'R';
    if (bot_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int countR = 0;
        int countS = 0;
        int countP = 0;

        for (char c : s) {
            if (c == 'R') {
                countR++;
            } else if (c == 'S') {
                countS++;
            } else { // c == 'P'
                countP++;
            }
        }

        char most_frequent_bot_move;
        if (countR >= countS && countR >= countP) {
            most_frequent_bot_move = 'R';
        } else if (countS >= countR && countS >= countP) {
            most_frequent_bot_move = 'S';
        } else {
            most_frequent_bot_move = 'P';
        }

        char our_optimal_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << our_optimal_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_val = 0; // The minimum possible value for the current element a[i]

    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];

        if (current_a <= prev_val) {
            // Case 1: current_a is already less than or equal to prev_val.
            // We need to increment current_a to be at least prev_val.
            // The required increment is (prev_val - current_a).
            // If (prev_val - current_a) > x, it's impossible.
            // Example: prev_val = 5, current_a = 2, m = 10. Need to increment by 3.
            // If x = 2, impossible.
            // If x = 3, possible. New value is 5.
            if (prev_val - current_a > x) {
                return false;
            }
            // If we can increment current_a to prev_val, we do.
            // The new value for a[i] will be prev_val.
            // prev_val remains unchanged for the next iteration.
        } else { // current_a > prev_val
            // Case 2: current_a is greater than prev_val.
            // We have two choices:
            // Choice A: Don't increment current_a. The new value for a[i] is current_a.
            //           This is valid if current_a >= prev_val.
            // Choice B: Increment current_a such that it wraps around and becomes smaller.
            //           The new value for a[i] would be (current_a + k) % m.
            //           We want this new value to be prev_val.
            //           This means (current_a + k) % m = prev_val.
            //           This is equivalent to k = (prev_val - current_a + m) % m.
            //           The number of increments needed is (prev_val - current_a + m) % m.
            //           If this number of increments is <= x, then we can achieve prev_val.
            //           Example: prev_val = 2, current_a = 8, m = 10.
            //           Option A: Keep 8. Valid.
            //           Option B: Increment 8 to 2. Need (2 - 8 + 10) % 10 = 4 increments.
            //                     If x = 3, impossible to make it 2.
            //                     If x = 4, possible to make it 2.
            //
            // We want to keep the value as small as possible to satisfy the non-decreasing condition.
            // So, if we can achieve prev_val by incrementing current_a (wrapping around),
            // and the number of increments is <= x, then we should choose that.
            // The number of increments needed for this is (m - (current_a - prev_val)).
            // If (m - (current_a - prev_val)) <= x, then we can make a[i] equal to prev_val.
            // Otherwise, we must keep a[i] as current_a (without wrapping around).
            // In this case, the new prev_val for the next iteration becomes current_a.

            if (current_a + x < m + prev_val) { // This is equivalent to (current_a - prev_val) > x
                                                // or (current_a - prev_val) + m > x + m
                                                // or (m - (current_a - prev_val)) > x
                                                // This means we cannot wrap around to prev_val or less.
                                                // So we must keep current_a as is.
                prev_val = current_a;
            } else {
                // We can potentially wrap around to prev_val.
                // The current_a can be incremented to (current_a + k) % m.
                // We need (current_a + k) % m >= prev_val.
                // The smallest value we can achieve is prev_val.
                // This happens if we increment current_a by (prev_val - current_a + m) % m.
                // The number of increments is (prev_val - current_a + m) % m.
                // If this is <= x, we can make it prev_val.
                // Otherwise, we cannot make it prev_val by wrapping around.
                // The condition (current_a + x < m + prev_val) is equivalent to
                // (current_a - prev_val) > x.
                // If (current_a - prev_val) > x, it means the "gap" is too large to bridge by wrapping.
                // Example: prev_val=2, current_a=8, m=10, x=3.
                // current_a - prev_val = 6. x = 3. 6 > 3.
                // So we cannot make 8 become 2 (needs 4 increments).
                // We must keep 8. So prev_val becomes 8.
                //
                // If (current_a - prev_val) <= x, it means we can make current_a become prev_val
                // by wrapping around.
                // Example: prev_val=2, current_a=8, m=10, x=4.
                // current_a - prev_val = 6. x = 4. 6 > 4.
                // This logic is tricky. Let's simplify.
                // We want to find the smallest `val` such that `val >= prev_val` and `val` can be formed from `a[i]` with at most `x` increments.
                // `val` can be `a[i]` (0 increments).
                // `val` can be `(a[i] + k) % m` where `1 <= k <= x`.
                //
                // If `a[i] >= prev_val`:
                //   We can choose `a[i]` itself. This is valid.
                //   We can also choose `(a[i] + k) % m` for some `k`.
                //   If `(a[i] + x) % m < prev_val`, it means even with max increments, we can't reach `prev_val` by wrapping around.
                //   So we must use `a[i]` itself. `prev_val` for next becomes `a[i]`.
                //   This is equivalent to `a[i] + x < m + prev_val`.
                //   If `a[i] + x >= m + prev_val`, it means we can reach `prev_val` by wrapping around.
                //   Example: a[i]=8, prev_val=2, m=10, x=4.
                //   a[i]+x = 8+4 = 12. m+prev_val = 10+2 = 12.
                //   12 >= 12. So we can make a[i] become prev_val (2).
                //   Number of increments needed: (2 - 8 + 10) % 10 = 4. This is <= x.
                //   So we set prev_val to 2.
                //
                // The condition `a[i] + x < m + prev_val` is equivalent to `(a[i] - prev_val) > x`.
                // If `(a[i] - prev_val) > x`, it means the difference `a[i] - prev_val` is too large
                // to be covered by `x` increments *if we wrap around*.
                // No, this is not quite right.
                //
                // Let's re-evaluate:
                // We need to find `v_i` such that `v_i >= prev_val` and `v_i` can be obtained from `a[i]`
                // by adding `k` increments, where `0 <= k <= x`.
                //
                // If `a[i] >= prev_val`:
                //   Option 1: Don't increment `a[i]`. New value is `a[i]`. This is valid.
                //   Option 2: Increment `a[i]` by `k` such that `(a[i] + k) % m = prev_val`.
                //             The `k` needed is `(prev_val - a[i] + m) % m`.
                //             If this `k <= x`, then we can make `a[i]` become `prev_val`.
                //             In this case, we prefer `prev_val` because it's smaller.
                //   So, if `(prev_val - a[i] + m) % m <= x`, we set `prev_val` to `prev_val`.
                //   Else (if `(prev_val - a[i] + m) % m > x`), we must use `a[i]` itself.
                //   So we set `prev_val` to `a[i]`.
                //
                // This can be simplified:
                // If `a[i] >= prev_val`:
                //   If `a[i] + x < m + prev_val` (which means `a[i] - prev_val > x`):
                //     We cannot make `a[i]` wrap around to `prev_val` or less.
                //     So we must use `a[i]` itself. `prev_val` for next becomes `a[i]`.
                //   Else (`a[i] + x >= m + prev_val`):
                //     We can make `a[i]` wrap around to `prev_val` (or even smaller, but we need at least `prev_val`).
                //     So we can set `prev_val` to `prev_val`.
                //
                // This logic is correct.
                // The condition `a[i] + x < m + prev_val` is equivalent to `(a[i] - prev_val) > x`.
                // If `(a[i] - prev_val) > x`, it means the "distance" from `prev_val` to `a[i]` (without wrap) is too large.
                // We cannot make `a[i]` become `prev_val` by wrapping around.
                // Example: prev_val=2, a[i]=8, m=10, x=3.
                // a[i] - prev_val = 6. x = 3. 6 > 3.
                // So we must use a[i] itself. `prev_val` becomes 8.
                //
                // Example: prev_val=2, a[i]=8, m=10, x=4.
                // a[i] - prev_val = 6. x = 4. 6 > 4 is false.
                // So we can make a[i] become prev_val. `prev_val` remains 2.
                //
                // This is the correct logic for `a[i] > prev_val`.
                // If `(a[i] - prev_val) > x`, then we cannot make `a[i]` become `prev_val` by wrapping around.
                // So we must take `a[i]` as the current value.
                // `prev_val` for the next iteration becomes `a[i]`.
                // Otherwise, we can make `a[i]` become `prev_val` by wrapping around.
                // So `prev_val` for the next iteration remains `prev_val`.
                if (current_a - prev_val > x) {
                    prev_val = current_a;
                }
            }
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// In the worst case, y could be n * max(a_i) * 2, which is 2*10^5 * 10^9 * 2 = 4*10^14.
// This fits in long long.

// Using a vector for a, indexed from 0 to n-1.
// The problem uses 1-based indexing for x and a_x.
// So, a[x] in problem corresponds to a_vec[x-1] in code.
// n is up to 2*10^5.

// To detect cycles and avoid recomputing, we can use dynamic programming or memoization.
// For each starting `a[1]` (which is `i` from 1 to n-1), we need to find the result.
// The state of the program is (current_x, current_y, current_a_val_at_x).
// However, `y` accumulates, so it's not a simple state.
// The crucial observation is that the sequence of `x` values depends only on `x` and `a[x]`.
// The `y` value is just an accumulation.
// Let `dp[x]` store a pair: {final_y_contribution, final_x_position} if starting from `x` and performing one full (step 2 then step 3) cycle.
// Or, more simply, `dp[x]` can store the result if we start at `x` and perform the operations.
// But the problem starts with `x=1`, then `x` becomes `1+a[1]`, then `x` becomes `(1+a[1]) - a[1+a[1]]`, etc.
// The `a[1]` value changes for each query.

// Let's define a function `solve(start_x, start_y_offset)` that computes the final `y` and `x` if we start at `start_x`
// and `y` has already accumulated `start_y_offset`.
// This is not quite right because `a[1]` is special.

// The problem asks for `n-1` queries. For each query `i`, `a[1]` is set to `i`.
// The values `a[2], ..., a[n]` are fixed.
// Let's define `dp[x]` as the pair `{final_y_delta, final_x_pos}` if we start at `x` and perform one full cycle (step 2 then step 3).
// This is not quite right either. The `a[x]` value changes.

// Let's define `dp[x][0]` as the final `y` value and `dp[x][1]` as the final `x` value
// if we start at `x` and perform the operations until termination.
// This is for a fixed `a` array.
// The `a[1]` value changes for each query.
// So, `dp[x]` can only be precomputed for `x > 1`.
// For `x=1`, `a[1]` is `i`.

// Let `memo[x]` store the result for starting at `x` with the fixed `a_2, ..., a_n`.
// `memo[x]` will be a pair `{total_y_added, final_x_position}`.
// `memo[x].first` is the sum of `a_val`s added to `y` from `x` until termination.
// `memo[x].second` is the `x` position where it terminates.
// If `memo[x].second` is 0, it means it terminates at `x <= 0`.
// If `memo[x].second` is `n+1`, it means it terminates at `x > n`.
// If `memo[x].second` is -1, it means it loops.

// Initialize `memo` with a special value indicating not computed, e.g., `{-2, -2}`.
// `visited` array to detect cycles during DFS. `visited[x] = true` means currently in recursion stack.

std::vector<long long> a_vals;
std::vector<std::pair<long long, int>> memo; // memo[x] = {total_y_added, final_x_pos}
std::vector<bool> visited; // To detect cycles

int N;

// Function to compute the result for a given starting x.
// This function assumes a_vals[x-1] is the value to use.
// It returns {total_y_added, final_x_pos}.
// final_x_pos: 0 for x <= 0, N+1 for x > N, -1 for loop.
std::pair<long long, int> compute_result(int current_x) {
    // Base cases for termination
    if (current_x <= 0) {
        return {0, 0};
    }
    if (current_x > N) {
        return {0, N + 1};
    }

    // Check memoization table
    if (memo[current_x].first != -2) { // -2 indicates not computed
        return memo[current_x];
    }

    // Detect cycle
    if (visited[current_x]) {
        return memo[current_x] = {-1, -1}; // Mark as looping
    }

    visited[current_x] = true;

    long long val_at_x = a_vals[current_x - 1];

    // Step 2: x = x + a[x], y = y + a[x]
    int next_x_after_step2 = current_x + val_at_x;
    long long y_added_step2 = val_at_x;

    // Check termination after step 2
    if (next_x_after_step2 <= 0) {
        visited[current_x] = false;
        return memo[current_x] = {y_added_step2, 0};
    }
    if (next_x_after_step2 > N) {
        visited[current_x] = false;
        return memo[current_x] = {y_added_step2, N + 1};
    }

    // Step 3: x = x - a[x], y = y + a[x]
    // The a[x] here is a[next_x_after_step2]
    long long val_at_next_x = a_vals[next_x_after_step2 - 1];
    int next_x_after_step3 = next_x_after_step2 - val_at_next_x;
    long long y_added_step3 = val_at_next_x;

    // Recursively compute for the next state
    std::pair<long long, int> res_from_next_state = compute_result(next_x_after_step3);

    visited[current_x] = false; // Backtrack

    if (res_from_next_state.second == -1) { // Loop detected
        return memo[current_x] = {-1, -1};
    } else {
        return memo[current_x] = {y_added_step2 + y_added_step3 + res_from_next_state.first, res_from_next_state.second};
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    a_vals.resize(N); // a_vals[0] will be a_1, a_vals[1] will be a_2, etc.
                      // Problem gives a_2 to a_n, so a_vals[1] to a_vals[N-1] are fixed.
                      // a_vals[0] (which is a_1) changes for each query.

    for (int i = 1; i < N; ++i) { // Read a_2, ..., a_n
        std::cin >> a_vals[i];
    }

    // Initialize memoization table and visited array for fixed a_2...a_n part
    // memo[0] is unused, memo[1] is for a_1, memo[2] for a_2, etc.
    // We only need to precompute for x > 1.
    // For x=1, a_vals[0] (a_1) changes.
    memo.resize(N + 1, {-2, -2}); // {y_added, final_x_pos}. -2 means not computed.
    visited.resize(N + 1, false);

    // Precompute results for starting positions x from 2 to N.
    // These results are independent of a_1.
    for (int i = 2; i <= N; ++i) {
        if (memo[i].first == -2) { // If not already computed (e.g., by another path)
            compute_result(i);
        }
    }

    // Now, for each query i (1 to N-1), set a_1 = i and run the program.
    for (int i = 1; i < N; ++i) {
        a_vals[0] = i; // Set a_1 to current query value

        long long current_y = 0;
        int current_x = 1;

        // Step 2: x = x + a[x], y = y + a[x]
        long long val_at_x_initial = a_vals[current_x - 1]; // This is a_1
        current_x += val_at_x_initial;
        current_y += val_at_x_initial;

        // Check termination after step 2
        if (current_x <= 0) {
            std::cout << current_y << "\n";
            continue;
        }
        if (current_x > N) {
            std::cout << current_y << "\n";
            continue;
        }

        // Step 3: x = x - a[x], y = y + a[x]
        // The a[x] here is a[current_x]
        long long val_at_current_x = a_vals[current_x - 1];
        current_x -= val_at_current_x;
        current_y += val_at_current_x;

        // Now, current_x is the state after the first full (step 2 then step 3) cycle.
        // From this point, the behavior is independent of the initial a_1.
        // We can use the precomputed memo table.

        if (current_x <= 0) {
            std::cout << current_y << "\n";
        } else if (current_x > N) {
            std::cout << current_y << "\n";
        } else {
            std::pair<long long, int> res = memo[current_x];
            if (res.second == -1) { // Loop detected
                std::cout << -1 << "\n";
            } else {
                std::cout << current_y + res.first << "\n";
            }
        }
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm>

// Function to convert a number to its parity pattern string
// The pattern is always 18 characters long, padded with '0's from the left.
// '0' for even digits, '1' for odd digits.
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the right to make it 18 characters long
    // This corresponds to padding with '0's (even digits) from the left in the number itself.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // A map to store counts of each parity pattern string
    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            counts[pattern]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the left to make it 18 characters long
            // This corresponds to padding with '0's (even digits) from the right in the pattern string.
            std::string query_pattern = s;
            std::reverse(query_pattern.begin(), query_pattern.end()); // Reverse to match get_parity_pattern's right-to-left digit processing
            while (query_pattern.length() < 18) {
                query_pattern += '0';
            }
            std::cout << counts[query_pattern] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> a(n);
    std::vector<long long> current_add(n, 0);

    // Initialize a_i to a very small value to satisfy max constraints
    // We want to find the largest possible a_i that satisfies all constraints.
    // For type 2 operations, max(a_j + current_add_j) = m_i.
    // This implies a_j + current_add_j <= m_i for all j in [l_i, r_i].
    // So, a_j <= m_i - current_add_j.
    // We can initialize a_j to a large negative value and then take min.
    // However, the problem asks for *any* suitable array.
    // A simpler approach is to initialize a_i to m_i - current_add_j for the first type 2 op that covers it.
    // But current_add_j depends on type 1 ops *before* the type 2 op.
    // This suggests processing operations in reverse.

    // Let's try to find the maximum possible initial values for a_i.
    // We can initialize a_i to a large value and then reduce it.
    // The maximum possible value for a_i is constrained by type 2 operations.
    // For each type 2 operation (l, r, m), for any j in [l, r],
    // a_j + sum_of_d_up_to_this_point <= m.
    // So, a_j <= m - sum_of_d_up_to_this_point.
    // We want to find the largest possible a_j that satisfies this for all relevant type 2 ops.
    // This means a_j = min(m - sum_of_d_up_to_this_point) over all type 2 ops covering j.

    // To calculate sum_of_d_up_to_this_point efficiently for each j and each operation:
    // We can iterate through operations in reverse.
    // When we encounter a type 1 op (l, r, d), it means that for all elements j in [l, r],
    // their effective value was d less *before* this operation.
    // When we encounter a type 2 op (l, r, m), it means that for all elements j in [l, r],
    // their initial value a_j must satisfy a_j <= m - current_add_j.
    // We want to maximize a_j, so we take the minimum of these upper bounds.

    std::vector<long long> initial_a(n, std::numeric_limits<long long>::max());
    std::vector<long long> current_delta(n, 0); // This accumulates d values for elements

    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] -= ops[i].val; // This d was applied *after* this point
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val + current_delta[j]);
            }
        }
    }

    // If any initial_a[j] is still max_long_long, it means it was never constrained by a type 2 op.
    // We can set it to 0 (or any value within bounds).
    // The problem states |a_i| <= 10^9.
    // Let's set unconstrained values to 0.
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == std::numeric_limits<long long>::max()) {
            initial_a[i] = 0;
        }
        // Check if initial_a[i] is within bounds
        if (initial_a[i] < -1000000000LL || initial_a[i] > 1000000000LL) {
            // This case should ideally not happen if a solution exists,
            // as m_i are within 5*10^7 and d_i are within 10^4.
            // The maximum number of operations is 5000.
            // Max possible delta is 5000 * 10^4 = 5*10^7.
            // So m_i + delta_j is roughly 5*10^7 + 5*10^7 = 10^8, which is within 10^9.
            // If it happens, it means no solution.
            // For safety, we can print NO, but based on constraints, it might not be necessary.
            // Let's assume it won't exceed 10^9 if a solution exists.
        }
    }

    // Now, verify the solution with the calculated initial_a
    std::vector<long long> test_a = initial_a;
    std::vector<long long> diff(n + 1, 0); // For prefix sums to apply type 1 ops

    for (const auto& op : ops) {
        if (op.type == 1) {
            diff[op.l] += op.val;
            if (op.r + 1 < n) {
                diff[op.r + 1] -= op.val;
            }
        } else { // type 2
            long long current_val_sum = 0;
            for (int j = 0; j < n; ++j) {
                current_val_sum += diff[j];
                test_a[j] = initial_a[j] + current_val_sum;
            }

            long long max_val = std::numeric_limits<long long>::min();
            for (int j = op.l; j <= op.r; ++j) {
                max_val = std::max(max_val, test_a[j]);
            }

            if (max_val != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

