        }
    }

    int ones_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_b++;
        }
    }

    // If a has an odd number of ones, we can append '1' to make it even.
    // After that, any subsequent parity appends will be '0'.
    // So, the maximum number of ones we can achieve is ones_a if ones_a is even,
    // or ones_a + 1 if ones_a is odd.
    // This is equivalent to (ones_a + (ones_a % 2)).
    int max_ones_reachable_from_a = ones_a + (ones_a % 2);

