#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // Child i goes to the dentist

        long long current_cry_volume = children[i].v;
        long long accumulated_d_cry = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_cry from previous children who ran away
            children[j].p -= accumulated_d_cry;

            // Apply current child's v_cry
            if (current_cry_volume > 0) {
                children[j].p -= current_cry_volume;
                current_cry_volume--;
            }

            // Check if child j runs away
            if (children[j].p < 0) {
                children[j].in_line = false;
                accumulated_d_cry += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    long long min_goodness = -1;
    std::vector<int> best_partition(n);

    // Case 1: All elements in one subsequence (e.g., all 1s)
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    min_goodness = (a[n - 2].value + a[n - 1].value) - (a[0].value + a[1].value);
    for (int i = 0; i < n; ++i) {
        best_partition[a[i].original_index] = 1;
    }

    // Case 2: a[0] in one subsequence, all others in another
    // min_f:
    //   - a[0] + a[1] + h (different subsequences)
    //   - a[1] + a[2] (same subsequence)
    //   So, min_f = min(a[0].value + a[1].value + h, a[1].value + a[2].value)
    // max_f:
    //   - a[n-2] + a[n-1] (same subsequence)
    //   - a[0] + a[n-1] + h (different subsequences)
    //   So, max_f = max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h)
    // This case is only relevant if n >= 3. If n=2, this is same as Case 1.
    if (n >= 3) {
        long long current_min_f = std::min(a[0].value + a[1].value + h, a[1].value + a[2].value);
        long long current_max_f = std::max(a[n - 2].value + a[n - 1].value, a[0].value + a[n - 1].value + h);
        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition[a[0].original_index] = 1;
            for (int i = 1; i < n; ++i) {
                best_partition[a[i].original_index] = 2;
            }
        }
    }

    // Case 3: a[n-1] in one subsequence, all others in another
    // min_f:
    //   - a[0] + a[1] (same subsequence)
    //   - a[0] + a[n-1] + h (different subsequences)
    //   So, min_f = min(a[0].value + a[1].value, a[0].value + a[n-1].value + h)
    // max_f:
    //   - a[n-2] + a[n-1] + h (different subsequences)
    //   - a[n-3] + a[n-2] (same subsequence)
    //   So, max_f = max(a[n-2].value + a[n-1].value + h, a[n-3].value + a[n-2].value)
    // This case is only relevant if n >= 3. If n=2, this is same as Case 1.
    if (n >= 3) {
        long long current_min_f = std::min(a[0].value + a[1].value, a[0].value + a[n - 1].value + h);
        long long current_max_f = std::max(a[n - 3].value + a[n - 2].value, a[n - 2].value + a[n - 1].value + h);
        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition[a[n - 1].original_index] = 1;
            for (int i = 0; i < n - 1; ++i) {
                best_partition[a[i].original_index] = 2;
            }
        }
    }

    // Case 4: a[0] and a[n-1] in one subsequence, all others in another
    // This is only relevant if n >= 4. If n=2, same as Case 1. If n=3, same as Case 2 or 3.
    if (n >= 4) {
        long long current_min_f = std::min({a[0].value + a[n-1].value, a[0].value + a[1].value + h, a[1].value + a[2].value});
        long long current_max_f = std::max({a[0].value + a[n-1].value, a[n-2].value + a[n-1].value + h, a[n-2].value + a[n-3].value});
        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            best_partition[a[0].original_index] = 1;
            best_partition[a[n-1].original_index] = 1;
            for (int i = 1; i < n-1; ++i) {
                best_partition[a[i].original_index] = 2;
            }
        }
    }


    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case 1: k = 1 (one cut)
    // Try all possible single cuts and rearrangements
    for (int i = 1; i < n; ++i) {
        std::string s_prefix = s.substr(0, i);
        std::string s_suffix = s.substr(i);
        std::string s_new = s_suffix + s_prefix;

        if (s_new != s && is_palindrome(s_new)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case 2: k = 2 (two cuts)
    // If no solution with k=1, check if a solution with k=2 exists.
    // A solution with k=2 always exists unless all characters in s are the same.
    // If all characters are the same, e.g., "aaaaa", then any rearrangement of pieces
    // will result in the same string "aaaaa", which is a palindrome but not different from s.
    // In this case, it's impossible.

    // Check if all characters in s are the same
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }

    if (all_same) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, a solution with k=2 always exists.
        // Example: s = "nolon"
        // Cut into "no" | "l" | "on"
        // Rearrange to "on" | "l" | "no" -> "onlno" (palindrome, != "nolon")
        // This can be achieved by cutting s into s[0...i-1], s[i...j-1], s[j...n-1]
        // and rearranging.
        // For any palindrome s that is not composed of all identical characters,
        // we can always find a way to make two cuts and rearrange to form a new palindrome.
        // For example, cut s into s[0...0], s[1...n-2], s[n-1...n-1].
        // Since s is a palindrome, s[0] == s[n-1].
        // Rearrange to s[n-1...n-1] + s[1...n-2] + s[0...0].
        // This forms s[n-1] + s[1...n-2] + s[0].
        // Since s[0] == s[n-1], this is equivalent to s[0] + s[1...n-2] + s[0].
        // This is a palindrome.
        // If this new string is different from s, we have a solution with k=2.
        // If it's the same as s, it means s[0] + s[1...n-2] + s[0] == s[0] + s[1...n-2] + s[n-1].
        // This is always true.
        // The key is that if not all characters are the same, there must be at least two distinct characters.
        // Since s is a palindrome, if s[0] != s[1], then s[n-1] != s[n-2].
        // Consider cutting s into s[0...i-1] and s[i...n-1].
        // If s_new = s[i...n-1] + s[0...i-1] is not a palindrome or is equal to s,
        // we need more cuts.
        // The problem statement implies that if k=1 doesn't work and not all chars are same, k=2 works.
        // This is a known property for palindromes. If a palindrome is not monochromatic,
        // it can always be rearranged with 2 cuts to form a different palindrome.
        // For example, take s = "abacaba".
        // Cut "a" | "bacab" | "a". Rearrange to "a" | "bacab" | "a" -> "abacaba" (same).
        // Cut "ab" | "aca" | "ba". Rearrange to "ba" | "aca" | "ab" -> "baacaab" (palindrome, different).
        // This requires 2 cuts.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0;
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) { // All tracks covered
            return true;
        }

        long long current_h = h[h_idx];
        long long min_reach = current_h - T;
        long long max_reach = current_h + T;

        // Find the first track p[p_idx] that can be covered by current_h
        // This means p[p_idx] must be within [min_reach, max_reach]
        // If p[p_idx] < min_reach, this head cannot cover it, and previous heads should have covered it.
        // If p[p_idx] > max_reach, this head cannot cover it, and we need to move to the next head.
        // Since p is sorted, if p[p_idx] > max_reach, then all subsequent p's will also be > max_reach.
        // So this head cannot cover p[p_idx] or any subsequent tracks.
        // This implies that if p[p_idx] > max_reach, this head is "too far left" for p[p_idx].
        // This logic is flawed. We need to cover p[p_idx] using *some* head.

        // Correct greedy approach:
        // For each head, cover as many *uncovered* tracks as possible, starting from the leftmost uncovered track.
        // If p[p_idx] is the first uncovered track:
        // 1. If current_h can't reach p[p_idx] (i.e., p[p_idx] > current_h + T), then this head is too far left.
        //    It means p[p_idx] cannot be covered by current_h, nor by any h_k where k < h_idx.
        //    So, p[p_idx] cannot be covered at all. This T is not enough.
        // 2. If current_h can reach p[p_idx] (i.e., p[p_idx] <= current_h + T):
        //    This head can cover p[p_idx].
        //    To maximize coverage for subsequent tracks, this head should cover p[p_idx] and then extend its reach
        //    as far right as possible.
        //    The effective range covered by this head, starting from p[p_idx], would be
        //    [p[p_idx], current_h + T].
        //    However, the head must also be able to reach p[p_idx].
        //    The actual range covered by this head is [current_h - T, current_h + T].
        //    If p[p_idx] is the first uncovered track, and current_h can reach it,
        //    then this head will cover p[p_idx] and all tracks p_k such that p_k <= current_h + T.
        //    The crucial part is that the head must be able to reach p[p_idx].
        //    So, p[p_idx] must be in [current_h - T, current_h + T].
        //    If p[p_idx] < current_h - T, it means p[p_idx] is too far left for current_h.
        //    This implies that p[p_idx] should have been covered by a previous head.
        //    But since p_idx is the first *uncovered* track, this means it wasn't covered.
        //    This scenario should not happen if previous heads were used optimally.

        // Let's refine the greedy strategy:
        // Iterate through heads. For each head h_idx:
        // If all tracks are already covered (p_idx == m), return true.
        // If the current head h[h_idx] cannot reach the current target track p[p_idx]
        // (i.e., p[p_idx] > h[h_idx] + T), then this head is too far left to cover p[p_idx].
        // Since h is sorted, all previous heads h[k] (k < h_idx) are even further left or at the same position,
        // so they also couldn't cover p[p_idx] (or they would have).
        // Thus, p[p_idx] cannot be covered. Return false.
        // If h[h_idx] *can* reach p[p_idx] (i.e., p[p_idx] <= h[h_idx] + T):
        // This head can cover p[p_idx].
        // The head can move to any position in [h[h_idx] - T, h[h_idx] + T].
        // To cover p[p_idx] and maximize coverage to the right, the head should move to p[p_idx]
        // and then cover tracks up to p[p_idx] + (T - abs(h[h_idx] - p[p_idx])).
        // This is equivalent to saying the head can cover any track in [h[h_idx] - T, h[h_idx] + T].
        // So, it covers all tracks p_k such that p_k >= p[p_idx] and p_k <= h[h_idx] + T.
        // We advance p_idx past all tracks covered by this head.

        // The key is that a head h_i can cover a range [L, R] where L = h_i - T and R = h_i + T.
        // We need to cover all p_j.
        // We iterate through the target tracks `p_idx`.
        // For each `p[p_idx]`, we need to find a head that covers it.
        // We use the leftmost available head `h[h_idx]` that can cover `p[p_idx]`.
        // If `h[h_idx]` is too far right to cover `p[p_idx]` (i.e., `h[h_idx] - T > p[p_idx]`),
        // then this `h[h_idx]` cannot cover `p[p_idx]`.
        // This means `p[p_idx]` must be covered by a head `h_k` where `k < h_idx`.
        // But we are processing heads in order. This implies `h[h_idx]` is the current head we are considering.
        // If `h[h_idx] - T > p[p_idx]`, then `p[p_idx]` is to the left of `h[h_idx]`'s leftmost reach.
        // This means `p[p_idx]` must have been covered by a previous head.
        // If `p[p_idx]` is the first *uncovered* track, and `h[h_idx] - T > p[p_idx]`,
        // then `p[p_idx]` cannot be covered by `h[h_idx]` or any subsequent heads.
        // This is incorrect. We should use `h[h_idx]` to cover `p[p_idx]` if possible.

        // Let's use a two-pointer approach:
        // `p_idx` points to the first track not yet covered.
        // `h_idx` points to the current head we are trying to use.
        // While `p_idx < m`:
        //   If `h_idx == n` (no more heads), return false.
        //   If `h[h_idx]` can cover `p[p_idx]` (i.e., `h[h_idx] - T <= p[p_idx] <= h[h_idx] + T`):
        //     This head `h[h_idx]` can cover `p[p_idx]`.
        //     It can also cover all tracks up to `h[h_idx] + T`.
        //     So, advance `p_idx` past all tracks `p_k` such that `p_k <= h[h_idx] + T`.
        //     Then move to the next head: `h_idx++`.
        //   Else (`h[h_idx]` cannot cover `p[p_idx]`):
        //     If `p[p_idx] < h[h_idx] - T`:
        //       This means `p[p_idx]` is too far left for `h[h_idx]`.
        //       Since `h` is sorted, `p[p_idx]` is also too far left for any `h_k` where `k > h_idx`.
        //       This implies `p[p_idx]` should have been covered by a previous head.
        //       But `p[p_idx]` is the first *uncovered* track. So it's impossible to cover `p[p_idx]`. Return false.
        //     If `p[p_idx] > h[h_idx] + T`:
        //       This means `h[h_idx]` is too far left for `p[p_idx]`.
        //       We need to use a head further to the right. So, move to the next head: `h_idx++`.
        //       (This head `h[h_idx]` cannot cover `p[p_idx]`, and it cannot cover any `p_k` where `k > p_idx` either,
        //       because `p_k >= p[p_idx] > h[h_idx] + T`. So this head is useless for `p[p_idx]` and beyond.)

    int current_p_idx = 0;
    for (int current_h_idx = 0; current_h_idx < n; ++current_h_idx) {
        if (current_p_idx == m) {
            break; // All tracks covered
        }

        long long head_pos = h[current_h_idx];
        long long head_left_reach = head_pos - T;
        long long head_right_reach = head_pos + T;

        // If the current head cannot reach the current target track p[current_p_idx] from its left side,
        // meaning p[current_p_idx] is too far left for this head.
        // Since p is sorted, and h is sorted, this means p[current_p_idx] should have been covered by a previous head.
        // If it wasn't, then it's impossible to cover.
        if (p[current_p_idx] < head_left_reach) {
            return false;
        }

        // If the current head can reach p[current_p_idx] (i.e., p[current_p_idx] >= head_left_reach),
        // then this head can cover p[current_p_idx] and all subsequent tracks
        // that are within its right reach (head_right_reach).
        // We advance current_p_idx past all tracks covered by this head.
        while (current_p_idx < m && p[current_p_idx] <= head_right_reach) {
            current_p_idx++;
        }
    }

    return current_p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible distance: (10^10 - 1) + (10^10 - 1) approx 2*10^10
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

