#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substring_count = 0;

    // Precompute prefix sums of '0's
    std::vector<int> prefix_zeros(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_zeros[i + 1] = prefix_zeros[i];
        if (s[i] == '0') {
            prefix_zeros[i + 1]++;
        }
    }

    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            continue; // A good substring cannot start with '0' unless its value is 0, but length must be positive.
                      // The problem statement implies f(t) is positive for non-zero t.
                      // If f(000) = 0, then length must be 0, which is not possible for a substring.
                      // So, a good substring must have f(s_l...s_r) > 0, meaning it must contain at least one '1'.
                      // If it starts with '0', it must have a '1' later.
                      // However, the problem example s_2...s_4 = 011 is good. Here l=2, s[1]='0'.
                      // So, we must iterate over all possible starting positions.
        }

        long long current_val = 0;
        for (int j = i; j < n; ++j) {
            // Check for overflow before multiplying by 2
            if (current_val > (2LL * n + 1) / 2) { // Max possible length is N. Max value to check is N.
                                                  // If current_val * 2 > N, it's too large.
                                                  // (2LL * n + 1) / 2 is a safe upper bound for current_val to avoid overflow
                                                  // when current_val * 2 is computed, and to ensure current_val * 2 <= 2N.
                                                  // More precisely, if current_val > N, then current_val * 2 > 2N, which is too large.
                                                  // If current_val > N/2, then current_val * 2 > N.
                                                  // We are interested in values up to N.
                                                  // If current_val already exceeds N, then any further multiplication will also exceed N.
                                                  // The maximum length is N. So f(s_l...s_r) cannot exceed N.
                                                  // If current_val > N, we can break.
                break;
            }

            current_val = current_val * 2 + (s[j] - '0');

            if (current_val == 0) { // If the substring is all zeros, e.g., "000"
                // f("000") = 0. Length is 3. 3 != 0. Not good.
                // This case is implicitly handled by the check current_val == len.
                // If current_val is 0, it will only be good if len is 0, which is not possible.
                continue;
            }

            int len = j - i + 1;

            if (current_val > n) { // If the value is already greater than max possible length, break.
                break;
            }

            if (current_val == len) {
                good_substring_count++;
            } else if (current_val < len) {
                // If current_val < len, it means the binary value is too small for its length.
                // This can only happen if the substring starts with '0's.
                // Example: s_l...s_r = "011", len=3, val=3. Good.
                // Example: s_l...s_r = "001", len=3, val=1. Not good.
                // We need to check if we can prepend some '0's to make it good.
                // The actual substring starts at index `i`.
                // The current substring being evaluated is `s[i...j]`.
                // Its length is `len = j - i + 1`. Its value is `current_val`.
                // We are looking for a substring `s[k...j]` where `k < i`.
                // The length of `s[k...j]` would be `j - k + 1`.
                // The value `f(s[k...j])` would be `f(s[i...j])` because leading zeros don't change the value.
                // So we need `j - k + 1 == current_val`.
                // This means `k = j + 1 - current_val`.
                // We need to check if `k` is a valid starting index, i.e., `0 <= k < i`.
                // And also, all characters `s[k...i-1]` must be '0'.

                int required_start_idx = j + 1 - static_cast<int>(current_val);

                if (required_start_idx >= 0 && required_start_idx < i) {
                    // Check if s[required_start_idx ... i-1] are all '0's.
                    // This can be done efficiently using prefix_zeros.
                    // Number of zeros in s[required_start_idx ... i-1] is
                    // prefix_zeros[i] - prefix_zeros[required_start_idx].
                    // The length of this prefix is i - required_start_idx.
                    if (prefix_zeros[i] - prefix_zeros[required_start_idx] == (i - required_start_idx)) {
                        good_substring_count++;
                    }
                }
            }
        }
    }

    std::cout << good_substring_count << std::endl;
}

