        if (a == b) {
            std::cout << 0 << "\n";
            continue;
        }
        long long diff = std::abs(a - b);
        long long presses = 0;

        // Greedy approach: prioritize larger denominations
        presses += diff / 5;
        diff %= 5;

        // For remaining diff (0, 1, 2, 3, 4)
        // If diff is 0, 1, 2: use 1s and 2s
        // If diff is 3, 4: it's optimal to use a 5 and then adjust
        //   e.g., for 3: 5 - 2 (2 presses) vs 1+1+1 (3 presses)
        //   e.g., for 4: 5 - 1 (2 presses) vs 2+2 (2 presses) vs 1+1+1+1 (4 presses)
        //   So for 3, 4, it's always 2 presses.
        //   For 1, 2, it's 1 press.
        //   For 0, it's 0 presses.

        if (diff == 1 || diff == 2) {
            presses += 1;
        } else if (diff == 3 || diff == 4) {
            presses += 2;
        }
        // If diff is 0, presses remains unchanged.

        std::cout << presses << "\n";
    }
    return 0;
}

