void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The strategy is to reverse the permutation.
    // If p = [p_1, p_2, ..., p_n], then p' = [p_n, p_{n-1}, ..., p_1].
    // The sums for p are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
    // The sums for p' are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
    // These are the same set of sums, just in reverse order.
    // Sorting them will yield the same fingerprint.
    // Since n >= 2, p is always different from p' unless p is a palindrome.
    // However, a permutation cannot be a palindrome unless n=1 (which is not allowed)
    // or n=2 and p=[1,2] or p=[2,1].
    // For n=2, p=[1,2], p'=[2,1]. They are different and have same fingerprint.
    // For n=2, p=[2,1], p'=[1,2]. They are different and have same fingerprint.
    // For n > 2, a permutation cannot be a palindrome.
    // For example, if p = [p_1, ..., p_k, ..., p_n] and p_i = p_{n-i+1} for all i.
    // Then p_1 = p_n. But p_1 and p_n must be distinct elements from 1 to n.
    // This is only possible if n=1, which is not allowed.
    // So, for n >= 2, reversing a permutation always yields a different permutation.

    std::vector<int> p_prime(n);
    for (int i = 0; i < n; ++i) {
        p_prime[i] = p[n - 1 - i];
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p_prime[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

