        b_items[i].original_index = i;
    }

    // Sort both vectors based on their values
    std::sort(a_items.begin(), a_items.end(), compareItems);
    std::sort(b_items.begin(), b_items.end(), compareItems);

    // The strategy is to pair the i-th smallest necklace with the (i-k)-th smallest bracelet
    // where k is some constant.
    // A simple strategy that works is to pair the i-th smallest necklace with the i-th smallest bracelet.
    // This is equivalent to sorting both arrays and then printing them in sorted order.
    // The problem statement guarantees that an answer always exists.
    // The example output for the second test case suggests a different pairing,
    // but the simplest pairing (sorted a with sorted b) is often a good first guess.
    // Let's try printing sorted a and sorted b.

    // Output the sorted necklace brightnesses
    for (int i = 0; i < n; ++i) {
        std::cout << a_items[i].value << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    // Output the sorted bracelet brightnesses
    for (int i = 0; i < n; ++i) {
        std::cout << b_items[i].value << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

