#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long d; // d can be up to 100, but total days spent can exceed int if n is large and a_i are large.
                 // However, n, a_i are up to 100, so max days needed for one pile is (100-1)*100 = 9900.
                 // Total days d is up to 100. So d fits in int.
                 // Let's keep d as long long to be safe, though int is fine for d.
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0]; // Initial haybales in pile 1

    // Iterate through piles from 2nd to nth (index 1 to n-1)
    for (int i = 1; i < n; ++i) {
        long long pile_idx = i + 1; // Pile number (1-indexed)
        long long cost_per_haybale = pile_idx - 1; // Days to move one haybale from pile_idx to pile 1

        if (cost_per_haybale == 0) { // This should only happen for pile 1 itself, which is skipped
            continue;
        }

        // Calculate how many haybales can be moved from this pile
        // based on remaining days
        long long haybales_can_move_by_days = d / cost_per_haybale;

        // The actual number of haybales we can move is limited by
        // 1. The number of haybales in the current pile (a[i])
        // 2. The number of haybales we can afford to move with remaining days
        long long haybales_to_move = std::min((long long)a[i], haybales_can_move_by_days);

        current_a1 += haybales_to_move;
        d -= haybales_to_move * cost_per_haybale;

        if (d <= 0) { // If days run out, no more moves are possible
            break;
        }
    }

    std::cout << current_a1 << std::endl;
}

