int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        long long T;
        std::cin >> n >> T;
        std::vector<int> a(n);
        std::vector<int> p(n);
        int current_color_for_half = 0; // 0 for white, 1 for black

        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < T / 2.0) { // Using 2.0 for float division to handle T being odd
                p[i] = 0; // Assign to white (color 0)
            } else if (a[i] > T / 2.0) {
                p[i] = 1; // Assign to black (color 1)
            } else { // a[i] == T / 2.0, i.e., a[i] * 2 == T
                // For elements equal to T/2, alternate colors
                p[i] = current_color_for_half;
                current_color_for_half = 1 - current_color_for_half; // Flip color for next T/2 element
            }
        }

        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

int main() {
    // Optimize C++ standard streams for competitive programming.
    // Unties cin/cout from C stdio and disables synchronization.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t; // Number of test cases
    std::cin >> t;
    while (t--) {
        int n; // Number of days
        std::cin >> n;
        std::vector<int> a(n); // Prices for n days
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        if (n == 0) { // Edge case: no days, no bad prices
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0; // Counter for bad prices
        // Initialize min_price_suffix with the last day's price.
        // The last day's price can never be bad as there are no days after it.
        int min_price_suffix = a[n - 1]; 

        // Iterate from the second to last day down to the first day
        for (int i = n - 2; i >= 0; --i) {
            // If the current day's price is greater than the minimum price
            // found in any subsequent day, then it's a bad price.
            if (a[i] > min_price_suffix) {
                bad_prices_count++;
            } else {
                // If the current day's price is not greater, it means it's
                // either equal to or less than the current min_price_suffix.
                // In this case, this price becomes the new minimum for
                // any days before it.
                min_price_suffix = a[i];
            }
        }
        std::cout << bad_prices_count << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_gap = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' encountered, or -1 for cell 0.
                             // If last_r_pos is -1, it means the frog is at cell 0.
                             // If last_r_pos is k, it means the frog is at cell k.
                             // The next 'R' must be at least last_r_pos + 1.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // Current cell is i+1 (1-indexed).
                // The distance from the previous 'R' (or cell 0) to this 'R' is (i+1) - (last_r_pos + 1) + 1
                // which simplifies to (i+1) - last_r_pos.
                // If last_r_pos was -1 (meaning we were at cell 0), the distance is (i+1) - (-1) = i+2.
                // If last_r_pos was k (meaning we were at cell k), the distance is (i+1) - k.
                // This is the length of the segment of 'L's plus one 'R' at the end.
                // The actual gap is (i+1) - last_r_pos.
                max_gap = std::max(max_gap, (i + 1) - (last_r_pos + 1) + 1);
                last_r_pos = i;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' to cell n+1.
        // If last_r_pos was k, the jump is from cell k+1 to cell n+1.
        // The distance is (n+1) - (last_r_pos + 1) + 1.
        // If last_r_pos was -1 (no 'R's in the string), the jump is from cell 0 to cell n+1.
        // The distance is (n+1) - 0 = n+1.
        max_gap = std::max(max_gap, (n + 1) - (last_r_pos + 1) + 1);

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;
        while (low <= high) {
            long long mid = low + (high - low) / 2;
            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians as minimums.
            // Remaining coders: c - mid
            // Remaining mathematicians: m - mid
            // Remaining students without specialization: x
            // Total remaining students to fill the 3-member requirement:
            // Each team needs 3 members. 'mid' teams need 3 * mid members.
            // We've already accounted for 'mid' coders and 'mid' mathematicians.
            // So, 2 * mid members are already assigned (one C, one M for each team).
            // We need 'mid' more members to fill the teams (3 * mid - 2 * mid = mid).
            // These 'mid' additional members can come from remaining coders,
            // remaining mathematicians, or students without specialization.
            // Total available for these 'mid' additional spots:
            // (c - mid) + (m - mid) + x
            if (c >= mid && m >= mid && (c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
