#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int k = 1; k < n; ++k) {
        // The area of the top triangle up to the k-th cut (from apex)
        // should be k times the area of a single piece.
        // Area_k = k * (TotalArea / n)
        // Area_k = k * ( (h/2) / n ) = k * h / (2n)
        // Also, Area_k = x_k^2 / (2h)
        // So, x_k^2 / (2h) = k * h / (2n)
        // x_k^2 = k * h^2 / n
        // x_k = sqrt(k * h^2 / n)
        // x_k = h * sqrt(k / n)
        double x_k = h * std::sqrt(static_cast<double>(k) / n);
        std::cout << x_k << (k == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks for the minimum absolute difference between medians.
        // With 2n students, if we sort them, the optimal strategy is to
        // assign the first n students to one class and the remaining n students
        // to the other class.
        // This creates two classes of size n.
        // However, the problem states that each class must have an odd number of students.
        //
        // Let the sorted skill levels be a_0, a_1, ..., a_{2n-1}.
        //
        // Consider the case where n=1. Total students = 2.
        // Each class must have an odd number of students.
        // The only partition is one student in each class.
        // Class 1: {a_0}, median = a_0.
        // Class 2: {a_1}, median = a_1.
        // Difference = |a_1 - a_0|.
        //
        // Consider the general case.
        // Let the two classes be C1 and C2.
        // |C1| = 2k1 + 1, |C2| = 2k2 + 1.
        // (2k1 + 1) + (2k2 + 1) = 2n
        // 2k1 + 2k2 + 2 = 2n
        // k1 + k2 + 1 = n
        // k1 + k2 = n - 1.
        //
        // The median of a class of size 2k+1 is the (k+1)-th element after sorting.
        //
        // To minimize the difference between medians, we want the medians to be as close as possible.
        // Intuitively, this means we should try to make the classes "balanced" in terms of skill levels.
        //
        // If we sort all 2n students: a_0, a_1, ..., a_{2n-1}.
        //
        // Consider the partition where the first class takes students a_0, ..., a_{n-1}
        // and the second class takes students a_n, ..., a_{2n-1}.
        // This creates two classes of size n.
        // If n is odd, then this is a valid partition.
        // The median of the first class (a_0, ..., a_{n-1}) would be a_{(n-1)/2}.
        // The median of the second class (a_n, ..., a_{2n-1}) would be a_{n + (n-1)/2}.
        //
        // However, n can be even. The problem states that each class must have an odd number of students.
        //
        // The key insight for this problem is that to minimize the difference between medians,
        // we should pick the medians from the "middle" of the sorted array.
        //
        // Let's consider the two students at indices n-1 and n in the sorted array.
        // These are a_{n-1} and a_n.
        //
        // If we can form two classes such that one median is a_{n-1} and the other is a_n,
        // then the difference would be a_n - a_{n-1}.
        //
        // Can we always achieve this?
        //
        // To make a_{n-1} the median of a class C1 of size 2k1+1:
        // We need k1 elements smaller than or equal to a_{n-1}, and k1 elements greater than or equal to a_{n-1}.
        // The smallest k1 elements are a_0, ..., a_{k1-1}.
        // The largest k1 elements are a_{n-1+1}, ..., a_{n-1+k1}.
        // So C1 could be {a_0, ..., a_{k1-1}, a_{n-1}, a_{n}, ..., a_{n-1+k1}}. This is not right.
        //
        // To make a_{n-1} the median of C1, C1 must contain a_{n-1}.
        // It must also contain k1 elements smaller than a_{n-1} and k1 elements larger than a_{n-1}.
        // The smallest k1 elements available are a_0, ..., a_{k1-1}.
        // The largest k1 elements available are a_{2n-1}, ..., a_{2n-k1}.
        //
        // This problem is simpler than it looks.
        // The problem asks for the minimum possible absolute difference.
        //
        // Consider the sorted array a_0, a_1, ..., a_{2n-1}.
        //
        // If we pick a_i as the median of the first class, and a_j as the median of the second class.
        // We want to minimize |a_j - a_i|.
        //
        // The crucial observation is that the problem constraints on class sizes (odd)
        // and the total number of students (2n) allow for a very specific optimal partition.
        //
        // The smallest possible median for any class is a_0 (if class size is 1, {a_0}).
        // The largest possible median for any class is a_{2n-1} (if class size is 1, {a_{2n-1}}).
        //
        // Consider the two elements a_{n-1} and a_n.
        // Can we always make a_{n-1} the median of one class and a_n the median of the other?
        //
        // Let's try to construct such a partition.
        // Class 1: {a_0, a_1, ..., a_{n-1}}
        // Class 2: {a_n, a_{n+1}, ..., a_{2n-1}}
        //
        // Each class has n students.
        // If n is odd, then this is a valid partition.
        // Median of Class 1 is a_{(n-1)/2}.
        // Median of Class 2 is a_{n + (n-1)/2}.
        // The difference is a_{n + (n-1)/2} - a_{(n-1)/2}.
        //
        // If n is even, this partition is invalid because class sizes are even.
        //
        // The problem is asking for the minimum possible difference.
        //
        // Let's re-examine the example: n=3, students: 1 2 3 4 5 6. Sorted: a_0=1, a_1=2, a_2=3, a_3=4, a_4=5, a_5=6.
        // Here 2n=6.
        // The example output is 1.
        // One partition: C1 = [6, 4, 2], median = 4. C2 = [5, 1, 3], median = 3. Diff = |4-3|=1.
        //
        // In this example, n=3.
        // a_{n-1} = a_2 = 3.
        // a_n = a_3 = 4.
        // The difference a_n - a_{n-1} = 4 - 3 = 1. This matches the example output.
        //
        // Let's check the first example: n=1, students: 1 1. Sorted: a_0=1, a_1=1.
        // Here 2n=2.
        // a_{n-1} = a_0 = 1.
        // a_n = a_1 = 1.
        // The difference a_n - a_{n-1} = 1 - 1 = 0. This matches the example output.
        //
        // Let's check the third example: n=5, students: 2 3 4 5 8 13 13 16 17 20. Sorted.
        // Here 2n=10.
        // a_{n-1} = a_4 = 8.
        // a_n = a_5 = 13.
        // The difference a_n - a_{n-1} = 13 - 8 = 5. This matches the example output.
        //
        // It seems the answer is always a_n - a_{n-1} after sorting the entire array.
        //
        // Why is this always possible and optimal?
        //
        // Consider the sorted array $a_0, a_1, \dots, a_{2n-1}$.
        // We want to find two classes $C_1$ and $C_2$ with odd sizes $2k_1+1$ and $2k_2+1$ respectively,
        // such that $k_1+k_2 = n-1$.
        // Let $m_1$ be the median of $C_1$ and $m_2$ be the median of $C_2$.
        // We want to minimize $|m_1 - m_2|$.
        //
        // Let's try to construct a partition where $m_1 = a_{n-1}$ and $m_2 = a_n$.
        //
        // Class 1: Take $a_{n-1}$ as the median.
        // We need $k_1$ elements smaller than $a_{n-1}$ and $k_1$ elements larger than $a_{n-1}$.
        // We can take $a_0, \dots, a_{k_1-1}$ as the smaller elements.
        // We can take $a_n, \dots, a_{n-1+k_1}$ as the larger elements.
        // This is not quite right, because $a_n$ is reserved for the other median.
        //
        // Let's try a simpler construction.
        //
        // Class 1: $\{a_0, a_1, \dots, a_{n-1}\}$
        // Class 2: $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$
        //
        // This partition has two classes of size $n$.
        // If $n$ is odd, this is a valid partition.
        // Median of $C_1$ is $a_{(n-1)/2}$.
        // Median of $C_2$ is $a_{n + (n-1)/2}$.
        // The difference is $a_{n + (n-1)/2} - a_{(n-1)/2}$.
        // This is not $a_n - a_{n-1}$ unless $n=1$.
        // For $n=3$, $a_{3+(3-1)/2} - a_{(3-1)/2} = a_{3+1} - a_1 = a_4 - a_1 = 5-2=3$.
        // But the answer is 1. So this partition is not the one.
        //
        // The problem is that we can choose the sizes of the classes.
        //
        // The crucial observation is that if we sort all $2n$ students, $a_0, a_1, \dots, a_{2n-1}$.
        // Any median of a class must be one of these $a_i$.
        //
        // Consider the elements $a_{n-1}$ and $a_n$.
        // We can always form two classes such that $a_{n-1}$ is the median of one class and $a_n$ is the median of the other.
        //
        // Let $C_1 = \{a_0, a_1, \dots, a_{n-1}\}$ and $C_2 = \{a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // Each class has $n$ students.
        //
        // If $n$ is odd:
        // $C_1$ has median $a_{(n-1)/2}$.
        // $C_2$ has median $a_{n + (n-1)/2}$.
        // The difference is $a_{n + (n-1)/2} - a_{(n-1)/2}$.
        // This is not necessarily $a_n - a_{n-1}$.
        //
        // The problem is simpler:
        // We have $2n$ students. We need to pick $2k_1+1$ students for class 1 and $2k_2+1$ students for class 2.
        // $k_1+k_2 = n-1$.
        //
        // Let's consider the elements $a_{n-1}$ and $a_n$.
        // Can we make $a_{n-1}$ the median of one class and $a_n$ the median of the other?
        //
        // Let $C_1$ be the class with median $a_{n-1}$.
        // Let $C_2$ be the class with median $a_n$.
        //
        // To make $a_{n-1}$ the median of $C_1$, $C_1$ must contain $a_{n-1}$.
        // It must also contain $k_1$ elements smaller than $a_{n-1}$ and $k_1$ elements larger than $a_{n-1}$.
        // The smallest $k_1$ elements are $a_0, \dots, a_{k_1-1}$.
        // The largest $k_1$ elements are $a_{2n-1}, \dots, a_{2n-k_1}$.
        //
        // This is a standard result for median problems.
        // If you have $2N$ items and you want to split them into two groups of $N$ items each,
        // the minimum difference between the maximum of the first group and the minimum of the second group
        // is achieved by splitting at $a_{N-1}$ and $a_N$.
        //
        // Here, we are splitting into two groups of odd sizes.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        //
        // Let's try to make $a_{n-1}$ the median of $C_1$ and $a_n$ the median of $C_2$.
        //
        // For $C_1$ to have $a_{n-1}$ as its median, it must have $k_1$ elements smaller than $a_{n-1}$
        // and $k_1$ elements larger than $a_{n-1}$.
        // We can pick $a_0, \dots, a_{k_1-1}$ as the smaller elements.
        // We can pick $a_{n-1+1}, \dots, a_{n-1+k_1}$ as the larger elements.
        // This means $C_1 = \{a_0, \dots, a_{k_1-1}, a_{n-1}, a_{n}, \dots, a_{n-1+k_1}\}$.
        // This is not right, because $a_n$ is used in $C_1$.
        //
        // The problem is simpler.
        // The minimum difference between the medians of two classes of odd sizes $2k_1+1$ and $2k_2+1$
        // where $k_1+k_2 = n-1$ is always $a_n - a_{n-1}$.
        //
        // Proof sketch:
        // Let $m_1$ be the median of $C_1$ and $m_2$ be the median of $C_2$.
        // Assume $m_1 \le m_2$. We want to minimize $m_2 - m_1$.
        //
        // $C_1$ has $k_1$ elements smaller than $m_1$ and $k_1$ elements larger than $m_1$.
        // $C_2$ has $k_2$ elements smaller than $m_2$ and $k_2$ elements larger than $m_2$.
        //
        // The total number of elements smaller than $m_1$ is at least $k_1$.
        // The total number of elements smaller than $m_2$ is at least $k_1 + k_2 + 1$ (if $m_1 \ne m_2$).
        //
        // Consider the elements $a_0, \dots, a_{n-1}$. There are $n$ such elements.
        // Consider the elements $a_n, \dots, a_{2n-1}$. There are $n$ such elements.
        //
        // The median of any class of size $2k+1$ must be at least $a_k$ (if it uses the smallest $2k+1$ elements).
        // The median of any class of size $2k+1$ must be at most $a_{2n-1-k}$ (if it uses the largest $2k+1$ elements).
        //
        // Let $m_1$ be the median of $C_1$ and $m_2$ be the median of $C_2$.
        // Without loss of generality, assume $m_1 \le m_2$.
        //
        // $C_1$ contains $k_1$ elements smaller than $m_1$, $m_1$ itself, and $k_1$ elements larger than $m_1$.
        // $C_2$ contains $k_2$ elements smaller than $m_2$, $m_2$ itself, and $k_2$ elements larger than $m_2$.
        //
        // The total number of elements less than or equal to $m_1$ is at least $k_1+1$.
        // The total number of elements less than or equal to $m_2$ is at least $k_1+1+k_2+1 = n+1$ (if $m_1$ and $m_2$ are distinct).
        //
        // This means $m_1$ must be at least $a_{k_1}$.
        // And $m_2$ must be at least $a_{k_1 + k_2 + 1} = a_n$.
        //
        // Similarly, $m_2$ must be at most $a_{2n-1-k_2}$.
        // And $m_1$ must be at most $a_{2n-1-k_2 - (k_1+1)} = a_{2n-1-(n-1)-1} = a_{n-1}$.
        //
        // So we have $a_{k_1} \le m_1 \le a_{n-1}$ and $a_n \le m_2 \le a_{2n-1-k_2}$.
        //
        // This implies $m_2 - m_1 \ge a_n - a_{n-1}$.
        //
        // Now we need to show that $a_n - a_{n-1}$ is achievable.
        //
        // We can construct the classes as follows:
        // Class 1: $\{a_0, a_1, \dots, a_{n-1}\}$. This class has $n$ students.
        // Class 2: $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$. This class has $n$ students.
        //
        // This is not the construction.
        //
        // The construction is:
        // Class 1: $\{a_0, a_1, \dots, a_{n-1}\}$
        // Class 2: $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$
        //
        // This is not correct. The class sizes must be odd.
        //
        // The correct construction is to put $a_{n-1}$ in one class and $a_n$ in the other.
        //
        // Let $C_1 = \{a_0, a_1, \dots, a_{n-1}\}$ and $C_2 = \{a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        //
        // The problem is that the sizes must be odd.
        //
        // The solution is simply $a_n - a_{n-1}$.
        // This is a known result for this type of problem.
        // The minimum difference between medians of two groups of odd sizes that partition $2n$ elements
        // is achieved by taking $a_{n-1}$ and $a_n$ as the medians.
        //
        // To achieve this:
        // Let $C_1$ be $\{a_0, a_1, \dots, a_{n-1}\}$. This has $n$ elements.
        // Let $C_2$ be $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$. This has $n$ elements.
        //
        // If $n$ is odd, then $C_1$ and $C_2$ are valid classes.
        // Median of $C_1$ is $a_{(n-1)/2}$. Median of $C_2$ is $a_{n+(n-1)/2}$.
        // The difference is $a_{n+(n-1)/2} - a_{(n-1)/2}$. This is not $a_n - a_{n-1}$ for $n>1$.
        //
        // The solution is $a_n - a_{n-1}$.
        // This is because we can always construct two classes with $a_{n-1}$ and $a_n$ as their medians.
        //
        // Let $k_1 = 0$ and $k_2 = n-1$.
        // Class 1 has size $2k_1+1 = 1$. Let $C_1 = \{a_{n-1}\}$. Median is $a_{n-1}$.
        // Class 2 has size $2k_2+1 = 2(n-1)+1 = 2n-1$.
        // We need to pick $2n-1$ students for $C_2$ such that $a_n$ is its median.
        // $C_2$ needs $k_2 = n-1$ elements smaller than $a_n$ and $n-1$ elements larger than $a_n$.
        // The elements available are $a_0, \dots, a_{n-2}$ and $a_{n+1}, \dots, a_{2n-1}$.
        // We can form $C_2 = \{a_0, \dots, a_{n-2}, a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // This uses $n-1$ elements from $a_0, \dots, a_{n-2}$ (total $n-1$ elements).
        // This uses $n-1$ elements from $a_{n+1}, \dots, a_{2n-1}$ (total $n-1$ elements).
        // This uses $a_n$.
        // Total elements in $C_2$ is $(n-1) + 1 + (n-1) = 2n-1$.
        // The elements used are $a_0, \dots, a_{n-2}, a_n, a_{n+1}, \dots, a_{2n-1}$.
        // The student $a_{n-1}$ is left out.
        //
        // This construction is valid.
        // Class 1: $\{a_{n-1}\}$, median $a_{n-1}$. Size 1 (odd).
        // Class 2: $\{a_0, \dots, a_{n-2}, a_n, a_{n+1}, \dots, a_{2n-1}\}$, median $a_n$. Size $2n-1$ (odd).
        // All students are assigned.
        // The difference is $|a_n - a_{n-1}|$.
        // Since $a$ is sorted, $a_n - a_{n-1} \ge 0$.
        //
        // This construction always works.
        // And we proved that $m_2 - m_1 \ge a_n - a_{n-1}$.
        // So $a_n - a_{n-1}$ is the minimum possible difference.

        long long result = a[n] - a[n - 1];
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n_val, k_val;
    std::cin >> n_val >> k_val;

    std::vector<int> p_val(n_val);
    int left_ptr = 1;
    int right_ptr = k_val + 1; // The largest number to use for generating k distinct differences

    for (int i = 0; i < k_val + 1; ++i) {
        if (i % 2 == 0) {
            p_val[i] = left_ptr;
            left_ptr++;
        } else {
            p_val[i] = right_ptr;
            right_ptr--;
        }
    }

    // Fill the remaining elements in increasing order
    // The numbers used so far are 1, 2, ..., k+1.
    // The remaining numbers are k+2, ..., n.
    // Appending them in increasing order will only introduce a difference of 1,
    // which is already covered by the alternating sequence (if k >= 1).
    // For example, if k=1, sequence is 1, 2. Then 3, 4, ...
    // Differences: |1-2|=1, |2-3|=1, |3-4|=1. Only 1 distinct difference.
    // If k=2, sequence is 1, 3, 2. Then 4, 5, ...
    // Differences: |1-3|=2, |3-2|=1, |2-4|=2, |4-5|=1. Distinct: 1, 2.
    for (int i = k_val + 1; i < n_val; ++i) {
        p_val[i] = i + 1;
    }

    for (int i = 0; i < n_val; ++i) {
        std::cout << p_val[i] << (i == n_val - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n; // Length of the input string s
    int k; // Desired length of the regular bracket subsequence
    std::cin >> n >> k;
    std::string s; // The input regular bracket sequence
    std::cin >> s;

    std::string result = ""; // The resulting regular bracket subsequence
    int open_needed = k / 2; // Number of '(' characters needed
    int close_needed = k / 2; // Number of ')' characters needed
    int current_balance = 0; // Balance of '(' and ')' in the result string

    for (char c : s) {
        if (c == '(') {
            if (open_needed > 0) {
                result += '(';
                open_needed--;
                current_balance++;
            }
        } else { // c == ')'
            // We can add a ')' only if we have an open bracket to match it
            // and we still need closing brackets.
            // The condition current_balance > 0 ensures it's a valid closing bracket
            // for the current prefix of the result.
            // The condition close_needed > 0 ensures we don't exceed k/2 closing brackets.
            if (current_balance > 0 && close_needed > 0) {
                result += ')';
                close_needed--;
                current_balance--;
            }
        }
        // If we have collected k characters, we can stop.
        // This is an optimization, as the problem guarantees a solution exists
        // and our greedy strategy should find it.
        if (result.length() == k) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost peak of a non-increasing suffix
    // This is the first element from the right that breaks the non-increasing order
    // i.e., a[i] > a[i+1]
    int p1 = n - 1;
    while (p1 > 0 && a[p1 - 1] >= a[p1]) {
        p1--;
    }
    // After this loop, a[p1...n-1] is non-increasing.
    // If p1 is 0, the whole array is non-increasing.
    // If p1 > 0, then a[p1-1] < a[p1].

    // Find the rightmost peak of a non-decreasing suffix
    // This is the first element from the right that breaks the non-decreasing order
    // i.e., a[i] < a[i+1]
    int p2 = p1; // Start search from p1, as elements to the right of p1 are already non-increasing
                 // and thus potentially part of a non-decreasing sequence if we reverse direction.
                 // More precisely, we are looking for the start of the "valley" part.
    while (p2 > 0 && a[p2 - 1] <= a[p2]) {
        p2--;
    }
    // After this loop, a[p2...p1] is non-decreasing.
    // If p2 is 0, then a[0...p1] is non-decreasing.
    // If p2 > 0, then a[p2-1] > a[p2].

    std::cout << p2 << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

