int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y " << std::fixed << std::setprecision(9) << 0.0 << " " << 0.0 << "\n";
            continue;
        }

        double discriminant = d * d - 4.0 * d;

        if (discriminant < 0.0) {
            std::cout << "N\n";
        } else {
            double sqrt_discriminant = std::sqrt(discriminant);
            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // Check if a and b are non-negative.
            // Since d >= 0, and sqrt_discriminant >= 0, a1 will always be non-negative.
            // We need to check b1.
            // b1 = (d - sqrt(d^2 - 4d)) / 2
            // For b1 to be non-negative, d >= sqrt(d^2 - 4d)
            // Squaring both sides (both are non-negative): d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // This is true since d is non-negative.
            // So, if discriminant >= 0, both a1 and b1 will be non-negative.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the 0-indexed position of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result(n, '0');

    // For m=1, the subsegment [1] is always a permutation of {1}.
    // It's found at p[pos[1]...pos[1]]. Length is 1. Min is 1, Max is 1.
    result[0] = '1';

    // Initialize current min_idx and max_idx for the range containing {1}
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    // Iterate for m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // Update min_idx and max_idx to include the position of 'm'
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the subsegment p[current_min_idx ... current_max_idx]
        // forms a permutation of {1, ..., m}.
        // This requires its length to be exactly m.
        // The length is (current_max_idx - current_min_idx + 1).
        if ((current_max_idx - current_min_idx + 1) == m) {
            result[m - 1] = '1';
        }
    }

    std::cout << result << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

