void solve() {
    long long a, b, c, d;
    std::cin >> a >> b >> c >> d;

    long long total_toys = a + b + c + d;

    std::vector<std::string> result(4, "Tidak");

    if (total_toys == 0) {
        // This case is prevented by A+B+C+D > 0 constraint.
        // But if it were possible, no toy means no special box.
        std::cout << "Tidak Tidak Tidak Tidak\n";
        return;
    }

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        if (a == 1) result[0] = "Ya";
        if (b == 1) result[1] = "Ya";
        if (c == 1) result[2] = "Ya";
        if (d == 1) result[3] = "Ya";
        std::cout << result[0] << " " << result[1] << " " << result[2] << " " << result[3] << "\n";
        return;
    }

    // Box 1: (-inf, -1]
    // Final product is negative and magnitude >= 1
    // This requires an odd number of negative factors.
    // And at least one factor with magnitude >= 1, or multiple factors with magnitude > 1/x.
    // To guarantee magnitude >= 1, we need:
    // 1. At least one toy from Box 1 or Box 4 (magnitude >= 1)
    // 2. If only toys from Box 2 and Box 3, then the product will have magnitude < 1.
    // So, if a+d == 0, Box 1 is impossible.
    // If a+d > 0, we can potentially make magnitude >= 1.
    // Parity of negatives: (a + b) % 2 == 1
    if ((a + b) % 2 == 1 && (a + d > 0 || (b > 0 && c > 0))) {
        result[0] = "Ya";
    }

    // Box 2: (-1, 0)
    // Final product is negative and magnitude < 1
    // This requires an odd number of negative factors.
    // And the product's magnitude must be < 1.
    // To guarantee magnitude < 1, we need:
    // 1. At least one toy from Box 2 or Box 3 (magnitude < 1)
    // 2. If only toys from Box 1 and Box 4, then the product will have magnitude >= 1.
    // So, if b+c == 0, Box 2 is impossible.
    // If b+c > 0, we can potentially make magnitude < 1.
    // Parity of negatives: (a + b) % 2 == 1
    if ((a + b) % 2 == 1 && (b + c > 0 || (a > 0 && d > 0))) {
        result[1] = "Ya";
    }

    // Box 3: (0, 1)
    // Final product is positive and magnitude < 1
    // This requires an even number of negative factors.
    // And the product's magnitude must be < 1.
    // To guarantee magnitude < 1, we need:
    // 1. At least one toy from Box 2 or Box 3 (magnitude < 1)
    // 2. If only toys from Box 1 and Box 4, then the product will have magnitude >= 1.
    // So, if b+c == 0, Box 3 is impossible.
    // If b+c > 0, we can potentially make magnitude < 1.
    // Parity of negatives: (a + b) % 2 == 0
    if ((a + b) % 2 == 0 && (b + c > 0 || (a > 0 && d > 0))) {
        result[2] = "Ya";
    }

    // Box 4: [1, inf)
    // Final product is positive and magnitude >= 1
    // This requires an even number of negative factors.
    // And at least one factor with magnitude >= 1, or multiple factors with magnitude > 1/x.
    // To guarantee magnitude >= 1, we need:
    // 1. At least one toy from Box 1 or Box 4 (magnitude >= 1)
    // 2. If only toys from Box 2 and Box 3, then the product will have magnitude < 1.
    // So, if a+d == 0, Box 4 is impossible.
    // If a+d > 0, we can potentially make magnitude >= 1.
    // Parity of negatives: (a + b) % 2 == 0
    if ((a + b) % 2 == 0 && (a + d > 0 || (b > 0 && c > 0))) {
        result[3] = "Ya";
    }

    std::cout << result[0] << " " << result[1] << " " << result[2] << " " << result[3] << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate minimum possible values for the left increasing part
    // b[i] = minimum value a[i] can take to satisfy a[0] < a[1] < ... < a[i]
    // b[0] = 0
    // b[i] = b[i-1] + 1
    // So, b[i] = i
    // We need a[i] >= b[i] for all i in the increasing part.
    // This means a[i] >= i.

    // Calculate minimum possible values for the right decreasing part
    // c[i] = minimum value a[i] can take to satisfy a[i] > a[i+1] > ... > a[n-1]
    // c[n-1] = 0
    // c[i] = c[i+1] + 1
    // So, c[i] = (n-1) - i
    // We need a[i] >= c[i] for all i in the decreasing part.
    // This means a[i] >= (n-1) - i.

    // Find the maximum possible length of the strictly increasing prefix
    // where a[i] can be made to satisfy a[i] >= i.
    int left_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            left_len++;
        } else {
            break;
        }
    }

    // Find the maximum possible length of the strictly decreasing suffix
    // where a[i] can be made to satisfy a[i] >= (n-1) - i.
    int right_len = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1) - i) {
            right_len++;
        } else {
            break;
        }
    }

    // If the sum of lengths is greater than or equal to n, it means there's an overlap
    // or they meet exactly, implying a valid peak can be formed.
    // For example, if n=3, left_len=2 (a[0], a[1] can be part of increasing)
    // and right_len=2 (a[1], a[2] can be part of decreasing).
    // This means a[1] can be the peak.
    // The condition is left_len + right_len > n.
    // This is equivalent to left_len + right_len >= n + 1.
    // Example: n=3. left_len=2, right_len=2. 2+2=4 > 3. Yes.
    // Example: n=4. left_len=2, right_len=2. 2+2=4. Not > 4. No.
    // This means the "potential" increasing part ends at index left_len-1.
    // The "potential" decreasing part starts at index n-right_len.
    // For a peak to exist, the end of the increasing part must be >= the start of the decreasing part.
    // (left_len - 1) >= (n - right_len)
    // left_len + right_len - 1 >= n
    // left_len + right_len >= n + 1
    if (left_len + right_len >= n + 1) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

