// Function to check if a sub-array is a permutation
// `arr` is the original array
// `start_idx` is the 0-based starting index of the sub-array
// `length` is the length of the sub-array
// `max_val_expected` is the maximum value expected in the permutation (which is `length`)
bool is_permutation(const std::vector<int>& arr, int start_idx, int length, int max_val_expected) {
    if (length == 0) { // A permutation must have non-zero length
        return false;
    }
    std::vector<bool> seen(length + 1, false);
    int current_max = 0;
    for (int i = 0; i < length; ++i) {
        int val = arr[start_idx + i];
        if (val <= 0 || val > length || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > current_max) {
            current_max = val;
        }
    }
    return current_max == max_val_expected;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    int max_val_overall = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] > max_val_overall) {
            max_val_overall = a[i];
        }
    }

    // Precompute prefix_is_perm[i] = true if a[0...i-1] is a permutation of length i
    std::vector<bool> prefix_is_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max_prefix = 0;
    bool possible_prefix = true;
    for (int i = 0; i < n; ++i) {
        int val = a[i];
        if (val <= 0 || val > (i + 1) || seen_prefix[val]) {
            possible_prefix = false;
        }
        if (possible_prefix) {
            seen_prefix[val] = true;
            if (val > current_max_prefix) {
                current_max_prefix = val;
            }
            if (current_max_prefix == (i + 1)) {
                prefix_is_perm[i + 1] = true;
            }
        }
    }

    // Precompute suffix_is_perm[i] = true if a[i...n-1] is a permutation of length n-i
    std::vector<bool> suffix_is_perm(n + 1, false); // suffix_is_perm[i] means a[i...n-1]
    std::vector<bool> seen_suffix(n + 1, false);
    int current_max_suffix = 0;
    bool possible_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        int length = n - i;
        int val = a[i];
        if (val <= 0 || val > length || seen_suffix[val]) {
            possible_suffix = false;
        }
        if (possible_suffix) {
            seen_suffix[val] = true;
            if (val > current_max_suffix) {
                current_max_suffix = val;
            }
            if (current_max_suffix == length) {
                suffix_is_perm[i] = true;
            }
        }
    }

    std::vector<std::pair<int, int>> results;

    // Iterate through all possible split points l1
    // l1 goes from 1 to n-1
    // l2 = n - l1
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (l2 <= 0) continue; // l2 must be positive

        // Check if the first l1 elements form a permutation of length l1
        // Check if the last l2 elements form a permutation of length l2
        if (prefix_is_perm[l1] && suffix_is_perm[l1]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

