    // The original index of b_indexed[m-1-i].first is b_indexed[m-1-i].second.
    // So, result_a[b_indexed[m-1-i].second] = a[i].

    for (int i = 0; i < m; ++i) {
        result_a[b_indexed[m - 1 - i].second] = a[i];
    }

    for (int i = 0; i < m; ++i) {
