    // Let's try to append two elements: X and S.
    // New XOR sum: current_xor_sum ^ X ^ S
    // New sum: current_sum + X + S
    // We want current_sum + X + S = 2 * (current_xor_sum ^ X ^ S)

    // Let's try to append two elements: current_xor_sum and current_sum.
    // This is not quite right. The problem states we can append at most 3 elements.
    // A common strategy for these problems is to append X and then something else.

    // Let's append two elements: current_xor_sum and current_sum + current_xor_sum.
    // This is a common trick.
    // Let b1 = current_xor_sum
    // Let b2 = current_sum + current_xor_sum
    // This is not quite right either. The values can be large.

    // The standard approach for this type of problem is to append two values:
    // 1. The current XOR sum (let's call it X_curr)
    // 2. A value that makes the sum and XOR sum satisfy the condition.

    // Let X_curr be the XOR sum of the initial array.
    // Let S_curr be the sum of the initial array.

    // We want to find b1, b2 such that:
    // (S_curr + b1 + b2) = 2 * (X_curr ^ b1 ^ b2)

    // Consider appending two elements:
    // b1 = X_curr
    // b2 = S_curr + X_curr
    // This is not correct. The sum and XOR sum of b1 and b2 are not simple.

    // Let's try to append two elements:
    // b1 = X_curr
    // b2 = (S_curr + X_curr)
    // This is not correct.

    // The problem states we can append at most 3 elements.
    // A common construction is to append X_curr, and then a value that makes the sum even.
    // Let X_curr be the current XOR sum.
    // Let S_curr be the current sum.

    // Append X_curr.
    // New XOR sum: X_curr' = X_curr ^ X_curr = 0
    // New sum: S_curr' = S_curr + X_curr

    // Now we have an array with sum S_curr' and XOR sum X_curr' = 0.
    // We need to append one more element, say `val`, such that:
    // (S_curr' + val) = 2 * (X_curr' ^ val)
    // (S_curr + X_curr + val) = 2 * (0 ^ val)
    // (S_curr + X_curr + val) = 2 * val
    // S_curr + X_curr = val

    // So, the three elements to append are:
    // 1. X_curr
    // 2. S_curr + X_curr
    // 3. 0 (if we need to make it 3 elements, but we only need 2 here)

    // Let's verify this strategy:
    // Append b1 = current_xor_sum
    // Append b2 = current_sum + current_xor_sum
    // The new array has elements: a_1, ..., a_n, b1, b2
    // New XOR sum: X_new = current_xor_sum ^ b1 ^ b2
    // X_new = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
    // X_new = 0 ^ (current_sum + current_xor_sum)
    // X_new = current_sum + current_xor_sum

    // New sum: S_new = current_sum + b1 + b2
    // S_new = current_sum + current_xor_sum + (current_sum + current_xor_sum)
    // S_new = 2 * (current_sum + current_xor_sum)

    // We need S_new = 2 * X_new
    // 2 * (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum)
    // This holds true!

    // So, we can always append two elements:
    // b1 = current_xor_sum
    // b2 = current_sum + current_xor_sum

    // Output:
    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

