#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long opponent_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, taking 1 is optimal
                    chanek_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 != 0 && n != 4) { // N/2 is odd, and N is not 4
                    // Taking N/2 leaves an odd number for opponent.
                    // Taking 1 leaves an odd number for opponent.
                    // If N/2 is odd, taking N/2 is better for Chanek.
                    // Exception: N=4. N/2=2 (even). Taking N/2=2 leaves 2. Opponent takes 1. Chanek takes 1. Total Chanek: 2+1=3.
                    // If N=4, Chanek takes 1. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Total Chanek: 1+1=2.
                    // So for N=4, Chanek takes N/2.
                    // The condition (n/2)%2 != 0 covers cases like N=6, N=10, N=14, etc.
                    // For N=6, N/2=3 (odd). Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek: 3+1=4.
                    // For N=6, Chanek takes 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek: 1+2+1=4.
                    // Both give 4.
                    // The logic for N=4 is tricky.
                    // If N=4:
                    //   Chanek takes 1 -> N=3. Opponent takes 1 -> N=2. Chanek takes 1 -> N=1. Opponent takes 1 -> N=0. Chanek: 1+1=2.
                    //   Chanek takes N/2 (2) -> N=2. Opponent takes 1 -> N=1. Chanek takes 1 -> N=0. Chanek: 2+1=3.
                    // So for N=4, Chanek takes N/2.
                    // The condition (n/2)%2 != 0 is for when taking N/2 leaves an odd number for the opponent.
                    // If N/2 is odd, taking N/2 is generally better.
                    // If N/2 is even, taking 1 might be better to leave an odd number for the opponent.
                    // This is the core of the greedy strategy.
                    // If N is even:
                    //   Option 1: Take 1. N becomes N-1 (odd). Opponent takes 1. N becomes N-2 (even).
                    //   Option 2: Take N/2. N becomes N/2.
                    //     If N/2 is odd, opponent takes 1. N becomes N/2-1 (even).
                    //     If N/2 is even, opponent can take N/4 or 1.
                    // The optimal strategy for Chanek when N is even is to take N/2 if N/2 is odd.
                    // If N/2 is even, Chanek should take 1.
                    // This is because if N/2 is odd, the opponent is forced to take 1, leaving an even number for Chanek.
                    // If N/2 is even, and Chanek takes N/2, the opponent can also take N/4, which is a strong move.
                    // By taking 1, Chanek leaves N-1 (odd) for the opponent, forcing the opponent to take 1.
                    // This leaves N-2 (even) for Chanek.
                    // This logic is sound for N > 4.
                    // For N=4, N/2=2 (even). According to this, Chanek should take 1. But we saw Chanek takes 2.
                    // So the rule is: if N is even, and N/2 is odd, take N/2.
                    // If N is even, and N/2 is even, take 1. (Except N=4, take N/2).
                    // This can be simplified: if N is even, take N/2.
                    // This is because if N/2 is odd, it's good.
                    // If N/2 is even, it means N is a multiple of 4.
                    // If N is a multiple of 4, say N=4k. Chanek takes 2k. Opponent faces 2k.
                    // If Chanek takes 1, Opponent faces 4k-1. Opponent takes 1. Chanek faces 4k-2.
                    // This is the key: if N is even, and N/2 is odd, Chanek takes N/2.
                    // If N is even, and N/2 is even, Chanek takes 1. (This is for N=4k, Chanek takes 1, leaves 4k-1).
                    // The only exception is N=4.
                    // For N=4, N/2=2 (even). If Chanek takes 1, gets 2. If Chanek takes 2, gets 3. So Chanek takes 2.
                    // So the rule is: if N is even, and N/2 is odd, take N/2.
                    // If N is even, and N/2 is even:
                    //   If N=4, take N/2.
                    //   If N > 4, take 1.
                    // This is equivalent to: if N is even, and N is not a power of 2, take N/2.
                    // If N is a power of 2 (and N > 2), take 1.
                    // Let's re-evaluate.
                    // If N is even:
                    //   Option A: Take 1. Remaining N-1 (odd). Opponent takes 1. Remaining N-2 (even).
                    //   Option B: Take N/2. Remaining N/2.
                    //     If N/2 is odd: Opponent takes 1. Remaining N/2-1 (even).
                    //     If N/2 is even: Opponent can take N/4 or 1.
                    // Chanek wants to maximize his coins.
                    // If N/2 is odd, Chanek takes N/2. He gets N/2. Opponent gets 1. Chanek gets (N/2-1)/2.
                    // If N/2 is even, Chanek takes 1. He gets 1. Opponent gets 1. Chanek gets (N-2)/2.
                    // This is the greedy strategy.
                    // If N is even:
                    //   If N/2 is odd (e.g., N=6, N=10, N=14, ...): Chanek takes N/2.
                    //   If N/2 is even (e.g., N=4, N=8, N=12, ...): Chanek takes 1.
                    // This rule works for N=6 (N/2=3 odd, Chanek takes 3).
                    // This rule works for N=4 (N/2=2 even, Chanek takes 1). But example says Chanek takes 3.
                    // The example for N=4 is: Chanek takes 2. Opponent takes 1. Chanek takes 1. Total Chanek: 2+1=3.
                    // My rule for N=4 (N/2=2 even) says Chanek takes 1. Total Chanek: 1+1=2.
                    // So the rule "If N/2 is even, Chanek takes 1" is wrong for N=4.
                    // The rule should be:
                    // If N is odd: take 1.
                    // If N is even:
                    //   If N/2 is odd: take N/2. (e.g., N=6, N=10, N=14, ...)
                    //   If N/2 is even:
                    //     If N is a power of 2 (and N > 2): take 1. (e.g., N=8, N=16, ...)
                    //     If N is not a power of 2 (but N/2 is even): take N/2. (e.g., N=4, N=12, N=20, ...)
                    // This is equivalent to:
                    // If N is odd: take 1.
                    // If N is even:
                    //   If N is a power of 2 (and N > 2): take 1.
                    //   Else (N is even, not a power of 2): take N/2.
                    // Let's test this refined rule:
                    // N=1: odd, take 1. Chanek: 1. N=0. Correct.
                    // N=2: even, power of 2. Take 1. Chanek: 1. N=1. Opponent takes 1. Chanek: 1. N=0. Correct.
                    // N=3: odd, take 1. Chanek: 1. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek: 1+1=2. N=0. Correct.
                    // N=4: even, power of 2. Take 1. Chanek: 1. N=3. Opponent takes 1. N=2. Chanek takes 1. Chanek: 1+1=2. N=0.
                    // This is still wrong for N=4. Example says 3.
                    // The example for N=4 is: Chanek takes 2. Opponent takes 1. Chanek takes 1. Total Chanek: 2+1=3.
                    // This means for N=4, Chanek takes N/2.
                    // So the rule "If N is a power of 2 (and N > 2): take 1" is wrong for N=4.
                    // It seems the only special case is N=2.
                    // For N=2, Chanek takes 1.
                    // For N > 2:
                    //   If N is odd: take 1.
                    //   If N is even: take N/2.
                    // Let's test this simpler rule:
                    // N=1: odd, take 1. Chanek: 1. N=0. Correct.
                    // N=2: special case, take 1. Chanek: 1. N=1. Opponent takes 1. Chanek: 1. N=0. Correct.
                    // N=3: odd, take 1. Chanek: 1. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek: 1+1=2. N=0. Correct.
                    // N=4: even, N>2. Take N/2 (2). Chanek: 2. N=2. Opponent takes 1. N=1. Chanek takes 1. Chanek: 2+1=3. N=0. Correct.
                    // N=5: odd, N>2. Take 1. Chanek: 1. N=4. Opponent takes N/2 (2). N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek: 1+1=2. N=0. Correct.
                    // N=6: even, N>2. Take N/2 (3). Chanek: 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek: 3+1=4. N=0. Correct.
                    // This simpler rule seems to work for all examples and small cases.
                    // Let's use this rule:
                    // If N is odd: take 1.
                    // If N is even:
                    //   If N == 2: take 1.
                    //   Else (N is even and N > 2): take N/2.
                    if (n == 2) {
                        chanek_coins += 1;
                        n -= 1;
                    } else {
                        chanek_coins += n / 2;
                        n /= 2;
                    }
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                opponent_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) {
                    opponent_coins += 1;
                    n -= 1;
                } else {
                    opponent_coins += n / 2;
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

