        current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;

        // Add extra Ql or Qr costs
        if (i > j) { // More items from left than right
            // The last item taken must have been from the left side.
            // The number of "extra" left items is i - j.
            // If i - j >= 2, then there are (i - j - 1) pairs of consecutive left takes
            // where the left side was taken more often than the right side.
            // This means the robot took (i-j) more items from the left than from the right.
            // The minimum number of times the robot must have taken from the left consecutively
            // to achieve this difference is (i-j-1).
            current_energy += (i - j - 1) * Ql;
        } else if (j > i) { // More items from right than left
            // Similar logic, (j - i - 1) pairs of consecutive right takes.
            current_energy += (j - i - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

