// Function to get prime factors of a number
// Returns a vector of pairs: {prime_factor, exponent}
std::vector<std::pair<long long, int>> get_prime_factors(long long n) {
    std::vector<std::pair<long long, int>> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            int count = 0;
            while (n % i == 0) {
                n /= i;
                count++;
            }
            factors.push_back({i, count});
        }
    }
    if (n > 1) {
        factors.push_back({n, 1});
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that p % x == 0 and x % q != 0.
        // Let q = f1^a1 * f2^a2 * ... * fk^ak be the prime factorization of q.
        // For x to be not divisible by q, there must be at least one prime factor fi of q
        // such that the exponent of fi in x's prime factorization is less than ai.
        // To maximize x, we want to remove as few factors from p as possible.
        // For each prime factor fi of q, we can try to remove just enough fi's from p
        // such that the resulting number x is no longer divisible by q.
        // Specifically, if p = fi^bi * ... and q = fi^ai * ..., and bi >= ai,
        // we can form a candidate x by dividing p by fi^(bi - ai + 1).
        // This ensures that the exponent of fi in x is (bi - (bi - ai + 1)) = ai - 1,
        // which is less than ai, so x is not divisible by q.
        // We want to maximize x, so we want to minimize the division factor.
        // The division factor is fi^(bi - ai + 1).
        // We iterate through all prime factors fi of q and find the minimum such division factor.
        // The largest x will be p / (minimum division factor).

        std::vector<std::pair<long long, int>> q_factors = get_prime_factors(q);
        long long max_x = 1; // Initialize with a small value, as p >= 1

        for (const auto& factor_pair : q_factors) {
            long long f = factor_pair.first;
            int a = factor_pair.second; // Exponent of f in q

            // Calculate the exponent of f in p
            long long temp_p = p;
            int b = 0; // Exponent of f in p
            while (temp_p > 0 && temp_p % f == 0) {
                temp_p /= f;
                b++;
            }

            // If b < a, then p is not divisible by q (contradicts p % q == 0).
            // This case should not happen if p % q == 0.
            // If b >= a, we need to reduce the power of f in p.
            // To make x not divisible by q, the power of f in x must be less than a.
            // The largest possible power of f in x that is less than a is a-1.
            // So, we need to divide p by f^(b - (a - 1)) = f^(b - a + 1).
            long long current_x = p;
            for (int i = 0; i < b - a + 1; ++i) {
                current_x /= f;
            }
            max_x = std::max(max_x, current_x);
        }
        std::cout << max_x << "\n";
    }

    return 0;
}

