int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < n; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    std::vector<std::vector<int>> count_pairs(n, std::vector<int>(n, 0));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            count_pairs[i][j] = 0;
        }
    }

    for (int k = 0; k < n; ++k) {
        for (int p = 1; p < n; ++p) {
            int k_prime = (k + p) % n;
            count_pairs[k][k_prime]++;
        }
    }

    std::vector<std::vector<int>> count_pairs_by_char(26, std::vector<int>(26, 0));
    for (int k = 0; k < n; ++k) {
        for (int p = 1; p < n; ++p) {
            int k_prime = (k + p) % n;
            count_pairs_by_char[s[k] - 'a'][s[k_prime] - 'a']++;
        }
    }

    double total_prob = 0.0;

    for (int first_char_val = 0; first_char_val < 26; ++first_char_val) {
        if (char_indices[first_char_val].empty()) {
            continue;
        }

        double max_prob_for_first_char = 0.0;

        for (int p = 1; p < n; ++p) { // Vasya chooses position p
            std::map<int, int> counts_for_p; // Map (s[k], s[(k+p)%n]) to count of k's
            for (int k_idx : char_indices[first_char_val]) {
                int second_char_val = s[(k_idx + p) % n] - 'a';
                counts_for_p[second_char_val]++;
            }

            double current_p_prob = 0.0;
            for (auto const& [second_char_val, count] : counts_for_p) {
                if (count == 1) {
                    current_p_prob += 1.0;
                }
            }
            max_prob_for_first_char = std::max(max_prob_for_first_char, current_p_prob);
        }
        total_prob += max_prob_for_first_char;
    }

    std::cout << std::fixed << std::setprecision(15) << total_prob / n << std::endl;

    return 0;
}

