    // by just `(x & A) ^ X`.
    // The general form for any boolean function of one variable `b` is `(b & C1) | C2`.
    // Let `f(0)` and `f(1)` be the target values for bit `j`.
    // We want `(0 & C1_j) | C2_j = f(0)` => `C2_j = f(0)`
    // We want `(1 & C1_j) | C2_j = f(1)` => `C1_j | C2_j = f(1)`
    // So `C2_j = f(0)`
    // And `C1_j | f(0) = f(1)`
    // This means if `f(0) = 0`, then `C1_j = f(1)`.
    // If `f(0) = 1`, then `f(1)` must be 1, and `C1_j` can be 0 or 1. We can choose `C1_j = 0`.
    // So, `C1_j = f(1)` if `f(0) = 0`, else `C1_j = 0`.
    // This can be written as `C1_j = f(1) & (~f(0))`.
    // So, `A_final = sum((f1 & (~f0)) << j)`
    // `O_final = sum(f0 << j)`
    // This gives `(x & A_final) | O_final`. This uses at most 2 operations.

    // Let's try this approach: `(x & A) | O`
    int final_AND_const = 0; // A
    int final_OR_const = 0;  // O

    for (int j = 0; j < 10; ++j) {
        int f0 = initial_zero_bit_val[j];
        int f1 = initial_one_bit_val[j];

        // For (x & A_j) | O_j:
        // If x_j = 0: (0 & A_j) | O_j = O_j. So O_j = f0.
        // If x_j = 1: (1 & A_j) | O_j = A_j | O_j. So A_j | O_j = f1.
        // Substitute O_j = f0: A_j | f0 = f1.
        // This implies:
        // If f0 = 0: A_j = f1. (0 | A_j = f1 => A_j = f1)
        // If f0 = 1: f1 must be 1. A_j can be 0 or 1. We can choose A_j = 0. (A_j | 1 = 1)
        // So, A_j = f1 if f0 = 0, else A_j = 0. This is equivalent to A_j = f1 & (~f0).
        // O_j = f0.

        final_AND_const |= ((f1 & (~f0)) << j);
        final_OR_const |= (f0 << j);
    }

    // Now we have `(x & final_AND_const) | final_OR_const`.
    // This uses at most 2 operations.
    // If final_AND_const is 1023, then `x & 1023` is `x`.
    // If final_OR_const is 0, then `x | 0` is `x`.

    std::vector<std::pair<char, int>> ops_A_OR_O;
    if (final_AND_const != 1023) { // If A is 1023, then x & 1023 is just x (for 0-1023 range). No need for & op.
        ops_A_OR_O.push_back({'&', final_AND_const});
    }
    if (final_OR_const != 0) { // If O is 0, then x | 0 is just x. No need for | op.
        ops_A_OR_O.push_back({'|', final_OR_const});
    }

    // This is one possible representation.
    // Another is `(x | O) & A`.
    // Let's try to find `O_prime` and `A_prime` such that `(x | O_prime) & A_prime`.
    // For each bit `j`:
    // `(0 | O_prime_j) & A_prime_j = f0` => `O_prime_j & A_prime_j = f0`
    // `(1 | O_prime_j) & A_prime_j = f1` => `1 & A_prime_j = f1` => `A_prime_j = f1`
    // Substitute `A_prime_j = f1`: `O_prime_j & f1 = f0`.
    // This implies:
    // If `f1 = 0`: `f0` must be 0. `O_prime_j` can be 0 or 1. We can choose `O_prime_j = 0`. (`O_prime_j & 0 = 0`)
    // If `f1 = 1`: `O_prime_j = f0`. (`O_prime_j & 1 = f0`)
    // So, `O_prime_j = f0` if `f1 = 1`, else `O_prime_j = 0`. This is equivalent to `O_prime_j = f0 & f1`.
    // `A_prime_j = f1`.

    int final_OR_prime_const = 0; // O_prime
    int final_AND_prime_const = 0; // A_prime

    for (int j = 0; j < 10; ++j) {
        int f0 = initial_zero_bit_val[j];
        int f1 = initial_one_bit_val[j];

        final_OR_prime_const |= ((f0 & f1) << j);
        final_AND_prime_const |= (f1 << j);
    }

    std::vector<std::pair<char, int>> ops_OR_A_prime;
    if (final_OR_prime_const != 0) { // If O_prime is 0, then x | 0 is just x. No need for | op.
        ops_OR_A_prime.push_back({'|', final_OR_prime_const});
    }
    if (final_AND_prime_const != 1023) { // If A_prime is 1023, then x & 1023 is just x. No need for & op.
        ops_OR_A_prime.push_back({'&', final_AND_prime_const});
    }

    // We need to output the shortest sequence.
    // The problem statement implies that 3 operations (AND, OR, XOR) are sufficient.
    // Let's use the form `((x & A) | O) ^ X`.
    // We need to find A, O, X.
    // For each bit `j`:
    // `f0 = initial_zero_bit_val[j]`
    // `f1 = initial_one_bit_val[j]`

    // We want `((0 & A_j) | O_j) ^ X_j = f0` => `O_j ^ X_j = f0`
    // We want `((1 & A_j) | O_j) ^ X_j = f1` => `(A_j | O_j) ^ X_j = f1`

    // Let's try to find A, O, X that work for all bits.
    // A_j = f1 ^ f0
    // O_j = 0
    // X_j = f0
    // This gives `(x & A) ^ X`. This is 2 ops.

    // What if we use `(x | O) ^ X`?
    // `(0 | O_j) ^ X_j = f0` => `O_j ^ X_j = f0`
    // `(1 | O_j) ^ X_j = f1` => `1 ^ X_j = f1` => `X_j = !f1`
    // Substitute `X_j = !f1`: `O_j ^ (!f1) = f0` => `O_j = f0 ^ (!f1)`
    // So, `O_j = f0 ^ (!f1)`
    // `X_j = !f1`
    // This gives `(x | O) ^ X`. This is 2 ops.

    // What if we use `(x ^ X) & A`?
    // `(0 ^ X_j) & A_j = f0` => `X_j & A_j = f0`
    // `(1 ^ X_j) & A_j = f1`
    // If `X_j = 0`: `0 & A_j = f0` => `f0 = 0`.
    //   Then `(1 ^ 0) & A_j = f1` => `1 & A_j = f1` => `A_j = f1`.
    //   So if `f0 = 0`, then `X_j = 0`, `A_j = f1`.
    // If `X_j = 1`: `1 & A_j = f0` => `A_j = f0`.
    //   Then `(1 ^ 1) & A_j = f1` => `0 & A_j = f1` => `f1 = 0`.
    //   So if `f1 = 0`, then `X_j = 1`, `A_j = f0`.
    // This is getting complicated.

    // The simplest approach is to find the constants for the three operations: AND, OR, XOR.
    // Let `res_and = 1023` (initial value for AND, effectively no change)
    // Let `res_or = 0` (initial value for OR, effectively no change)
    // Let `res_xor = 0` (initial value for XOR, effectively no change)

    // We want to find `A, O, X` such that `((x & A) | O) ^ X` is the final function.
    // For each bit `j`:
    // `f0 = initial_zero_bit_val[j]`
    // `f1 = initial_one_bit_val[j]`

    // We need to find `A_j, O_j, X_j` such that:
    // `(0 & A_j | O_j) ^ X_j = f0`  => `O_j ^ X_j = f0`
    // `(1 & A_j | O_j) ^ X_j = f1`  => `(A_j | O_j) ^ X_j = f1`

    // Let's try to construct A, O, X directly.
    // A = 0, O = 0, X = 0.
    // For each bit j:
    // If (f0, f1) is (0,0): `x_j` becomes 0.
    //   This means `A_j` must be 0, `O_j` must be 0, `X_j` must be 0.
    //   Or `A_j` can be 1, `O_j` can be 0, `X_j` can be 0, then `(x_j & 1) | 0 ^ 0` is `x_j`.
    //   This is not right.

    // Let's use the standard representation for any boolean function of one variable `b`:
    // `f(b) = (b AND (f(1) XOR f(0))) XOR f(0)`
    // This means `A = (f(1) XOR f(0))` and `X = f(0)`.
    // The OR constant `O` is 0.
    // This is `(x & A) ^ X`.

    // Let's calculate A and X based on this.
    int A_val = 0;
    int X_val = 0;
    for (int j = 0; j < 10; ++j) {
        int f0 = initial_zero_bit_val[j];
        int f1 = initial_one_bit_val[j];
        A_val |= ((f1 ^ f0) << j);
        X_val |= (f0 << j);
    }

    std::vector<std::pair<char, int>> final_ops;
    if (A_val != 1023) { // If A_val is 1023, then x & 1023 is x. No need for & op.
        final_ops.push_back({'&', A_val});
    }
    if (X_val != 0) { // If X_val is 0, then x ^ 0 is x. No need for ^ op.
        final_ops.push_back({'^', X_val});
    }

    // This approach guarantees at most 2 operations.
    // The problem statement says "no more than 5 lines".
    // This is a valid solution.

    std::cout << final_ops.size() << std::endl;
    for (const auto& op : final_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

