                max_val_in_row = std::max(max_val_in_row, a[i][j]);
            }
        }
        p[i] = max_val_in_row;
    }

    bool n_assigned = false;
    for (int i = 0; i < n; ++i) {
        if (p[i] == n - 1) {
            // If p[i] is n-1, it means p[i] could be n.
            // We need to check if n has already been assigned.
            // If not, assign n to this position and mark n as assigned.
            // If n has been assigned, then this p[i] must be n-1.
            if (!n_assigned) {
                p[i] = n;
                n_assigned = true;
            }
        }
    }

    // If n was not assigned to any p[i] (meaning no row had max_val_in_row == n-1),
    // it implies that all p[i] values were correctly determined as max_val_in_row,
    // and the value 'n' itself was not present in any p[i] as max_val_in_row.
    // This can only happen if 'n' was the value of some p[k] and for all j!=k,
    // min(p[k], p[j]) = p[j], and max(p[j]) was less than n-1.
    // This logic is flawed. The problem guarantees a solution.
    // The logic for assigning 'n' is: if there's any p[i] that is currently n-1,
    // it means p[i] could be n. If there are multiple such positions, only one can be n.
    // The problem statement guarantees that there is at least one solution.
    // The maximum value in any row `i` (excluding `a[i][i]`) is `max_{j!=i} min(p_i, p_j)`.
    // If `p_i = k`, then `max_{j!=i} min(k, p_j)` will be `k` if there is some `p_j > k`.
    // If `p_i = n`, then `max_{j!=i} min(n, p_j) = max_{j!=i} p_j = n-1`.
    // So, if `p_i` is `n`, the calculated `max_val_in_row` for index `i` will be `n-1`.
    // If `p_i` is not `n`, then `max_val_in_row` for index `i` will be `p_i` (unless `p_i` is 1 and `n=2`, then `p_i=1` and `max_val_in_row=1`).
    // The only case where `p_i` is not `n` but `max_val_in_row` is `n-1` is if `p_i = n-1` and there is some `p_j > n-1`, which is impossible.
    // So, if `max_val_in_row` for index `i` is `n-1`, then `p_i` must be `n`.
    // If `max_val_in_row` for index `i` is `k < n-1`, then `p_i` must be `k`.
    // This means there will be exactly one index `i` for which `max_val_in_row` is `n-1`.
    // For all other indices `k`, `p_k` is `max_val_in_row` for row `k`.

    // Re-evaluate the logic for assigning 'n'.
    // The values `p[i]` are initially set to `max_{j!=i} a[i][j]`.
    // If `p_k = N`, then `max_{j!=k} min(p_k, p_j) = max_{j!=k} p_j = N-1`.
    // So, if `p_k = N`, then `p[k]` (as computed) will be `N-1`.
    // If `p_k < N`, then `max_{j!=k} min(p_k, p_j)` will be `p_k` (if there's a `p_j > p_k`)
    // or some `p_j` (if all `p_j < p_k`).
    // The crucial observation is that `p_i` is either `max_{j!=i} a[i][j]` or `N`.
    // It is `N` if and only if `max_{j!=i} a[i][j]` is `N-1`.
    // Since `p` is a permutation of `1..N`, there is exactly one `i` such that `p_i = N`.
    // For this `i`, `max_{j!=i} a[i][j]` will be `N-1`.
    // For all other `k != i`, `p_k < N`, so `max_{j!=k} a[k][j]` will be `p_k`.
    // Therefore, we find the unique `i` for which `p[i]` (as computed) is `N-1`, and set `p[i] = N`.
    // All other `p[k]` (as computed) are already correct.

    // The previous loop already correctly identifies the candidate for 'n'.
    // If `n_assigned` is still false after the loop, it means no `p[i]` was `n-1`.
    // This implies that `n` was not present in the permutation, which contradicts the problem.
    // This scenario should not happen given the problem constraints.
    // The problem guarantees a solution.
    // So, `n_assigned` will be true after the loop, and exactly one `p[i]` will be `n`.

    for (int i = 0; i < n; ++i) {
