#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_s_count = 0;
    int initial_b_count = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_s_count++;
        } else {
            initial_b_count++;
        }
    }

    int target_diff = initial_s_count - initial_b_count;

    // Calculate prefix sums for the left side (jars 1 to n)
    // diff_L[k] = (s_count - b_count) for jars 1 to k
    std::vector<int> diff_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_L[i + 1] = diff_L[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right side (jars n+1 to 2n)
    // diff_R[k] = (s_count - b_count) for jars 2n-k+1 to 2n
    std::vector<int> diff_R(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_R[i + 1] = diff_R[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars eaten from the left (L)
    // to achieve a certain difference (s_count - b_count)
    std::map<int, int> left_diff_to_L;
    for (int L = 0; L <= n; ++L) {
        int current_diff = diff_L[L];
        if (left_diff_to_L.find(current_diff) == left_diff_to_L.end()) {
            left_diff_to_L[current_diff] = L;
        }
    }

    int min_jars_eaten = 2 * n; // Initialize with maximum possible jars eaten

    // Iterate through all possible numbers of jars eaten from the right (R)
    for (int R = 0; R <= n; ++R) {
        int current_right_diff = diff_R[R];
        // The remaining jars have a difference of (initial_s - initial_b) - (diff_L[L] + diff_R[R])
        // We want this to be 0.
        // So, initial_s - initial_b = diff_L[L] + diff_R[R]
        // Or, diff_L[L] = target_diff - current_right_diff
        int required_left_diff = target_diff - current_right_diff;

        if (left_diff_to_L.count(required_left_diff)) {
            int L = left_diff_to_L[required_left_diff];
            min_jars_eaten = std::min(min_jars_eaten, L + R);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

