                // If first_one_idx is -1, current_val is 0, which can't equal current_len.
                if (first_one_idx != -1) {
                    if (current_val == current_len) {
                        good_substrings_count++;
                    }
                }
            }
        }
        std::cout << good_substrings_count << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::vector<std::set<char>> adj(26);
    std::vector<bool> in_password(26, false);

    for (size_t i = 0; i < s.length() - 1; ++i) {
        char c1 = s[i];
        char c2 = s[i+1];
        adj[c1 - 'a'].insert(c2);
        adj[c2 - 'a'].insert(c1);
        in_password[c1 - 'a'] = true;
        in_password[c2 - 'a'] = true;
    }
    if (s.length() == 1) { // Handle single character password
        in_password[s[0] - 'a'] = true;
    }

    for (int i = 0; i < 26; ++i) {
        if (adj[i].size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::vector<bool> visited(26, false);

    for (int i = 0; i < 26; ++i) {
        if (in_password[i] && !visited[i]) {
            if (adj[i].size() == 1 || adj[i].empty()) { // Start of a chain or isolated character
                char current_char = (char)('a' + i);
                while (current_char != 0 && !visited[current_char - 'a']) {
                    visited[current_char - 'a'] = true;
                    layout += current_char;

                    char next_char = 0;
                    for (char neighbor : adj[current_char - 'a']) {
                        if (!visited[neighbor - 'a']) {
                            next_char = neighbor;
                            break;
                        }
                    }
                    current_char = next_char;
                }
            }
        }
    }

    if (layout.length() != 0) { // Check for cycles or invalid chains
        std::vector<bool> layout_chars_present(26, false);
        for (char c : layout) {
            layout_chars_present[c - 'a'] = true;
        }
        for (int i = 0; i < 26; ++i) {
            if (in_password[i] && !layout_chars_present[i]) {
                std::cout << "NO\n"; // A character from password was not included in any chain
                return;
            }
        }
    }

    // Add remaining characters not in password
    for (int i = 0; i < 26; ++i) {
        if (!visited[i]) {
            layout += (char)('a' + i);
        }
    }

    if (layout.length() == 26) {
        std::cout << "YES\n";
        std::cout << layout << "\n";
    } else {
        std::cout << "NO\n"; // Should not happen if logic is correct, but as a safeguard
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    // We need to handle division by 2 with modular inverse.
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 7 + 1) / 2 = 500000004.
    long long inv2 = 500000004;

    long long sum_r_term = (b - 1);
    if (sum_r_term < 0) sum_r_term = 0; // If b=1, b-1=0, sum is 0.
    sum_r_term %= MOD;

    long long b_mod = b % MOD;

    sum_r_term = (sum_r_term * b_mod) % MOD;
    sum_r_term = (sum_r_term * inv2) % MOD;

    // Calculate sum_k_b_plus_1 = sum_{k=1 to a} (k * b + 1)
    // sum_{k=1 to a} (k * b + 1) = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // = b * (a * (a+1) / 2) + a
    long long sum_k_term = (a % MOD);
    long long a_plus_1_mod = (a + 1) % MOD;

    long long sum_k_val = (sum_k_term * a_plus_1_mod) % MOD;
    sum_k_val = (sum_k_val * inv2) % MOD;

    long long term1 = (b_mod * sum_k_val) % MOD;
    long long term2 = (a % MOD);

    long long sum_k_b_plus_1 = (term1 + term2) % MOD;

    // Total sum = (sum_r_term * sum_k_b_plus_1) % MOD
    long long total_sum = (sum_r_term * sum_k_b_plus_1) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

