    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n, 0); // Initialize with 0s
    std::vector<long long> current_delta(n, 0); // Accumulates d values

    // First pass: Determine upper bounds for initial_a[j]
    // For each type 2 query (l, r, m), we know initial_a[j] + current_delta[j] <= m
    // for all j in [l, r]. This means initial_a[j] <= m - current_delta[j].
    // We want to find the largest possible initial_a[j] that satisfies all constraints.
    // So, initial_a[j] must be <= min(m - current_delta[j]) over all relevant type 2 queries.
    // Initialize initial_a[j] to a very large value (effectively infinity)
    // and then take minimums.
    std::vector<long long> upper_bound_initial_a(n, 2000000000000000000LL); // A sufficiently large number

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            long long m_val = ops[i].val;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                upper_bound_initial_a[j] = std::min(upper_bound_initial_a[j], m_val - current_delta[j]);
            }
        }
    }

