    // This maximizes initial_a[j] while satisfying all `initial_a[j] + delta[j] <= m` constraints.
    // If this choice leads to a valid solution, it's one such solution.
    for (int j = 0; j < n; ++j) {
        initial_a[j] = upper_bound_initial_a[j];
    }

    // Second pass: Verify the solution
    // Re-simulate all operations with the chosen initial_a and check if all type 2 queries match.
    std::fill(current_delta.begin(), current_delta.end(), 0); // Reset current_delta for simulation

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
