struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> treated_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        treated_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false;

        long long current_v_effect = children[i].v;
        long long total_d_effect = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply effects from the current child being treated
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect--;
            }

            // Apply cumulative effects from children who ran away
            children[j].p -= total_d_effect;

            // Check if child j runs away
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_effect += children[j].d;
            }
        }
    }

    std::cout << treated_children_indices.size() << "\n";
    for (size_t i = 0; i < treated_children_indices.size(); ++i) {
        std::cout << treated_children_indices[i] << (i == treated_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

