    // A string s of length N is a palindrome.
    // If all characters in s are the same (e.g., "aaaa"), then any permutation of its substrings
    // will result in the same string "aaaa". In this case, it's impossible to get s' != s.
    // We can check this by counting distinct characters.
    bool all_same_chars = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
