// Function to check if all target tracks can be covered within time 't'
bool check(long long t, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    // current_p_idx points to the first target track that has not yet been covered
    int current_p_idx = 0;

    // Iterate through each head
    for (int i = 0; i < n; ++i) {
        // If all target tracks are already covered, we are done
        if (current_p_idx == m) {
            return true;
        }

        // The current head h[i] can cover tracks in the range [h[i] - t, h[i] + t].
        // Let's call this range [L, R].
        long long L = h[i] - t;
        long long R = h[i] + t;

        // We need to cover p[current_p_idx].
        // If p[current_p_idx] is outside the range [L, R], this head cannot cover it
        // without moving further than 't' from its initial position.
        // However, the head can move to cover p[current_p_idx] if p[current_p_idx] is within [L, R].
        // If p[current_p_idx] is to the left of L, this head cannot cover it.
        // Since p is sorted, if this head cannot cover p[current_p_idx], no subsequent head
        // (which are at h[j] >= h[i]) can cover it either if they also move at most 't' distance.
        // This is not entirely correct. A head h[i] can cover a range [h[i]-t, h[i]+t].
        // We need to cover p[current_p_idx].
        // If p[current_p_idx] is to the left of h[i]-t, this head cannot cover it.
        // If p[current_p_idx] is to the right of h[i]+t, this head cannot cover it.
        // But the head can choose to move to cover p[current_p_idx] and then extend its reach.

        // The strategy is: for the current head h[i], try to cover p[current_p_idx].
        // If h[i] is too far to the right to cover p[current_p_idx] (i.e., h[i] - t > p[current_p_idx]),
        // then this head cannot cover p[current_p_idx]. Since heads are sorted,
        // and p is sorted, this means no subsequent head can cover p[current_p_idx] either
        // if they are restricted to moving 't' distance.
        // This is a greedy approach: assign the leftmost available head to cover the leftmost uncovered track.

        // If the current head h[i] is too far to the right to cover p[current_p_idx]
        // (even if it moves 't' steps to the left), then it's impossible.
        // This condition is h[i] - t > p[current_p_idx].
        // However, this is not quite right. The head can move to p[current_p_idx] and then cover a range.
        // The head h[i] can cover any track in [h[i]-t, h[i]+t].
        // If p[current_p_idx] is not in this range, this head cannot cover it.
        // But we can use the head to cover p[current_p_idx] and then extend its reach.

        // Let's re-evaluate the greedy strategy.
        // We want to cover p[current_p_idx].
        // The current head h[i] can cover a range.
        // If h[i] is too far to the right to cover p[current_p_idx] (i.e., h[i] - t > p[current_p_idx]),
        // then this head cannot cover p[current_p_idx].
        // Since h is sorted, h[i+1], h[i+2], ... are even further to the right.
        // So, if h[i] cannot cover p[current_p_idx], no subsequent head can.
        // Thus, it's impossible to cover p[current_p_idx] with any remaining head.
        // This means we must return false.
        if (h[i] - t > p[current_p_idx]) {
            return false;
        }

        // If h[i] can reach p[current_p_idx] (i.e., h[i] - t <= p[current_p_idx]),
        // then this head can be used to cover p[current_p_idx].
        // The head can move to p[current_p_idx].
        // The time taken for this move is abs(h[i] - p[current_p_idx]).
        // Since this must be <= t, the head can cover the range
        // [p[current_p_idx] - (t - abs(h[i] - p[current_p_idx])), p[current_p_idx] + (t - abs(h[i] - p[current_p_idx]))].
        // This simplifies to [min(h[i], p[current_p_idx]) - (t - abs(h[i] - p[current_p_idx])), max(h[i], p[current_p_idx]) + (t - abs(h[i] - p[current_p_idx]))].
        // This is equivalent to saying the head can cover the range [h[i]-t, h[i]+t].
        // The crucial part is that if a head covers p[current_p_idx], it can also cover
        // other tracks to its right, up to a certain point.
        // The maximum track this head can cover is R_covered = h[i] + t.
        // However, if h[i] is to the right of p[current_p_idx], say h[i] > p[current_p_idx],
        // then the head moves left to p[current_p_idx]. The time spent is h[i] - p[current_p_idx].
        // Remaining time is t - (h[i] - p[current_p_idx]).
        // So it can cover tracks up to p[current_p_idx] + (t - (h[i] - p[current_p_idx])) = p[current_p_idx] + t - h[i] + p[current_p_idx] = 2*p[current_p_idx] + t - h[i].
        // This is incorrect. The head can cover the range [h[i]-t, h[i]+t].
        // If p[current_p_idx] is within this range, it is covered.
        // The head can be positioned anywhere in [h[i]-t, h[i]+t].
        // To cover p[current_p_idx], the head must be able to reach it.
        // The head can reach p[current_p_idx] if abs(h[i] - p[current_p_idx]) <= t.
        // If it reaches p[current_p_idx], it has `t - abs(h[i] - p[current_p_idx])` time remaining.
        // It can use this remaining time to extend its reach to the right.
        // So, the rightmost track it can cover is p[current_p_idx] + (t - abs(h[i] - p[current_p_idx])).

        // Let's simplify:
        // The head h[i] can cover a segment.
        // If h[i] is to the left of p[current_p_idx]: h[i] < p[current_p_idx].
        // The head moves right to p[current_p_idx]. Time spent: p[current_p_idx] - h[i].
        // Remaining time: t - (p[current_p_idx] - h[i]).
        // Max track covered: p[current_p_idx] + (t - (p[current_p_idx] - h[i])) = h[i] + t.
        // If h[i] is to the right of p[current_p_idx]: h[i] > p[current_p_idx].
        // The head moves left to p[current_p_idx]. Time spent: h[i] - p[current_p_idx].
        // Remaining time: t - (h[i] - p[current_p_idx]).
        // Max track covered: p[current_p_idx] + (t - (h[i] - p[current_p_idx])) = 2*p[current_p_idx] - h[i] + t.
        // This is the crucial part. The head can cover a range starting from p[current_p_idx]
        // and extending to the right.
        // The rightmost point reachable by head h[i] if it covers p[current_p_idx] is:
        long long max_reachable_right;
        if (h[i] <= p[current_p_idx]) { // Head is to the left or at p[current_p_idx]
            // Move right to p[current_p_idx], then continue right
            max_reachable_right = h[i] + t;
        } else { // Head is to the right of p[current_p_idx]
            // Move left to p[current_p_idx], then continue right
            // Time spent moving left: h[i] - p[current_p_idx]
            // Remaining time for further movement: t - (h[i] - p[current_p_idx])
            // Max track covered: p[current_p_idx] + (t - (h[i] - p[current_p_idx]))
            max_reachable_right = p[current_p_idx] + t - (h[i] - p[current_p_idx]);
        }

        // Now, advance current_p_idx as long as p[current_p_idx] is covered by this head.
        while (current_p_idx < m && p[current_p_idx] <= max_reachable_right) {
            current_p_idx++;
        }
    }

    // If all target tracks are covered, return true
    return current_p_idx == m;
}

