#include <vector>
#include <map>

// Using long long for y and array values to prevent overflow
// x can be up to n, which is 2e5, so int is fine for x.
// a_i can be up to 1e9, so long long for a_i.
// y can accumulate sums of a_i, so long long for y.

// Global variables for memoization
std::vector<long long> a_values; // Stores a_1, a_2, ..., a_n
std::vector<long long> memo_y;   // Stores the final y value for a given starting x
std::vector<int> memo_x_next; // Stores the next x value for a given starting x
std::vector<bool> visited;    // To detect cycles during DFS
std::vector<bool> in_stack;   // To detect cycles in current path

int N;

// Function to simulate the program for a given starting x_start
// Returns the final y value if terminates, -1 if infinite loop
long long solve(int x_start) {
    // If already computed, return memoized value
    if (memo_y[x_start] != -2) { // -2 indicates not computed
        return memo_y[x_start];
    }

    // Mark as visited and in current recursion stack
    visited[x_start] = true;
    in_stack[x_start] = true;

    long long current_a_val = a_values[x_start];
    long long y_accumulated = current_a_val;

    // Step 2: x = x + a_x, y = y + a_x
    int x_after_step2 = x_start + current_a_val;

    // Check termination condition after step 2
    if (x_after_step2 <= 0 || x_after_step2 > N) {
        memo_y[x_start] = y_accumulated;
        memo_x_next[x_start] = x_after_step2; // Store for debugging/completeness, not strictly needed for logic
        in_stack[x_start] = false;
        return y_accumulated;
    }

    // Step 3: x = x - a_x_after_step2, y = y + a_x_after_step2
    long long a_val_at_x_after_step2 = a_values[x_after_step2];
    y_accumulated += a_val_at_x_after_step2;
    int x_after_step3 = x_after_step2 - a_val_at_x_after_step2;

    // Check termination condition after step 3
    if (x_after_step3 <= 0 || x_after_step3 > N) {
        memo_y[x_start] = y_accumulated;
        memo_x_next[x_start] = x_after_step3;
        in_stack[x_start] = false;
        return y_accumulated;
    }

    // If not terminated, recursively call for the next state
    // Check for cycle
    if (in_stack[x_after_step3]) {
        // Detected a cycle, this path leads to infinite loop
        memo_y[x_start] = -1;
        memo_x_next[x_start] = x_after_step3; // Points to itself or earlier in cycle
        in_stack[x_start] = false;
        return -1;
    }

    long long next_result = solve(x_after_step3);

    if (next_result == -1) {
        memo_y[x_start] = -1;
    } else {
        memo_y[x_start] = y_accumulated + next_result;
    }
    memo_x_next[x_start] = x_after_step3;
    in_stack[x_start] = false;
    return memo_y[x_start];
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    // a_values will be 1-indexed, so size N+1
    a_values.resize(N + 1);
    // a_1 is set for each run, a_2 to a_N are fixed
    for (int i = 2; i <= N; ++i) {
        std::cin >> a_values[i];
    }

    // Initialize memoization tables
    // -2 indicates not computed, -1 indicates infinite loop, non-negative is result
    memo_y.assign(N + 1, -2);
    memo_x_next.assign(N + 1, 0); // 0 is a dummy value
    visited.assign(N + 1, false);
    in_stack.assign(N + 1, false);

    // For each i from 1 to N-1, set a_1 = i and run the program
    for (int i = 1; i < N; ++i) {
        a_values[1] = i;

        // Reset memoization for each new a_1.
        // This is crucial because a_1 changes.
        // However, we only need to recompute for states reachable from (1,0) with current a_1.
        // A full reset is simpler but potentially slower if N is very large and many states are shared.
        // Given N=2e5, a full reset for each of N-1 runs would be N*(N+1) operations, too slow.
        // The key insight is that the problem asks for the result when a_1 is set to i,
        // and then the program starts with x=1.
        // The values a_2, ..., a_N are constant.
        // The state (x, y) depends on a_x. If x > 1, a_x is constant.
        // If x = 1, a_x is 'i'.
        // This means we can't just run solve(1) for each i and expect memoization to work across 'i's.
        // The problem statement implies that for each i, we run the program on the sequence i, a_2, ..., a_n.
        // This means a_1 is effectively 'i' for that specific run.
        // The values a_2...a_N are fixed.
        // The state transitions for x > 1 are fixed.
        // The state transition for x = 1 depends on the current 'i'.

        // We need to re-initialize memoization for each run, but only for the 'a_1' value.
        // The values for a_2...a_N are constant.
        // This means we can precompute results for x_start = 2 to N.
        // Then for each i, we only need to compute for x_start = 1.

        // Let's re-evaluate the problem structure.
        // "Suppose for each i (1 <= i <= n - 1) we run the program on the sequence i, a_2, a_3, ..., a_n."
        // This means for each 'i', a_1 is set to 'i'.
        // The values a_2, ..., a_N are fixed.
        // The transitions for x > 1 are fixed.
        // The transition for x = 1 depends on the current 'i'.

        // The current `solve` function is designed for a fixed `a_values` array.
        // If `a_values[1]` changes, the memoization for `solve(1)` becomes invalid.
        // However, `solve(k)` for `k > 1` remains valid because `a_values[k]` is constant.
        // So, we only need to clear `memo_y[1]`, `visited[1]`, `in_stack[1]` for each `i`.
        // And then call `solve(1)`.

        // Reset only for x=1
        memo_y[1] = -2;
        visited[1] = false;
        in_stack[1] = false;

        // Call solve for the starting state (x=1)
        std::cout << solve(1) << "\n";
    }

    return 0;
}

