#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm>

// Function to convert a non-negative integer to its parity pattern string
// The pattern is always 18 characters long, padded with '0's from the left.
std::string to_parity_pattern(long long n) {
    std::string pattern_str = "";
    if (n == 0) {
        pattern_str = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern_str += '0';
            } else {
                pattern_str += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the right to make it 18 characters long
    // This corresponds to padding the original number with '0's from the left
    while (pattern_str.length() < 18) {
        pattern_str += '0';
    }
    return pattern_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[to_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the right to make it 18 characters long
            // This corresponds to padding the original pattern with '0's from the left
            while (s.length() < 18) {
                s += '0';
            }
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}
